_AUTH_RATE_LIMIT_HITS: dict[str, deque[float]] = {}
_TFA_FERNET_INIT_ERROR = ''

# ─────────────────────────────────────────────────────────────
# Bencode decoder  (for .torrent parsing)
# ─────────────────────────────────────────────────────────────

def bdecode(data: bytes):
    def _decode(pos):
        ch = data[pos:pos+1]
        if ch == b'i':
            end = data.index(b'e', pos+1)
            return int(data[pos+1:end]), end+1
        if ch == b'l':
            lst, pos = [], pos+1
            while data[pos:pos+1] != b'e':
                val, pos = _decode(pos)
                lst.append(val)
            return lst, pos+1
        if ch == b'd':
            dct, pos = {}, pos+1
            while data[pos:pos+1] != b'e':
                key, pos = _decode(pos)
                val, pos = _decode(pos)
                dct[key] = val
            return dct, pos+1
        # byte string
        colon = data.index(b':', pos)
        length = int(data[pos:colon])
        start  = colon+1
        return data[start:start+length], start+length
    val, _ = _decode(0)
    return val


def parse_torrent(data: bytes) -> tuple:
    """Parse a .torrent file.
    Returns (info_hash, name, total_size, meta) where meta is a dict with
    extended fields for the detail page.
    """
    torrent = bdecode(data)
    if not isinstance(torrent, dict) or b'info' not in torrent:
        raise ValueError('Not a valid torrent file')
    info = torrent[b'info']
    # Locate the raw 'info' dict in the original bytes and SHA1 it
    start = data.index(b'4:info') + 6
    def _skip(pos):
        ch = data[pos:pos+1]
        if ch == b'i':
            end = data.index(b'e', pos+1)
            return end+1
        if ch in (b'l', b'd'):
            pos += 1
            while data[pos:pos+1] != b'e':
                pos = _skip(pos)
            return pos+1
        colon = data.index(b':', pos)
        length = int(data[pos:colon])
        return colon+1+length
    end = _skip(start)
    info_raw = data[start:end]
    ih = hashlib.sha1(info_raw).hexdigest().upper()
    # Name
    name_bytes = info.get(b'name.utf-8') or info.get(b'name') or b'Unknown'
    name = name_bytes.decode('utf-8', errors='replace') if isinstance(name_bytes, bytes) else str(name_bytes)
    # File list
    def _dec(b):
        return b.decode('utf-8', errors='replace') if isinstance(b, bytes) else str(b)
    if b'files' in info:
        files = []
        for f in info[b'files']:
            path_parts = [_dec(p) for p in f.get(b'path.utf-8', f.get(b'path', [b'?']))]
            files.append({'path': '/'.join(path_parts), 'size': f.get(b'length', 0)})
        total_size = sum(f['size'] for f in files)
        is_multifile = True
    else:
        total_size = info.get(b'length', 0)
        files = [{'path': name, 'size': total_size}]
        is_multifile = False
    # Pieces
    pieces_raw = info.get(b'pieces', b'')
    piece_count = len(pieces_raw) // 20
    piece_length = info.get(b'piece length', 0)
    # Privacy flag
    private = bool(info.get(b'private', 0))
    meta = {
        'piece_count':  piece_count,
        'piece_length': piece_length,
        'private':      private,
        'is_multifile': is_multifile,
        'files':        json.dumps(files),   # stored as JSON string
    }
    return ih, name, total_size, meta


# ─────────────────────────────────────────────────────────────
# Password hashing (PBKDF2 / hashlib built-in)
# ─────────────────────────────────────────────────────────────

def _hash_password(password: str, salt: str | None = None) -> tuple[str, str]:
    """Return (hash_hex, salt_hex). Generate salt if not provided."""
    if salt is None:
        salt = secrets.token_hex(16)
    dk = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt.encode(), 260000)
    return dk.hex(), salt


def _verify_password(password: str, stored_hash: str, salt: str) -> bool:
    dk = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt.encode(), 260000)
    return hmac.compare_digest(dk.hex(), stored_hash)


def _totp_secret_generate(num_bytes: int = 20) -> str:
    """Generate Base32 TOTP secret compatible with Google Authenticator."""
    n = max(10, min(64, int(num_bytes)))
    return base64.b32encode(secrets.token_bytes(n)).decode('ascii').rstrip('=')


def _totp_code(secret_b32: str, ts: int | None = None, period: int = 30, digits: int = 6) -> str:
    sec = re.sub(r'\s+', '', (secret_b32 or '').strip().upper())
    if not sec:
        return ''
    pad = '=' * ((8 - (len(sec) % 8)) % 8)
    key = base64.b32decode(sec + pad, casefold=True)
    now = int(ts if ts is not None else time.time())
    p = max(15, min(120, int(period)))
    d = max(6, min(8, int(digits)))
    counter = now // p
    msg = struct.pack('>Q', counter)
    digest = hmac.new(key, msg, hashlib.sha1).digest()
    off = digest[-1] & 0x0F
    code_int = struct.unpack('>I', digest[off:off + 4])[0] & 0x7FFFFFFF
    return str(code_int % (10 ** d)).zfill(d)


def _totp_verify(secret_b32: str, code: str, period: int = 30, digits: int = 6,
                 skew_steps: int = 1, ts: int | None = None) -> bool:
    return _totp_verify_counter(secret_b32, code, period=period, digits=digits, skew_steps=skew_steps, ts=ts) is not None


def _totp_verify_counter(secret_b32: str, code: str, period: int = 30, digits: int = 6,
                         skew_steps: int = 1, ts: int | None = None) -> tuple[int, int] | None:
    cand = re.sub(r'\s+', '', (code or '').strip())
    if not cand.isdigit():
        return None
    now = int(ts if ts is not None else time.time())
    skew = max(0, min(5, int(skew_steps)))
    step = max(15, min(120, int(period)))
    now_counter = now // step
    for i in range(-skew, skew + 1):
        if hmac.compare_digest(_totp_code(secret_b32, ts=now + (i * step), period=step, digits=digits), cand):
            return now_counter + i, i
    return None


def _tfa_generate_backup_codes(count: int = 10) -> list[str]:
    n = max(3, min(20, int(count)))
    out = []
    for _ in range(n):
        # 4 x 4 human-readable code blocks
        blocks = [''.join(secrets.choice('ABCDEFGHJKLMNPQRSTUVWXYZ23456789') for _ in range(4)) for _ in range(4)]
        out.append('-'.join(blocks))
    return out


def _tfa_hash_backup_code(code: str, salt: str = '') -> str:
    norm = re.sub(r'[^A-Za-z0-9]', '', (code or '')).upper()
    if not norm:
        return ''
    if not salt:
        return hashlib.sha256(norm.encode('utf-8')).hexdigest()
    return hashlib.sha256(f'{salt.strip()}:{norm}'.encode('utf-8')).hexdigest()


def _tfa_qr_data_uri(otpauth_uri: str) -> str:
    """Return inline SVG QR as data URI; empty string if QR backend unavailable."""
    if not _TFA_QR_LIB_AVAILABLE:
        return ''
    try:
        factory = qrcode.image.svg.SvgPathImage
        img = qrcode.make(otpauth_uri, image_factory=factory, box_size=6, border=2)
        svg = img.to_string().decode('utf-8')
        b64 = base64.b64encode(svg.encode('utf-8')).decode('ascii')
        return f'data:image/svg+xml;base64,{b64}'
    except Exception:
        return ''


# ── Security helpers ────────────────────────────────────
# CSRF secret is loaded from the DB on startup so server restarts
# do not invalidate existing browser CSRF cookies.
_CSRF_SECRET: bytes = b''  # populated by _init_csrf_secret() in main()


def _init_csrf_secret(db) -> None:
    """Load persistent CSRF secret from settings, creating it if absent."""
    global _CSRF_SECRET
    stored = db.get_setting('_csrf_secret')
    if stored:
        _CSRF_SECRET = bytes.fromhex(stored)
        log.debug('CSRF secret loaded from DB (prefix=%s)', stored[:8])
    else:
        _CSRF_SECRET = secrets.token_bytes(32)
        db.set_setting('_csrf_secret', _CSRF_SECRET.hex(), 'system')
        log.debug('CSRF secret generated and saved (prefix=%s)', _CSRF_SECRET.hex()[:8])


def _h(s: str) -> str:
    """HTML-escape for safe insertion into HTML."""
    return _html_mod.escape(str(s), quote=True)


def _session_token_for(user) -> str:
    """Look up the most recent active session token for a user (for CSRF generation in render functions)."""
    if not user or not REGISTRATION_DB:
        return ''
    return REGISTRATION_DB.get_latest_session_token_for_user(int(user['id']))


def _csrf_token(session_token: str) -> str:
    """Derive CSRF token from session token via HMAC."""
    return hmac.new(_CSRF_SECRET, session_token.encode(), 'sha256').hexdigest()[:32]


def _get_page_param(path_with_query: str) -> int:
    """Extract ?page=N from URL, default 1."""
    qs = urllib.parse.urlparse(path_with_query).query
    params = urllib.parse.parse_qs(qs)
    try:
        return max(1, int(params.get('page', ['1'])[0]))
    except (ValueError, TypeError):
        return 1


def _get_named_page_param(path_with_query: str, name: str = 'page') -> int:
    qs = urllib.parse.urlparse(path_with_query).query
    params = urllib.parse.parse_qs(qs)
    try:
        return max(1, int(params.get(name, ['1'])[0]))
    except (ValueError, TypeError):
        return 1


def _pagination_html(current_page: int, total_pages: int, base_url: str,
                     page_param: str = 'page') -> str:
    """Render compact pagination: 1 2 3 ... 8 9 10 style."""
    if total_pages <= 1:
        return ''

    def page_url(p):
        sep = '&' if '?' in base_url else '?'
        return f'{base_url}{sep}{page_param}={p}'

    # Build list of page numbers to show
    pages = set()
    pages.update([1, 2, 3])
    pages.update([total_pages - 2, total_pages - 1, total_pages])
    pages.update([current_page - 1, current_page, current_page + 1])
    pages = sorted(p for p in pages if 1 <= p <= total_pages)

    btn = ('font-family:var(--mono);font-size:0.72rem;padding:5px 10px;border-radius:5px;'
           'border:1px solid var(--border);background:transparent;color:var(--muted);'
           'cursor:pointer;text-decoration:none;display:inline-block')
    btn_active = btn.replace('var(--muted)', 'var(--accent)').replace('var(--border)', 'var(--accent)')

    items = []
    prev_p = None
    for p in pages:
        if prev_p is not None and p - prev_p > 1:
            items.append('<span style="color:var(--muted);padding:0 4px">&#8230;</span>')
        style = btn_active if p == current_page else btn
        items.append(f'<a href="{page_url(p)}" style="{style}">{p}</a>')
        prev_p = p

    # Prev / Next arrows
    prev_btn = (f'<a href="{page_url(current_page-1)}" style="{btn}">&#10094;</a> '
                if current_page > 1 else '')
    next_btn = (f' <a href="{page_url(current_page+1)}" style="{btn}">&#8594;</a>'
                if current_page < total_pages else '')

    inner = prev_btn + ' '.join(items) + next_btn
    return (
        f'<div style="display:flex;align-items:center;justify-content:center;gap:6px;'
        f'flex-wrap:wrap;margin-top:16px;padding-top:14px;border-top:1px solid var(--border)">'
        f'{inner}'
        f'<span style="color:var(--muted);font-family:var(--mono);font-size:0.68rem;margin-left:8px">'
        f'Page {current_page} of {total_pages}</span>'
        f'</div>'
    )


def _user_role(user) -> str:
    """Return 'super','admin','editor','standard','basic' for a user row."""
    if user['username'] == SUPER_USER:
        return 'super'
    if user['is_admin']:
        return 'admin'
    if ('is_editor' in user.keys()) and user['is_editor']:
        return 'editor'
    if 'is_standard' in user.keys() and user['is_standard']:
        return 'standard'
    return 'basic'


def _validate_username(username: str) -> str:
    """Return error string if username is invalid, else empty string."""
    if not username:
        return 'Username is required.'
    if len(username) > 32:
        return 'Username must be 32 characters or fewer.'
    if not re.match(r'^[a-zA-Z0-9._-]+$', username):
        return 'Username may only contain letters, digits, dots, hyphens, and underscores.'
    return ''


def _validate_password(password: str, settings: dict) -> list[str]:
    """Return list of unmet requirements. Empty = valid."""
    errors = []
    min_len = int(settings.get('pw_min_length', '12'))
    if len(password) < min_len:
        errors.append(f'At least {min_len} characters')
    if settings.get('pw_require_upper', '1') == '1' and not any(c.isupper() for c in password):
        errors.append('At least one uppercase letter')
    if settings.get('pw_require_lower', '1') == '1' and not any(c.islower() for c in password):
        errors.append('At least one lowercase letter')
    if settings.get('pw_require_digit', '1') == '1' and not any(c.isdigit() for c in password):
        errors.append('At least one digit')
    if settings.get('pw_require_symbol', '1') == '1':
        symbols = set(string.punctuation)
        if not any(c in symbols for c in password):
            errors.append('At least one symbol (!@#$%^&* etc.)')
    return errors


def _normalize_metadata_provider(raw: str) -> str:
    val = (raw or '').strip().lower()
    if val in ('imdb', 'tvmaze', 'steam'):
        return val
    return ''


def _normalize_report_reason(raw: str) -> str:
    reason = (raw or '').strip().lower()
    return reason if reason in REPORT_REASONS else ''


def _normalize_report_status(raw: str) -> str:
    status = (raw or '').strip().lower()
    return status if status in REPORT_STATUSES else ''


def _report_reason_severity(reason: str) -> str:
    return 'high' if (reason or '').strip().lower() == 'csam' else 'normal'


def _validate_imdb_id(raw: str) -> str:
    imdb_id = (raw or '').strip().lower()
    if re.fullmatch(r'tt[0-9]{4,12}', imdb_id):
        return imdb_id
    return ''


def _validate_tvmaze_id(raw: str) -> str:
    tvmaze_id = (raw or '').strip()
    if re.fullmatch(r'[0-9]{1,12}', tvmaze_id):
        return tvmaze_id
    return ''


def _validate_steam_app_id(raw: str) -> str:
    app_id = (raw or '').strip()
    if re.fullmatch(r'[0-9]{1,12}', app_id):
        return app_id
    return ''


def _infer_tv_season_episode(release_name: str) -> tuple[int | None, int | None]:
    text = (release_name or '').strip()
    if not text:
        return None, None
    m = re.search(r'(?i)\bS(\d{1,2})E(\d{1,2})\b', text)
    if m:
        return int(m.group(1)), int(m.group(2))
    m = re.search(r'(?i)\b(\d{1,2})x(\d{1,2})\b', text)
    if m:
        return int(m.group(1)), int(m.group(2))
    m = re.search(r'(?i)\bseason[ ._-]*(\d{1,2})[ ._-]*episode[ ._-]*(\d{1,2})\b', text)
    if m:
        return int(m.group(1)), int(m.group(2))
    # Season-pack releases often use S01 / S01.COMPLETE without episode token.
    m = re.search(r'(?i)\bS(\d{1,2})(?!\d)\b', text)
    if m:
        return int(m.group(1)), None
    m = re.search(r'(?i)\bseason[ ._-]*(\d{1,2})\b', text)
    if m:
        return int(m.group(1)), None
    return None, None


def _infer_tv_show_query(release_name: str) -> str:
    text = (release_name or '').strip()
    if not text:
        return ''
    # Strip common release/site prefixes like "www.site.tld - ".
    text = re.sub(r'(?i)^\s*(?:www\.)?[a-z0-9.-]+\.[a-z]{2,}\s*[-–—]\s*', '', text)
    s = re.sub(r'[ _]+', '.', text)
    s = re.sub(r'(?i)[.-]S\d{1,2}E\d{1,2}.*$', '', s)
    s = re.sub(r'(?i)[.-]\d{1,2}x\d{1,2}.*$', '', s)
    # Drop common release noise while preserving primary title tokens.
    s = re.sub(
        r'(?i)[.-](2160p|1080p|720p|480p|x264|x265|h264|h265|hevc|avc|'
        r'web[-.]dl|webrip|web|bluray|bdrip|brrip|hdr10\+?|dolby[ .-]?vision|dv|'
        r'ddp?[0-9.]+|aac|truehd|atmos|proper|repack|internal|extended|'
        r'nf|amzn|dsnp|hmax|atvp|pcok|roku|multi|dubbed|subbed|'
        r'19\d{2}|20\d{2}).*$', '', s)
    s = re.sub(r'\.+', '.', s).strip('.')
    q = s.replace('.', ' ').strip()
    return q[:120]


def _parse_torrent_name_cleanup_tags(raw: str) -> list[str]:
    tags: list[str] = []
    seen: set[str] = set()
    for part in re.split(r'[\n,]+', str(raw or '')):
        tag = part.strip()
        if not tag:
            continue
        key = tag.lower()
        if key in seen:
            continue
        seen.add(key)
        tags.append(tag[:120])
    return tags


def _normalize_torrent_display_name(name: str, cleanup_tags: list[str],
                                    strip_www_prefix: bool = True,
                                    strip_extensions: bool = True) -> str:
    original = str(name or '').strip()
    if not original:
        return ''
    normalized = original
    if strip_www_prefix:
        normalized = re.sub(
            r'(?i)^\s*(?:www\.)[a-z0-9.-]+\.[a-z]{2,}\s*[-–—]\s*',
            '',
            normalized,
        )
    for tag in cleanup_tags:
        if not tag:
            continue
        normalized = re.sub(re.escape(tag), '', normalized, flags=re.IGNORECASE)
    normalized = re.sub(r'\[\s*\]', ' ', normalized)
    normalized = re.sub(r'\(\s*\)', ' ', normalized)
    normalized = re.sub(r'\s{2,}', ' ', normalized).strip()
    normalized = re.sub(r'^\s*[-:|]\s*', '', normalized)
    normalized = re.sub(r'\s*[-:|]\s*$', '', normalized)
    if strip_extensions:
        normalized = re.sub(
            r'(?i)(?:\.(mkv|mp4|avi|mov|wmv|flv|m4v|ts|m2ts|webm|mpg|mpeg|iso|mka|mks|srt|sub|ass))+$',
            '',
            normalized,
        )
        normalized = re.sub(r'\s{2,}', ' ', normalized).strip()
        normalized = re.sub(r'^\s*[-:|.]\s*', '', normalized)
        normalized = re.sub(r'\s*[-:|.]\s*$', '', normalized)
    normalized = normalized.strip()
    return normalized or original


_FACET_PROVIDER_PATTERNS: list[tuple[str, str]] = [
    (r'(?i)(?:^|[ ._\-])(AMZN|AMAZON)(?:[ ._\-]|$)', 'amzn'),
    (r'(?i)(?:^|[ ._\-])(NF|NFLX|NETFLIX)(?:[ ._\-]|$)', 'nf'),
    (r'(?i)(?:^|[ ._\-])(DSNP|DISNEYPLUS)(?:[ ._\-]|$)', 'dsnp'),
    (r'(?i)(?:^|[ ._\-])(ATVP|APTV|ATV|APPLE)(?:[ ._\-]|$)', 'atvp'),
    (r'(?i)(?:^|[ ._\-])(HMAX|MAX|HBO)(?:[ ._\-]|$)', 'hmax'),
    (r'(?i)(?:^|[ ._\-])(PMTP|PARAMOUNT)(?:[ ._\-]|$)', 'pmtp'),
    (r'(?i)(?:^|[ ._\-])(PCOK|PEACOCK)(?:[ ._\-]|$)', 'pcok'),
    (r'(?i)(?:^|[ ._\-])(HULU)(?:[ ._\-]|$)', 'hulu'),
    (r'(?i)(?:^|[ ._\-])(NOW)(?:[ ._\-]|$)', 'now'),
    (r'(?i)(?:^|[ ._\-])(ROKU)(?:[ ._\-]|$)', 'roku'),
    (r'(?i)(?:^|[ ._\-])(MA|MOVIESANYWHERE)(?:[ ._\-]|$)', 'ma'),
    (r'(?i)(?:^|[ ._\-])(PLEX)(?:[ ._\-]|$)', 'plex'),
    (r'(?i)(?:^|[ ._\-])(LBXD)(?:[ ._\-]|$)', 'lbxd'),
]


def _csv_tags(values: list[str]) -> str:
    cleaned = []
    seen = set()
    for v in values:
        item = str(v or '').strip().lower()
        if not item or item in seen:
            continue
        seen.add(item)
        cleaned.append(item)
    cleaned.sort()
    return ','.join(cleaned)


def _parse_release_facets(raw_name: str) -> dict[str, Any]:
    cleaned = _normalize_torrent_display_name(
        raw_name, [], strip_www_prefix=True, strip_extensions=True
    )
    upper_raw = str(cleaned or '').upper().strip()
    if not upper_raw:
        return {}
    # Canonical scan text for token matching. This lets bracket/paren wrapped
    # tokens (e.g. `[1080p]`, `(WEBRip)`) behave like normal separators.
    upper = re.sub(r'[\[\]\(\)\{\}]', '.', upper_raw)
    upper = re.sub(r'\.+', '.', upper)

    facets: dict[str, Any] = {}

    # Optional scene/p2p group suffix at end of release name.
    # Keep this strict so we don't accidentally capture source/codec tails
    # like "WEB-DL.DDP5.1.ATMOS.H.264-SCOPE" as one giant group.
    gm = re.search(r'(?i)-([A-Z0-9][A-Z0-9_]{1,63})$', upper_raw)
    if gm:
        grp = str(gm.group(1) or '').strip('.-_ ').lower()
        if grp:
            facets['release_group'] = grp[:64]

    # Shared technical tokens for movies and TV.
    if re.search(r'(?i)(?:^|[ ._\-])2160P(?:[ ._\-]|$)|(?:^|[ ._\-])(4K|UHD)(?:[ ._\-]|$)', upper):
        facets['release_resolution'] = '2160p'
    elif re.search(r'(?i)(?:^|[ ._\-])1080P(?:[ ._\-]|$)', upper):
        facets['release_resolution'] = '1080p'
    elif re.search(r'(?i)(?:^|[ ._\-])720P(?:[ ._\-]|$)', upper):
        facets['release_resolution'] = '720p'
    elif re.search(r'(?i)(?:^|[ ._\-])480P(?:[ ._\-]|$)', upper):
        facets['release_resolution'] = '480p'

    if re.search(r'(?i)(?:^|[ ._\-])REMUX(?:[ ._\-]|$)', upper):
        facets['release_source_class'] = 'remux'
    elif re.search(r'(?i)(?:^|[ ._\-])(BLURAY|BLU-RAY|BDRIP|BRRIP)(?:[ ._\-]|$)', upper):
        facets['release_source_class'] = 'bluray'
    elif re.search(r'(?i)(?:^|[ ._\-])(DVDRIP|DVD)(?:[ ._\-]|$)', upper):
        facets['release_source_class'] = 'dvdrip'
    elif re.search(r'(?i)(?:^|[ ._\-])(WEB-DL|WEBDL)(?:[ ._\-]|$)', upper):
        facets['release_source_class'] = 'web-dl'
    elif re.search(r'(?i)(?:^|[ ._\-])WEBRIP(?:[ ._\-]|$)', upper):
        facets['release_source_class'] = 'webrip'
    elif re.search(r'(?i)(?:^|[ ._\-])WEB(?:[ ._\-]|$)', upper):
        facets['release_source_class'] = 'web'

    for pattern, provider in _FACET_PROVIDER_PATTERNS:
        if re.search(pattern, upper):
            facets['release_provider'] = provider
            break

    if re.search(r'(?i)(?:^|[ ._\-])(X265|H265|HEVC)(?:[ ._\-]|$)', upper):
        facets['release_video_codec'] = 'h265'
    elif re.search(r'(?i)(?:^|[ ._\-])(X264|H264|AVC)(?:[ ._\-]|$)', upper):
        facets['release_video_codec'] = 'h264'

    if re.search(r'(?i)(?:^|[ ._\-])DDP?[0-9.]*(?:[ ._\-]|$)', upper):
        facets['release_audio_codec'] = 'ddp'
    elif re.search(r'(?i)(?:^|[ ._\-])TRUEHD(?:[ ._\-]|$)', upper):
        facets['release_audio_codec'] = 'truehd'
    elif re.search(r'(?i)(?:^|[ ._\-])DTS(?:[ ._\-]|$)', upper):
        facets['release_audio_codec'] = 'dts'
    elif re.search(r'(?i)(?:^|[ ._\-])AC3(?:[ ._\-]|$)', upper):
        facets['release_audio_codec'] = 'ac3'
    elif re.search(r'(?i)(?:^|[ ._\-])AAC[0-9.]*(?:[ ._\-]|$)', upper):
        facets['release_audio_codec'] = 'aac'

    audio_features: list[str] = []
    if re.search(r'(?i)(?:^|[ ._\-])ATMOS(?:[ ._\-]|$)', upper):
        audio_features.append('atmos')
    if re.search(r'(?i)(?:^|[ ._\-])(?:DDP?|AAC|AC3|DTS|TRUEHD)?5[.]1(?:[ ._\-]|$)', upper):
        audio_features.append('5.1')
    if re.search(r'(?i)(?:^|[ ._\-])(?:DDP?|AAC|AC3|DTS|TRUEHD)?7[.]1(?:[ ._\-]|$)', upper):
        audio_features.append('7.1')
    audio_csv = _csv_tags(audio_features)
    if audio_csv:
        facets['release_audio_features'] = audio_csv

    hdr_flags: list[str] = []
    if re.search(r'(?i)(?:^|[ ._\-])HDR10[+]?|(?:^|[ ._\-])HDR(?:[ ._\-]|$)', upper):
        hdr_flags.append('hdr')
    if re.search(r'(?i)DOLBY[ ._\-]?VISION|(?:^|[ ._\-])DV(?:[ ._\-]|$)', upper):
        hdr_flags.append('dv')
    hdr_csv = _csv_tags(hdr_flags)
    if hdr_csv:
        facets['release_hdr_flags'] = hdr_csv

    edition_flags: list[str] = []
    for flag in ('proper', 'repack', 'internal', 'extended', 'unrated', 'remastered', 'limited', 'imax'):
        if re.search(rf'(?i)(?:^|[ ._\-]){re.escape(flag)}(?:[ ._\-]|$)', upper):
            edition_flags.append(flag)
    edition_csv = _csv_tags(edition_flags)
    if edition_csv:
        facets['release_edition_flags'] = edition_csv

    # Semantic detector fallback from name only.
    season, episode = _infer_tv_season_episode(upper)
    if season is not None or re.search(r'(?i)(?:^|[ ._\-])SEASON(?:[ ._\-]|$)', upper):
        facets['media_type'] = 'tv'
    elif re.search(r'(?i)(?:^|[^0-9])(19[0-9]{2}|20[0-9]{2})(?:[^0-9]|$)', upper):
        facets['media_type'] = 'movie'
    else:
        facets['media_type'] = 'other'

    # Confidence score from number of independent facet families matched.
    score = 0
    families = (
        'release_resolution', 'release_source_class', 'release_provider',
        'release_video_codec', 'release_audio_codec', 'release_audio_features',
        'release_hdr_flags', 'release_edition_flags', 'release_group',
    )
    for k in families:
        if facets.get(k):
            score += 10
    if re.search(r'(?i)(?:^|[^0-9])(19[0-9]{2}|20[0-9]{2})(?:[^0-9]|$)', upper):
        score += 10
    facets['classification_confidence'] = max(0, min(100, score))
    return facets


def _parse_torrent_facets_from_qs(params: dict[str, list[str]]) -> dict[str, str]:
    def _pick(key: str) -> str:
        return str((params.get(key, [''])[0] or '')).strip().lower()
    out: dict[str, str] = {}
    media_type = _pick('fmt')
    if media_type in ('movie', 'tv', 'game', 'other'):
        out['media_type'] = media_type
    resolution = _pick('fr')
    if resolution in ('2160p', '1080p', '720p', '480p'):
        out['release_resolution'] = resolution
    source = _pick('fs')
    if source in ('web-dl', 'webrip', 'web', 'bluray', 'dvdrip', 'remux'):
        out['release_source_class'] = source
    provider = _pick('fp')
    if provider in ('amzn', 'nf', 'dsnp', 'atvp', 'hmax', 'pmtp', 'pcok', 'hulu', 'now', 'roku', 'ma', 'plex', 'lbxd'):
        out['release_provider'] = provider
    genre = re.sub(r'[^a-z0-9 _-]+', '', _pick('fg')).strip()
    if genre:
        out['genre'] = genre[:40]
    if _pick('fa') in ('1', 'true', 'yes', 'on', 'atmos'):
        out['audio_feature'] = 'atmos'
    hdr = _pick('fh')
    if hdr in ('hdr', 'dv'):
        out['hdr_flag'] = hdr
    return out


def _parse_magnet_uri(magnet_uri: str) -> tuple[bool, str, str]:
    """Return (ok, normalized_btih_upper_hex, error_msg) for magnet URI or raw info hash."""
    raw = str(magnet_uri or '').strip()
    if not raw:
        return False, '', 'Magnet URI or info hash is required.'
    # Allow direct info-hash submissions (hex40 or base32-32).
    if re.fullmatch(r'(?i)[a-f0-9]{40}', raw):
        return True, raw.upper(), ''
    if re.fullmatch(r'(?i)[a-z2-7]{32}', raw):
        try:
            padded = raw.upper() + '=' * ((8 - (len(raw) % 8)) % 8)
            decoded = base64.b32decode(padded, casefold=True)
            ih = decoded.hex().upper()
            if re.fullmatch(r'[A-F0-9]{40}', ih):
                return True, ih, ''
        except Exception:
            pass
        return False, '', 'Info hash is invalid.'
    if len(raw) > 8192:
        return False, '', 'Magnet URI is too long.'
    try:
        parsed = urllib.parse.urlparse(raw)
    except Exception:
        return False, '', 'Invalid magnet URI or info hash.'
    if (parsed.scheme or '').lower() != 'magnet':
        return False, '', 'Input must be a magnet URI (magnet:?) or a raw 40-char info hash.'
    q = urllib.parse.parse_qs(parsed.query, keep_blank_values=False)
    xt_values = [v for v in q.get('xt', []) if isinstance(v, str) and v]
    btih_values: list[str] = []
    for xt in xt_values:
        m = re.match(r'(?i)^urn:btih:(.+)$', xt.strip())
        if not m:
            continue
        btih_values.append(m.group(1).strip())
    if len(btih_values) != 1:
        return False, '', 'Magnet URI must include exactly one xt=urn:btih value.'
    btih_raw = btih_values[0]
    if re.fullmatch(r'(?i)[a-f0-9]{40}', btih_raw):
        return True, btih_raw.upper(), ''
    if re.fullmatch(r'(?i)[a-z2-7]{32}', btih_raw):
        try:
            padded = btih_raw.upper() + '=' * ((8 - (len(btih_raw) % 8)) % 8)
            decoded = base64.b32decode(padded, casefold=True)
            ih = decoded.hex().upper()
            if re.fullmatch(r'[A-F0-9]{40}', ih):
                return True, ih, ''
        except Exception:
            pass
    return False, '', 'Magnet URI has an invalid btih hash.'


_TITLE_STOP_TOKENS = {
    '2160p', '1080p', '720p', '480p', 'x264', 'x265', 'h264', 'h265', 'hevc', 'avc',
    'webrip', 'web', 'webdl', 'web-dl', 'bluray', 'bdrip', 'brrip', 'hdr', 'hdr10',
    'dv', 'dolbyvision', 'proper', 'repack', 'internal', 'extended', 'remux', 'uhd',
    'dd', 'ddp', 'ddp5', 'ddp51', 'ddp7', 'aac', 'ac3', 'dts', 'atmos', 'truehd',
    'amzn', 'amazon', 'nf', 'netflix', 'dsnp', 'hmax', 'atvp', 'pcok', 'roku', 'itunes',
    'true',
}


def _normalize_match_text(raw: str) -> str:
    return re.sub(r'[^a-z0-9]+', '', str(raw or '').lower())


def _match_ratio(a: str, b: str) -> int:
    na = _normalize_match_text(a)
    nb = _normalize_match_text(b)
    if not na or not nb:
        return 0
    return int(round(difflib.SequenceMatcher(None, na, nb).ratio() * 100.0))


def _parse_release_for_auto_match(raw_name: str, cleanup_tags: list[str] | None = None,
                                  strip_www_prefix: bool = True,
                                  strip_extensions: bool = True) -> dict[str, Any]:
    src = str(raw_name or '').strip()
    cleaned = _normalize_torrent_display_name(
        src,
        cleanup_tags or [],
        strip_www_prefix=strip_www_prefix,
        strip_extensions=strip_extensions,
    )
    norm = re.sub(r'[\s_]+', '.', cleaned)
    norm = re.sub(r'\.+', '.', norm).strip('.')
    season = None
    episode = None
    m = re.search(r'(?i)\bS(\d{1,2})E(\d{1,2})\b', norm)
    if not m:
        m = re.search(r'(?i)\b(\d{1,2})x(\d{1,2})\b', norm)
    if m:
        try:
            season = int(m.group(1))
            episode = int(m.group(2))
        except Exception:
            season = None
            episode = None
    if season is None:
        ms = re.search(r'(?i)\bS(?:EASON)?[ ._-]?(\d{1,2})\b', norm)
        if ms:
            try:
                season = int(ms.group(1))
            except Exception:
                season = None
    if season is None:
        ms2 = re.search(r'(?i)\bseason[ ._-]*(\d{1,2})\b', norm)
        if ms2:
            try:
                season = int(ms2.group(1))
            except Exception:
                season = None
    year = None
    my = re.search(r'\b(19\d{2}|20\d{2})\b', norm)
    if my:
        try:
            year = int(my.group(1))
        except Exception:
            year = None
    # Treat wrapper punctuation as separators so `[1080p]` / `(2026)` do not
    # leak into title query tokens.
    token_src = re.sub(r'[\[\]\(\)\{\}]', '.', norm)
    tokens = [t for t in re.split(r'[.\-]+', token_src) if t]
    title_parts: list[str] = []
    for tok in tokens:
        bare = re.sub(r"^[^A-Za-z0-9']+|[^A-Za-z0-9']+$", '', tok)
        low = bare.lower()
        alnum = re.sub(r'[^a-z0-9]+', '', low)
        if not bare:
            continue
        if re.fullmatch(r'(?i)s\d{1,2}e\d{1,2}', bare):
            break
        if re.fullmatch(r'(?i)\d{1,2}x\d{1,2}', bare):
            break
        if re.fullmatch(r'(?i)s\d{1,2}', bare):
            break
        if low == 'season':
            break
        if re.fullmatch(r'(19\d{2}|20\d{2})', alnum):
            break
        if low in _TITLE_STOP_TOKENS or alnum in _TITLE_STOP_TOKENS:
            break
        if alnum.isdigit() and len(alnum) >= 3:
            break
        title_parts.append(bare)
    title_query = ' '.join(title_parts).strip()
    if not title_query:
        # Fallback: keep early alpha tokens only.
        alnum = [t for t in tokens if re.search(r'[a-zA-Z]', t)]
        title_query = ' '.join(alnum[:6]).strip()
    return {
        'kind': 'tv' if (season is not None) else 'movie',
        'title_query': title_query[:140],
        'year': year,
        'season': season,
        'episode': episode,
        'normalized': norm,
    }


def _strip_html_text(raw: str) -> str:
    text = str(raw or '')
    if not text:
        return ''
    text = re.sub(r'(?is)<br\s*/?>', '\n', text)
    text = re.sub(r'(?is)<[^>]+>', '', text)
    text = _html_mod.unescape(text)
    text = re.sub(r'\s+', ' ', text).strip()
    return text


def _normalize_release_name_for_srrdb(raw_name: str) -> str:
    name = str(raw_name or '').strip()
    if not name:
        return ''
    name = re.sub(r'[\s_]+', '.', name)
    name = re.sub(r'\.+', '.', name).strip('.')
    name = re.sub(r'(?i)\.(mkv|mp4|avi|mov|wmv|flv)$', '', name)
    return name[:240]


def _parse_torrent_files_json(files_json_raw: str) -> list[dict[str, Any]]:
    try:
        files = json.loads(files_json_raw or '[]')
        if isinstance(files, list):
            out: list[dict[str, Any]] = []
            for f in files:
                if isinstance(f, dict):
                    out.append(f)
            return out
    except Exception:
        pass
    return []


def _normalize_external_image_url(raw: str) -> str:
    url = str(raw or '').strip()
    if not url:
        return ''
    # Avoid mixed-content blocks for known poster providers.
    if url.startswith('http://'):
        host = urllib.parse.urlparse(url).netloc.lower()
        if any(x in host for x in (
            'tvmaze.com', 'static.tvmaze.com',
            'imdb.com', 'media-amazon.com',
            'steamstatic.com', 'steampowered.com', 'akamaihd.net',
        )):
            return 'https://' + url[len('http://'):]
    return url


def _sanitize_metadata_base_url(raw: str, default_url: str, allowed_hosts: set[str],
                                *, strict: bool = False) -> str:
    """Validate and normalize metadata provider base URL.

    Rules:
    - HTTPS only
    - host must be in allowed_hosts
    - no embedded credentials
    - query/fragment removed
    If strict=True, invalid input returns empty string.
    """
    default = (default_url or '').strip() or 'https://example.invalid/'
    candidate = (raw or '').strip() or default
    try:
        parsed = urllib.parse.urlparse(candidate)
        scheme = (parsed.scheme or '').lower()
        host = (parsed.hostname or '').lower()
        if scheme != 'https' or not host or host not in allowed_hosts:
            return '' if strict else default
        if parsed.username or parsed.password:
            return '' if strict else default
        netloc = host
        if parsed.port:
            netloc = f'{host}:{int(parsed.port)}'
        path = parsed.path or ''
        normalized = urllib.parse.urlunparse(('https', netloc, path, '', '', '')).strip()
        return normalized or ('' if strict else default)
    except Exception:
        return '' if strict else default


def _b64url_encode(raw: bytes) -> str:
    return base64.urlsafe_b64encode(raw).decode('ascii').rstrip('=')


def _b64url_decode(s: str) -> bytes:
    s = (s or '').strip()
    pad = '=' * ((4 - (len(s) % 4)) % 4)
    return base64.urlsafe_b64decode(s + pad)


def _json_safe_obj(value: Any):
    if isinstance(value, (bytes, bytearray)):
        return _b64url_encode(bytes(value))
    if isinstance(value, dict):
        out = {}
        for k, v in value.items():
            out[str(k)] = _json_safe_obj(v)
        return out
    if isinstance(value, (list, tuple)):
        return [_json_safe_obj(v) for v in value]
    return value


def _typed_json_encode(value: Any):
    if value is None or isinstance(value, (bool, int, float, str)):
        return value
    if isinstance(value, (bytes, bytearray)):
        return {'__wk_type': 'bytes', 'b64': _b64url_encode(bytes(value))}
    if isinstance(value, tuple):
        return {'__wk_type': 'tuple', 'items': [_typed_json_encode(v) for v in value]}
    if isinstance(value, list):
        return {'__wk_type': 'list', 'items': [_typed_json_encode(v) for v in value]}
    if isinstance(value, dict):
        return {
            '__wk_type': 'dict',
            'items': [[_typed_json_encode(k), _typed_json_encode(v)] for k, v in value.items()],
        }
    raise TypeError(f'Unsupported type in typed JSON encode: {type(value)!r}')


def _typed_json_decode(value: Any):
    if value is None or isinstance(value, (bool, int, float, str)):
        return value
    if isinstance(value, list):
        return [_typed_json_decode(v) for v in value]
    if not isinstance(value, dict):
        raise ValueError('Invalid typed JSON value')
    t = value.get('__wk_type')
    if not t:
        return {str(k): _typed_json_decode(v) for k, v in value.items()}
    if t == 'bytes':
        return _b64url_decode(str(value.get('b64', '')))
    if t == 'tuple':
        return tuple(_typed_json_decode(v) for v in (value.get('items') or []))
    if t == 'list':
        return [_typed_json_decode(v) for v in (value.get('items') or [])]
    if t == 'dict':
        out = {}
        for kv in (value.get('items') or []):
            if not isinstance(kv, list) or len(kv) != 2:
                raise ValueError('Invalid typed JSON dict entry')
            out[_typed_json_decode(kv[0])] = _typed_json_decode(kv[1])
        return out
    raise ValueError('Unknown typed JSON marker')


def _webauthn_state_pack(state: Any) -> str:
    payload = _typed_json_encode(state)
    signed = {'v': 1, 'payload': payload}
    canon = json.dumps(signed, sort_keys=True, separators=(',', ':'))
    key = _CSRF_SECRET or b'webauthn-state-fallback'
    sig = hmac.new(key, canon.encode('utf-8'), hashlib.sha256).hexdigest()
    return json.dumps({'v': 1, 'payload': payload, 'sig': sig}, separators=(',', ':'))


def _webauthn_state_unpack(state_json: str):
    try:
        blob = json.loads(state_json or '{}')
    except Exception:
        return None
    if not isinstance(blob, dict):
        return None
    v = int(blob.get('v', 0))
    payload = blob.get('payload')
    sig = str(blob.get('sig', '')).strip().lower()
    if v != 1 or payload is None or not re.fullmatch(r'[a-f0-9]{64}', sig):
        return None
    signed = {'v': v, 'payload': payload}
    canon = json.dumps(signed, sort_keys=True, separators=(',', ':'))
    key = _CSRF_SECRET or b'webauthn-state-fallback'
    expected = hmac.new(key, canon.encode('utf-8'), hashlib.sha256).hexdigest()
    if not hmac.compare_digest(expected, sig):
        return None
    try:
        return _typed_json_decode(payload)
    except Exception:
        return None


def _seconds_until_iso(ts: str) -> int:
    try:
        dt = datetime.datetime.fromisoformat((ts or '').strip())
    except Exception:
        return 0
    left = (dt - datetime.datetime.now()).total_seconds()
    if left <= 0:
        return 0
    return int(left + 0.999)


def _auth_break_glass_active() -> bool:
    global AUTH_BREAK_GLASS
    if not AUTH_BREAK_GLASS:
        return False
    if AUTH_BREAK_GLASS_UNTIL_TS > 0 and time.time() >= AUTH_BREAK_GLASS_UNTIL_TS:
        AUTH_BREAK_GLASS = False
        log.warning('AUTH BREAK-GLASS expired automatically.')
        if REGISTRATION_DB:
            try:
                REGISTRATION_DB._log('system', 'break_glass_expired', '',
                                     f'ttl_expired_at={datetime.datetime.now().isoformat(timespec="seconds")}')
            except Exception:
                pass
        return False
    return True


def _auth_rate_limit_allow(bucket: str, ip: str, limit: int = AUTH_IP_RATE_MAX_REQUESTS,
                           window_sec: int = AUTH_IP_RATE_WINDOW_SECONDS) -> bool:
    key = f'{bucket}:{(ip or "-").strip()}'
    now = time.time()
    cutoff = now - max(1, int(window_sec))
    with _AUTH_RATE_LIMIT_LOCK:
        dq = _AUTH_RATE_LIMIT_HITS.get(key)
        if dq is None:
            dq = deque()
            _AUTH_RATE_LIMIT_HITS[key] = dq
        while dq and dq[0] < cutoff:
            dq.popleft()
        if len(dq) >= max(1, int(limit)):
            return False
        dq.append(now)
    return True


def _auth_rate_limit_prune_empty() -> int:
    """Remove empty buckets to prevent unbounded key accumulation under scans."""
    removed = 0
    with _AUTH_RATE_LIMIT_LOCK:
        stale_keys = [k for k, dq in _AUTH_RATE_LIMIT_HITS.items() if not dq]
        for k in stale_keys:
            _AUTH_RATE_LIMIT_HITS.pop(k, None)
            removed += 1
    return removed


def _build_tfa_fernet():
    global _TFA_FERNET_INIT_ERROR
    _TFA_FERNET_INIT_ERROR = ''
    if not _TFA_FERNET_AVAILABLE:
        _TFA_FERNET_INIT_ERROR = 'cryptography.fernet backend unavailable'
        return None
    raw = (os.getenv('WK_TFA_SECRET_KEY', '') or '').strip()
    if not raw:
        return None
    try:
        raw.encode('ascii')
        key = b''
        # If already base64-decodable, require exact Fernet key material length.
        try:
            padding = '=' * ((4 - (len(raw) % 4)) % 4)
            decoded = base64.urlsafe_b64decode((raw + padding).encode('ascii'))
            if len(decoded) != 32:
                _TFA_FERNET_INIT_ERROR = (
                    f'WK_TFA_SECRET_KEY decoded length invalid ({len(decoded)} bytes; expected 32)'
                )
                log.error(_TFA_FERNET_INIT_ERROR)
                return None
            key = base64.urlsafe_b64encode(decoded)
        except Exception:
            # Non-base64 input is treated as passphrase material and derived to 32 bytes.
            digest = hashlib.sha256(raw.encode('utf-8')).digest()
            key = base64.urlsafe_b64encode(digest)
        return Fernet(key)
    except Exception as e:
        _TFA_FERNET_INIT_ERROR = f'WK_TFA_SECRET_KEY initialization failed: {e}'
        log.error(_TFA_FERNET_INIT_ERROR)
        return None


def _nested_get(obj, path: list[str], default=''):
    cur = obj
    for p in path:
        if not isinstance(cur, dict):
            return default
        cur = cur.get(p)
    return cur if cur is not None else default


def _coinbase_extract_refs(payload: dict) -> dict:
    """Extract likely Coinbase webhook references for order matching."""
    refs = {
        'event_id': str(payload.get('id') or payload.get('event_id') or ''),
        'event_type': str(payload.get('type') or payload.get('event') or _nested_get(payload, ['event', 'type'], '')),
        'order_uuid': '',
        'order_id': '',
        'checkout_id': '',
        'charge_id': '',
        'hosted_url': '',
    }
    metadata = {}
    for path in (
        ['metadata'],
        ['data', 'metadata'],
        ['event', 'metadata'],
        ['event', 'data', 'metadata'],
    ):
        val = _nested_get(payload, path, {})
        if isinstance(val, dict) and val:
            metadata = val
            break
    refs['order_uuid'] = str(metadata.get('order_uuid') or metadata.get('topup_order_uuid') or '')
    refs['order_id'] = str(metadata.get('order_id') or '')
    refs['checkout_id'] = str(
        _nested_get(payload, ['data', 'code'], '')
        or _nested_get(payload, ['data', 'checkout_id'], '')
        or _nested_get(payload, ['event', 'data', 'code'], '')
        or _nested_get(payload, ['event', 'data', 'checkout_id'], '')
        or _nested_get(payload, ['event', 'data', 'payment_link', 'id'], '')
    )
    refs['charge_id'] = str(
        _nested_get(payload, ['data', 'id'], '')
        or _nested_get(payload, ['event', 'data', 'id'], '')
        or _nested_get(payload, ['data', 'charge_id'], '')
        or _nested_get(payload, ['event', 'data', 'charge_id'], '')
    )
    refs['hosted_url'] = str(
        _nested_get(payload, ['data', 'hosted_url'], '')
        or _nested_get(payload, ['event', 'data', 'hosted_url'], '')
        or _nested_get(payload, ['data', 'url'], '')
        or _nested_get(payload, ['event', 'data', 'url'], '')
    )
    return refs


def _verify_coinbase_signature(secret: str, raw_body: bytes, header_value: str) -> bool:
    """Best-effort verifier supporting plain hex and key=value signature formats."""
    if not secret:
        return True
    if not header_value:
        return False
    expected = hmac.new(secret.encode('utf-8'), raw_body, hashlib.sha256).hexdigest().lower()
    hv = header_value.strip().lower()
    if hmac.compare_digest(expected, hv):
        return True
    candidates = []
    for part in hv.split(','):
        part = part.strip()
        if not part:
            continue
        if '=' in part:
            _, val = part.split('=', 1)
            candidates.append(val.strip())
        else:
            candidates.append(part)
    for cand in candidates:
        if hmac.compare_digest(expected, cand):
            return True
    return False


def _paypal_extract_refs(payload: dict) -> dict:
    """Extract useful PayPal webhook references for order matching."""
    refs = {
        'event_id': str(payload.get('id') or ''),
        'event_type': str(payload.get('event_type') or payload.get('type') or ''),
        'order_uuid': '',
        'order_id': '',
        'checkout_id': '',
        'capture_id': '',
    }
    resource = payload.get('resource') if isinstance(payload.get('resource'), dict) else {}
    refs['checkout_id'] = str(resource.get('supplementary_data', {}).get('related_ids', {}).get('order_id', '')
                              if isinstance(resource.get('supplementary_data'), dict) else '') or str(resource.get('id') or '')
    refs['capture_id'] = str(resource.get('id') or '')
    custom_id = str(resource.get('custom_id') or '')
    if custom_id:
        # custom_id uses order_uuid in current create flow
        refs['order_uuid'] = custom_id
    invoice_id = str(resource.get('invoice_id') or '')
    if invoice_id.startswith('wk-topup-'):
        refs['order_uuid'] = invoice_id[len('wk-topup-'):]
    return refs


# ─────────────────────────────────────────────────────────────
# SQLite database
# ─────────────────────────────────────────────────────────────

class RegistrationDB:
    def __init__(self, db_path: str):
        self._path = db_path
        self._local = threading.local()
        self._restore_lock = threading.Lock()
        self._restore_gen  = 0   # incremented on every restore; forces conn reopen
        self._last_seen_lock = threading.Lock()
        self._last_seen_cache = {}
        self._wild_announce_gate_lock = threading.Lock()
        self._wild_announce_hash_seen: dict[str, float] = {}
        self._wild_announce_ip_seen: dict[str, tuple[str, float]] = {}
        self._wild_owner_warn_lock = threading.Lock()
        self._wild_owner_warn_at = 0.0
        self._wild_owner_warn_msg = ''
        self._tfa_fernet = _build_tfa_fernet()
        if (os.getenv('WK_TFA_SECRET_KEY', '') or '').strip() and not self._tfa_fernet:
            err = _TFA_FERNET_INIT_ERROR or 'WK_TFA_SECRET_KEY is set but invalid'
            log.error('TFA encryption key invalid: %s', err)
        self._init_schema()

    def _conn(self) -> sqlite3.Connection:
        # If a restore happened since this thread last opened, reopen
        if (not getattr(self._local, 'conn', None) or
                getattr(self._local, 'conn_gen', -1) != self._restore_gen):
            old = getattr(self._local, 'conn', None)
            if old:
                try:
                    old.close()
                except Exception:
                    pass
            conn = sqlite3.connect(
                self._path,
                check_same_thread=False,
                timeout=10,
                factory=_WKSQLiteConnection,
            )
            conn.row_factory = sqlite3.Row
            conn.execute('PRAGMA journal_mode=WAL')
            conn.execute('PRAGMA foreign_keys=ON')
            conn.execute('PRAGMA busy_timeout=10000')  # wait up to 10s on lock
            self._local.conn = conn
            self._local.conn_gen = self._restore_gen
        return self._local.conn

    def _rollback_quiet(self, conn: sqlite3.Connection | None = None) -> None:
        """Best-effort rollback helper for failed write attempts.

        Centralizes rollback-on-error behavior so IntegrityError paths do not
        accidentally leave open transactions behind.
        """
        c = conn if conn is not None else self._conn()
        try:
            c.rollback()
        except Exception:
            pass

    @staticmethod
    def _normalize_ip_for_storage(raw: str) -> str:
        txt = str(raw or '').strip()
        if not txt:
            return ''
        try:
            return ipaddress.ip_address(txt).compressed
        except Exception:
            return ''

    def _wild_intake_announce_gate(self, info_hash: str, source_ip: str) -> tuple[bool, str]:
        """In-memory debounce/rate-limit for announce-driven wild intake.

        - Debounce duplicate hash attempts for a short window.
        - Limit each source IP to one *new* hash submission per minute.
        """
        ih = str(info_hash or '').strip().upper()
        ip = self._normalize_ip_for_storage(source_ip)
        if not ih or not ip:
            return False, 'invalid source ip'
        now_ts = time.time()
        hash_ttl = float(WILD_INTAKE_ANNOUNCE_HASH_DEBOUNCE_SECONDS * 3)
        ip_ttl = float(WILD_INTAKE_ANNOUNCE_NEW_HASH_PER_IP_WINDOW_SECONDS * 3)
        with self._wild_announce_gate_lock:
            # Prune stale entries to keep memory bounded.
            stale_hashes = [k for k, ts in self._wild_announce_hash_seen.items() if (now_ts - float(ts)) > hash_ttl]
            for k in stale_hashes:
                self._wild_announce_hash_seen.pop(k, None)
            stale_ips = [k for k, v in self._wild_announce_ip_seen.items() if (now_ts - float(v[1])) > ip_ttl]
            for k in stale_ips:
                self._wild_announce_ip_seen.pop(k, None)

            last_hash_ts = float(self._wild_announce_hash_seen.get(ih, 0.0) or 0.0)
            if last_hash_ts > 0 and (now_ts - last_hash_ts) < float(WILD_INTAKE_ANNOUNCE_HASH_DEBOUNCE_SECONDS):
                return False, 'debounced'

            last = self._wild_announce_ip_seen.get(ip)
            if last:
                prev_ih, prev_ts = str(last[0] or ''), float(last[1] or 0.0)
                if prev_ih != ih and (now_ts - prev_ts) < float(WILD_INTAKE_ANNOUNCE_NEW_HASH_PER_IP_WINDOW_SECONDS):
                    return False, 'rate_limited'

            self._wild_announce_hash_seen[ih] = now_ts
            self._wild_announce_ip_seen[ip] = (ih, now_ts)
        return True, ''

    def _warn_wild_owner_invalid_once(self, msg: str, min_interval_sec: int = 60) -> None:
        txt = str(msg or '').strip()[:240]
        if not txt:
            return
        now_ts = time.time()
        with self._wild_owner_warn_lock:
            recent_same = (txt == self._wild_owner_warn_msg and (now_ts - float(self._wild_owner_warn_at)) < float(max(1, min_interval_sec)))
            if recent_same:
                return
            self._wild_owner_warn_msg = txt
            self._wild_owner_warn_at = now_ts
        log.warning('wild intake disabled path: %s', txt)

