    def get_torrent_srrdb_cache(self, info_hash: str):
        ih = (info_hash or '').strip().upper()
        if not re.fullmatch(r'[A-F0-9]{40}', ih):
            return None
        return self._conn().execute(
            'SELECT * FROM torrent_srrdb_cache WHERE info_hash=?',
            (ih,)
        ).fetchone()

    def _compare_srrdb_local_files(self, files_json_raw: str, archived_name: str, archived_size: int,
                                   nfo_name: str, nfo_size: int) -> dict[str, int]:
        files = _parse_torrent_files_json(files_json_raw)
        archived_found = 0
        archived_size_match = 0
        nfo_found = 0
        nfo_size_match = 0
        archived_local_size = 0
        nfo_local_size = 0
        archived_name_exact = 0
        nfo_name_exact = 0
        archived_match_name = ''
        nfo_match_name = ''

        cleanup_tags = _parse_torrent_name_cleanup_tags(
            self.get_setting('torrent_name_cleanup_tags', '')
        )
        strip_www_prefix = self.get_setting('torrent_name_cleanup_strip_www_prefix', '1') == '1'

        def _canon_filename(name: str) -> str:
            base = os.path.basename(str(name or '')).strip()
            if not base:
                return ''
            return _normalize_torrent_display_name(
                base,
                cleanup_tags,
                strip_www_prefix=strip_www_prefix,
                strip_extensions=False,
            ).strip().lower()

        file_rows: list[dict[str, Any]] = []
        for f in files:
            path = str(f.get('path') or '')
            base = os.path.basename(path).strip()
            if not base:
                continue
            try:
                local_size = int(f.get('size') or 0)
            except Exception:
                local_size = 0
            file_rows.append({
                'base': base,
                'base_l': base.lower(),
                'canon': _canon_filename(base),
                'size': local_size,
            })

        def _find_local_match(remote_name: str) -> tuple[int, int, int, str]:
            remote_base = os.path.basename(str(remote_name or '')).strip()
            if not remote_base:
                return 0, 0, 0, ''
            remote_l = remote_base.lower()
            remote_canon = _canon_filename(remote_base)

            # 1) Exact basename match
            for row in file_rows:
                if row['base_l'] == remote_l:
                    return 1, 1, int(row['size'] or 0), str(row['base'])

            # 2) Normalized fallback match
            if remote_canon:
                for row in file_rows:
                    if row['canon'] and row['canon'] == remote_canon:
                        return 1, 0, int(row['size'] or 0), str(row['base'])
            return 0, 0, 0, ''

        a_found, a_exact, a_local_size, a_local_name = _find_local_match(archived_name)
        archived_found = int(a_found)
        archived_name_exact = int(a_exact)
        archived_local_size = int(a_local_size or 0)
        archived_match_name = a_local_name
        if archived_found and int(archived_size or 0) > 0 and a_local_size == int(archived_size):
            archived_size_match = 1

        n_found, n_exact, n_local_size, n_local_name = _find_local_match(nfo_name)
        nfo_found = int(n_found)
        nfo_name_exact = int(n_exact)
        nfo_local_size = int(n_local_size or 0)
        nfo_match_name = n_local_name
        if nfo_found and int(nfo_size or 0) > 0 and n_local_size == int(nfo_size):
            nfo_size_match = 1

        return {
            'local_archived_found': archived_found,
            'local_archived_size_match': archived_size_match,
            'local_nfo_found': nfo_found,
            'local_nfo_size_match': nfo_size_match,
            'local_archived_name_exact': archived_name_exact,
            'local_nfo_name_exact': nfo_name_exact,
            'local_archived_match_name': archived_match_name,
            'local_nfo_match_name': nfo_match_name,
            'local_archived_size': archived_local_size,
            'local_nfo_size': nfo_local_size,
        }

    def refresh_torrent_srrdb_cache(self, info_hash: str, actor_username: str = 'system',
                                    force: bool = False) -> tuple[bool, str]:
        ih = (info_hash or '').strip().upper()
        if not re.fullmatch(r'[A-F0-9]{40}', ih):
            return False, 'Invalid info hash.'
        cfg = self.get_srrdb_config()
        if not cfg.get('enabled', False):
            return False, 'SRRDB is disabled.'
        trow = self.get_torrent(ih)
        if not trow:
            return False, 'Torrent not found.'
        now_ts = self._ts()
        if not force:
            cached = self.get_torrent_srrdb_cache(ih)
            if cached:
                try:
                    age = datetime.datetime.now() - _parse_iso(str(cached['fetched_at'] or ''))
                    if age.total_seconds() < (int(cfg.get('cache_ttl_hours', 72)) * 3600):
                        return True, 'Cached SRRDB data is still fresh.'
                except Exception:
                    pass

        cleanup_tags = _parse_torrent_name_cleanup_tags(
            self.get_setting('torrent_name_cleanup_tags', '')
        )
        strip_www_prefix = self.get_setting('torrent_name_cleanup_strip_www_prefix', '1') == '1'
        strip_extensions = self.get_setting('torrent_name_cleanup_strip_extensions', '1') == '1'
        cleaned_name = _normalize_torrent_display_name(
            str(trow['name'] or ''), cleanup_tags,
            strip_www_prefix=strip_www_prefix,
            strip_extensions=strip_extensions,
        )
        release_name = _normalize_release_name_for_srrdb(cleaned_name)
        if not release_name:
            return False, 'Unable to build SRRDB release query.'
        base = (cfg.get('api_base_url') or 'https://api.srrdb.com/v1').rstrip('/')
        timeout_sec = int(cfg.get('timeout_sec', 5))
        search_key = urllib.parse.quote(f'r:{release_name}', safe=':')
        ok_search, search_raw, err_search = self._metadata_http_get_json(
            f'{base}/search/{search_key}', timeout_sec
        )
        match_release = ''
        if ok_search:
            results = search_raw.get('results') if isinstance(search_raw, dict) else None
            if isinstance(results, list) and results:
                match_release = str((results[0] or {}).get('release') or '').strip()
        if not match_release:
            for attempt in range(6):
                try:
                    c = self._conn()
                    c.execute(
                        '''INSERT INTO torrent_srrdb_cache (
                               info_hash, release_name, matched, srrdb_release, details_url,
                               nfo_name, nfo_url, imdb_id, imdb_title, archived_name, archived_size,
                               archived_crc, nfo_size, nfo_crc, local_archived_found, local_archived_size_match,
                               local_nfo_found, local_nfo_size_match, fetched_at, fetch_error, raw_json
                           ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
                           ON CONFLICT(info_hash) DO UPDATE SET
                               release_name=excluded.release_name,
                               matched=excluded.matched,
                               srrdb_release=excluded.srrdb_release,
                               details_url=excluded.details_url,
                               nfo_name=excluded.nfo_name,
                               nfo_url=excluded.nfo_url,
                               imdb_id=excluded.imdb_id,
                               imdb_title=excluded.imdb_title,
                               archived_name=excluded.archived_name,
                               archived_size=excluded.archived_size,
                               archived_crc=excluded.archived_crc,
                               nfo_size=excluded.nfo_size,
                               nfo_crc=excluded.nfo_crc,
                               local_archived_found=excluded.local_archived_found,
                               local_archived_size_match=excluded.local_archived_size_match,
                               local_nfo_found=excluded.local_nfo_found,
                               local_nfo_size_match=excluded.local_nfo_size_match,
                               fetched_at=excluded.fetched_at,
                               fetch_error=excluded.fetch_error,
                               raw_json=excluded.raw_json''',
                        (
                            ih, release_name, 0, '', '', '', '', '', '', '', 0, '', 0, '',
                            0, 0, 0, 0, now_ts,
                            str(err_search or 'No SRRDB match found.')[:500],
                            json.dumps({'search': search_raw if ok_search else {}, 'error': err_search or ''}, ensure_ascii=False),
                        )
                    )
                    c.commit()
                    self._log(actor_username, 'srrdb_cache_refresh', ih, f'matched=0 release={release_name}')
                    return False, 'No SRRDB match found.'
                except sqlite3.OperationalError as e:
                    if 'locked' in str(e).lower() and attempt < 5:
                        time.sleep(0.08 * (attempt + 1))
                        continue
                    if 'locked' in str(e).lower():
                        log.warning('refresh_torrent_srrdb_cache lock after retries (non-fatal): ih=%s actor=%s err=%s',
                                    ih, actor_username, e)
                        return False, 'Database is busy, please retry SRRDB refresh.'
                    raise

        ok_details, details_raw, err_details = self._metadata_http_get_json(
            f'{base}/details/{urllib.parse.quote(match_release, safe="")}', timeout_sec
        )
        ok_nfo, nfo_raw, err_nfo = self._metadata_http_get_json(
            f'{base}/nfo/{urllib.parse.quote(match_release, safe="")}', timeout_sec
        )
        ok_imdb, imdb_raw, _err_imdb = self._metadata_http_get_json(
            f'{base}/imdb/{urllib.parse.quote(match_release, safe="")}', timeout_sec
        )

        archived_name = ''
        archived_size = 0
        archived_crc = ''
        nfo_name = ''
        nfo_url = ''
        nfo_size = 0
        nfo_crc = ''
        imdb_id = ''
        imdb_title = ''
        if ok_details and isinstance(details_raw, dict):
            archived = details_raw.get('archived-files')
            if isinstance(archived, list) and archived:
                first = archived[0] if isinstance(archived[0], dict) else {}
                archived_name = str(first.get('name') or '')
                try:
                    archived_size = int(first.get('size') or 0)
                except Exception:
                    archived_size = 0
                archived_crc = str(first.get('crc') or '')
            files = details_raw.get('files')
            if isinstance(files, list):
                for f in files:
                    if not isinstance(f, dict):
                        continue
                    fname = str(f.get('name') or '')
                    if fname.lower().endswith('.nfo'):
                        nfo_name = fname
                        try:
                            nfo_size = int(f.get('size') or 0)
                        except Exception:
                            nfo_size = 0
                        nfo_crc = str(f.get('crc') or '')
                        break
        if ok_nfo and isinstance(nfo_raw, dict):
            nfo_list = nfo_raw.get('nfo')
            nfo_links = nfo_raw.get('nfolink')
            if isinstance(nfo_list, list) and nfo_list and not nfo_name:
                nfo_name = str(nfo_list[0] or '')
            if isinstance(nfo_links, list) and nfo_links:
                nfo_url = str(nfo_links[0] or '')
        if ok_imdb and isinstance(imdb_raw, dict):
            rels = imdb_raw.get('releases')
            if isinstance(rels, list) and rels:
                first_rel = rels[0] if isinstance(rels[0], dict) else {}
                iid = str(first_rel.get('imdb') or '').strip()
                if iid.isdigit():
                    imdb_id = f'tt{iid}'
                elif iid.lower().startswith('tt'):
                    imdb_id = iid.lower()
                imdb_title = str(first_rel.get('title') or '')

        local_cmp = self._compare_srrdb_local_files(
            str(trow['files_json'] or ''), archived_name, archived_size, nfo_name, nfo_size
        )
        details_url = f'https://www.srrdb.com/release/details/{urllib.parse.quote(match_release, safe="")}'
        fetch_error = ''
        if not ok_details:
            fetch_error = err_details or 'Failed to fetch SRRDB details.'
        elif not ok_nfo:
            fetch_error = err_nfo or 'Failed to fetch SRRDB NFO data.'

        for attempt in range(6):
            try:
                c = self._conn()
                c.execute(
                    '''INSERT INTO torrent_srrdb_cache (
                           info_hash, release_name, matched, srrdb_release, details_url,
                           nfo_name, nfo_url, imdb_id, imdb_title, archived_name, archived_size,
                           archived_crc, nfo_size, nfo_crc, local_archived_found, local_archived_size_match,
                           local_nfo_found, local_nfo_size_match, fetched_at, fetch_error, raw_json
                       ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
                       ON CONFLICT(info_hash) DO UPDATE SET
                           release_name=excluded.release_name,
                           matched=excluded.matched,
                           srrdb_release=excluded.srrdb_release,
                           details_url=excluded.details_url,
                           nfo_name=excluded.nfo_name,
                           nfo_url=excluded.nfo_url,
                           imdb_id=excluded.imdb_id,
                           imdb_title=excluded.imdb_title,
                           archived_name=excluded.archived_name,
                           archived_size=excluded.archived_size,
                           archived_crc=excluded.archived_crc,
                           nfo_size=excluded.nfo_size,
                           nfo_crc=excluded.nfo_crc,
                           local_archived_found=excluded.local_archived_found,
                           local_archived_size_match=excluded.local_archived_size_match,
                           local_nfo_found=excluded.local_nfo_found,
                           local_nfo_size_match=excluded.local_nfo_size_match,
                           fetched_at=excluded.fetched_at,
                           fetch_error=excluded.fetch_error,
                           raw_json=excluded.raw_json''',
                    (
                        ih, release_name, 1, match_release, details_url,
                        nfo_name[:400], nfo_url[:1000], imdb_id[:32], imdb_title[:200],
                        archived_name[:400], int(archived_size or 0), archived_crc[:32],
                        int(nfo_size or 0), nfo_crc[:32],
                        int(local_cmp.get('local_archived_found', 0)),
                        int(local_cmp.get('local_archived_size_match', 0)),
                        int(local_cmp.get('local_nfo_found', 0)),
                        int(local_cmp.get('local_nfo_size_match', 0)),
                        now_ts, fetch_error[:500],
                        json.dumps({
                            'search': search_raw if ok_search else {},
                            'details': {'ok': ok_details, 'error': err_details or ''},
                            'nfo': {'ok': ok_nfo, 'error': err_nfo or ''},
                            'imdb': {'ok': ok_imdb},
                        }, ensure_ascii=False),
                    )
                )
                c.commit()
                self._log(actor_username, 'srrdb_cache_refresh', ih,
                          f'matched=1 release={match_release} error={fetch_error[:120]}')
                return True, ('SRRDB matched.' if not fetch_error else 'SRRDB matched with partial data.')
            except sqlite3.OperationalError as e:
                if 'locked' in str(e).lower() and attempt < 5:
                    time.sleep(0.08 * (attempt + 1))
                    continue
                if 'locked' in str(e).lower():
                    log.warning('refresh_torrent_srrdb_cache lock after retries (non-fatal): ih=%s actor=%s err=%s',
                                ih, actor_username, e)
                    return False, 'Database is busy, please retry SRRDB refresh.'
                raise
        return False, 'Database is busy, please retry SRRDB refresh.'

    def list_metadata_proposals_for_torrent(self, info_hash: str, limit: int = 20) -> list:
        ih = (info_hash or '').strip().upper()
        if not ih:
            return []
        return self._conn().execute(
            '''SELECT * FROM torrent_metadata_proposals
               WHERE info_hash=?
               ORDER BY id DESC
               LIMIT ?''',
            (ih, max(1, min(200, int(limit))))
        ).fetchall()

    def get_active_metadata_proposal(self, info_hash: str, provider: str):
        ih = (info_hash or '').strip().upper()
        p = _normalize_metadata_provider(provider)
        if not ih or not p:
            return None
        return self._conn().execute(
            '''SELECT * FROM torrent_metadata_proposals
               WHERE info_hash=? AND provider=? AND status='pending'
               ORDER BY id DESC LIMIT 1''',
            (ih, p)
        ).fetchone()

    def get_metadata_proposal(self, proposal_id: int):
        return self._conn().execute(
            'SELECT * FROM torrent_metadata_proposals WHERE id=?',
            (int(proposal_id),)
        ).fetchone()

    def create_metadata_proposal(self, info_hash: str, provider: str, proposed_id: str,
                                 proposer_user_id: int, proposer_username: str,
                                 proposed_url: str = '', season: int | None = None,
                                 episode: int | None = None):
        ih = (info_hash or '').strip().upper()
        p = _normalize_metadata_provider(provider)
        if not ih or not p:
            return False, 'Invalid metadata provider.'
        trow = self.get_torrent(ih)
        if not trow:
            return False, 'Torrent not found.'
        # Anti-spam guardrails for community proposal volume.
        uid = int(proposer_user_id or 0)
        if uid > 0:
            proposer = self.get_user_by_id(uid)
            is_owner = int(trow['uploaded_by_id'] or 0) == int(uid)
            is_privileged = bool(
                proposer and (
                    str(proposer['username'] or '') == SUPER_USER or
                    int(proposer['is_admin'] or 0) == 1 or
                    int(proposer['is_editor'] or 0) == 1
                )
            )
            if not is_privileged and not is_owner:
                now = datetime.datetime.now()
                cutoff_24h = (now - datetime.timedelta(hours=24)).isoformat()
                cutoff_10m = (now - datetime.timedelta(minutes=10)).isoformat()
                c = self._conn()
                day_count = int(c.execute(
                    '''SELECT COUNT(*) FROM torrent_metadata_proposals
                       WHERE proposed_by_user_id=? AND created_at>=?''',
                    (uid, cutoff_24h)
                ).fetchone()[0] or 0)
                burst_count = int(c.execute(
                    '''SELECT COUNT(*) FROM torrent_metadata_proposals
                       WHERE proposed_by_user_id=? AND created_at>=?''',
                    (uid, cutoff_10m)
                ).fetchone()[0] or 0)
                if day_count >= 10:
                    self._log(proposer_username, 'metadata_propose_rate_limited', str(uid),
                              f'window=24h count={day_count}')
                    return False, 'Proposal rate limit reached (10 per 24h). Please try again later.'
                if burst_count >= 3:
                    self._log(proposer_username, 'metadata_propose_rate_limited', str(uid),
                              f'window=10m count={burst_count}')
                    return False, 'Proposal burst limit reached (3 per 10 minutes). Please wait and try again.'
        if p == 'imdb':
            ext_id = _validate_imdb_id(proposed_id)
            if not ext_id:
                return False, 'Invalid IMDb ID format.'
        elif p == 'tvmaze':
            ext_id = _validate_tvmaze_id(proposed_id)
            inferred_season, inferred_episode = _infer_tv_season_episode(str(trow['name'] or ''))
            if season is None:
                season = inferred_season
            if episode is None:
                episode = inferred_episode
            if not ext_id:
                show_query = _infer_tv_show_query(str(trow['name'] or ''))
                if not show_query:
                    return False, 'TVMaze show ID is required (auto-detect could not infer show name).'
                auto_id, auto_name, auto_url = self._search_tvmaze_show(show_query, self.get_metadata_config())
                if not auto_id:
                    return False, 'TVMaze show ID is required (auto-detect did not find a unique show).'
                ext_id = auto_id
                if not proposed_url:
                    proposed_url = auto_url
                self._log(proposer_username, 'metadata_tvmaze_auto_match', ih,
                          f'query={show_query[:80]} matched={auto_name[:80]} id={ext_id}')
            if not ext_id:
                return False, 'Invalid TVMaze show ID format.'
        else:
            ext_id = _validate_steam_app_id(proposed_id)
            if not ext_id:
                return False, 'Invalid Steam app ID format.'
            season = None
            episode = None
        cfg = self.get_metadata_config()
        now = datetime.datetime.now()
        closes_at = now + datetime.timedelta(hours=cfg['vote_window_hours'])
        ts_now = self._ts()
        c = self._conn()
        use_savepoint = bool(getattr(c, 'in_transaction', False))
        sp_name = 'wk_meta_propose'
        for attempt in range(8):
            try:
                if use_savepoint:
                    c.execute(f'SAVEPOINT {sp_name}')
                else:
                    c.execute('BEGIN IMMEDIATE')
                # Guard: one active proposal per provider per torrent.
                active = c.execute(
                    '''SELECT id FROM torrent_metadata_proposals
                       WHERE info_hash=? AND provider=? AND status='pending'
                       ORDER BY id DESC LIMIT 1''',
                    (ih, p)
                ).fetchone()
                if active:
                    if use_savepoint:
                        c.execute(f'ROLLBACK TO SAVEPOINT {sp_name}')
                        c.execute(f'RELEASE SAVEPOINT {sp_name}')
                    else:
                        c.execute('ROLLBACK')
                    return False, 'An active proposal already exists for this provider.'
                c.execute(
                    '''INSERT INTO torrent_metadata_proposals (
                           info_hash, provider, proposed_id, proposed_url, season, episode,
                           proposed_by_user_id, proposed_by_username, status,
                           decision_reason, decided_by_user_id, decided_by_username, decided_at,
                           voting_opened_at, voting_closes_at, auto_finalize_at,
                           rewards_issued_at, created_at, updated_at
                       ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)''',
                    (ih, p, ext_id, (proposed_url or '')[:500], season, episode,
                     int(proposer_user_id), proposer_username[:64], 'pending',
                     '', None, None, None,
                     ts_now, closes_at.isoformat(), closes_at.isoformat(),
                     None, ts_now, ts_now)
                )
                if use_savepoint:
                    c.execute(f'RELEASE SAVEPOINT {sp_name}')
                else:
                    c.execute('COMMIT')
                break
            except sqlite3.IntegrityError:
                try:
                    if use_savepoint:
                        c.execute(f'ROLLBACK TO SAVEPOINT {sp_name}')
                        c.execute(f'RELEASE SAVEPOINT {sp_name}')
                    else:
                        c.execute('ROLLBACK')
                except Exception:
                    pass
                return False, 'This metadata target has already been proposed for this torrent.'
            except sqlite3.OperationalError as e:
                try:
                    if use_savepoint:
                        c.execute(f'ROLLBACK TO SAVEPOINT {sp_name}')
                        c.execute(f'RELEASE SAVEPOINT {sp_name}')
                    else:
                        c.execute('ROLLBACK')
                except Exception:
                    pass
                if 'locked' in str(e).lower() and attempt < 7:
                    time.sleep(0.08 * (attempt + 1))
                    continue
                if 'locked' in str(e).lower():
                    log.warning('create_metadata_proposal lock after retries (non-fatal): ih=%s provider=%s err=%s',
                                ih, p, e)
                    return False, 'Database is busy, please retry metadata submission.'
                raise
        proposal_id = int(c.execute('SELECT last_insert_rowid()').fetchone()[0])
        self._log(proposer_username, 'metadata_propose', ih,
                  f'proposal_id={proposal_id} provider={p} id={ext_id}')
        return True, proposal_id

    def cast_metadata_proposal_vote(self, proposal_id: int, voter_user_id: int,
                                    voter_username: str, vote: int):
        p = self.get_metadata_proposal(int(proposal_id))
        if not p:
            return False, 'Proposal not found.'
        if (p['status'] or '') != 'pending':
            return False, 'Proposal is no longer open for voting.'
        v = 1 if int(vote) > 0 else -1
        if int(voter_user_id) == int(p['proposed_by_user_id'] or 0):
            return False, 'You cannot vote on your own proposal.'
        c = self._conn()
        # Toggle semantics: same vote removes vote.
        prev = c.execute(
            'SELECT vote FROM torrent_metadata_proposal_votes WHERE proposal_id=? AND voter_user_id=?',
            (int(proposal_id), int(voter_user_id))
        ).fetchone()
        if prev and int(prev['vote'] or 0) == v:
            c.execute(
                'DELETE FROM torrent_metadata_proposal_votes WHERE proposal_id=? AND voter_user_id=?',
                (int(proposal_id), int(voter_user_id))
            )
            c.execute(
                'UPDATE torrent_metadata_proposals SET updated_at=? WHERE id=?',
                (self._ts(), int(proposal_id))
            )
            c.commit()
            self._log(voter_username, 'metadata_vote_remove', str(proposal_id), f'vote={v:+d}')
            return True, 'Vote removed.'
        c.execute(
            '''INSERT INTO torrent_metadata_proposal_votes
               (proposal_id, voter_user_id, voter_username, vote, voted_at)
               VALUES (?,?,?,?,?)
               ON CONFLICT(proposal_id, voter_user_id)
               DO UPDATE SET vote=excluded.vote, voted_at=excluded.voted_at, voter_username=excluded.voter_username''',
            (int(proposal_id), int(voter_user_id), voter_username[:64], v, self._ts())
        )
        c.execute(
            'UPDATE torrent_metadata_proposals SET updated_at=? WHERE id=?',
            (self._ts(), int(proposal_id))
        )
        c.commit()
        self._log(voter_username, 'metadata_vote', str(proposal_id), f'vote={v:+d}')
        return True, 'Vote recorded.'

    def get_metadata_proposal_vote_summary(self, proposal_id: int, viewer_user_id: int = 0) -> dict:
        c = self._conn()
        row = c.execute(
            '''SELECT
                 COALESCE(SUM(CASE WHEN vote=1 THEN 1 ELSE 0 END),0) AS up,
                 COALESCE(SUM(CASE WHEN vote=-1 THEN 1 ELSE 0 END),0) AS down,
                 COALESCE(COUNT(DISTINCT voter_user_id),0) AS unique_voters
               FROM torrent_metadata_proposal_votes
               WHERE proposal_id=?''',
            (int(proposal_id),)
        ).fetchone()
        up = int(row['up'] or 0)
        down = int(row['down'] or 0)
        my_vote = 0
        if int(viewer_user_id or 0) > 0:
            my = c.execute(
                'SELECT vote FROM torrent_metadata_proposal_votes WHERE proposal_id=? AND voter_user_id=?',
                (int(proposal_id), int(viewer_user_id))
            ).fetchone()
            if my:
                my_vote = int(my['vote'] or 0)
        return {
            'up': up,
            'down': down,
            'net': up - down,
            'unique_voters': int(row['unique_voters'] or 0),
            'my_vote': my_vote,
        }

    def get_metadata_cache_for_link(self, link):
        if not link:
            return None
        provider = str(link['provider'] or '')
        external_id = str(link['external_id'] or '')
        if not provider or not external_id:
            return None
        epi = str(link['episode_external_id'] or '').strip()
        if epi:
            row = self._conn().execute(
                '''SELECT * FROM torrent_metadata_cache
                   WHERE provider=? AND external_id=? AND COALESCE(episode_external_id,'')=?
                   ORDER BY id DESC LIMIT 1''',
                (provider, external_id, epi)
            ).fetchone()
            if row:
                return row
        return self._conn().execute(
            '''SELECT * FROM torrent_metadata_cache
               WHERE provider=? AND external_id=? AND COALESCE(episode_external_id,'')=''
               ORDER BY id DESC LIMIT 1''',
            (provider, external_id)
        ).fetchone()

    def get_metadata_cache_for_target(self, provider: str, external_id: str,
                                      season: int | None = None, episode: int | None = None):
        p = str(provider or '').strip().lower()
        ext = str(external_id or '').strip()
        if not p or not ext:
            return None
        rows = self._conn().execute(
            '''SELECT * FROM torrent_metadata_cache
               WHERE provider=? AND external_id=?
               ORDER BY id DESC
               LIMIT 12''',
            (p, ext)
        ).fetchall()
        if not rows:
            return None
        if season is None or episode is None:
            return rows[0]
        for r in rows:
            try:
                raw = json.loads(r['raw_json'] or '{}')
                ep = (raw.get('episode') or {}) if isinstance(raw, dict) else {}
                if int(ep.get('season')) == int(season) and int(ep.get('number')) == int(episode):
                    return r
            except Exception:
                continue
        return rows[0]

    def _upsert_metadata_cache(self, provider: str, external_id: str,
                               payload: dict, episode_external_id: str = '') -> None:
        now = self._ts()
        epi = (episode_external_id or '').strip()
        self._conn().execute(
            '''INSERT INTO torrent_metadata_cache (
                   provider, external_id, episode_external_id, title, subtitle, year, media_type,
                   genres_json, runtime_minutes, rating_value, rating_count, network_name,
                   poster_url, canonical_url, episode_url, fetched_ok, fetch_error,
                   fetched_at, raw_json
               ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
               ON CONFLICT(provider, external_id, COALESCE(episode_external_id,''))
               DO UPDATE SET
                 title=excluded.title,
                 subtitle=excluded.subtitle,
                 year=excluded.year,
                 media_type=excluded.media_type,
                 genres_json=excluded.genres_json,
                 runtime_minutes=excluded.runtime_minutes,
                 rating_value=excluded.rating_value,
                 rating_count=excluded.rating_count,
                 network_name=excluded.network_name,
                 poster_url=excluded.poster_url,
                 canonical_url=excluded.canonical_url,
                 episode_url=excluded.episode_url,
                 fetched_ok=excluded.fetched_ok,
                 fetch_error=excluded.fetch_error,
                 fetched_at=excluded.fetched_at,
                 raw_json=excluded.raw_json''',
            (
                provider, external_id, epi,
                str(payload.get('title') or '')[:200],
                str(payload.get('subtitle') or '')[:300],
                payload.get('year'),
                str(payload.get('media_type') or '')[:40],
                json.dumps(payload.get('genres') or []),
                payload.get('runtime_minutes'),
                payload.get('rating_value'),
                payload.get('rating_count'),
                str(payload.get('network_name') or '')[:120],
                str(payload.get('poster_url') or '')[:1000],
                str(payload.get('canonical_url') or '')[:1000],
                str(payload.get('episode_url') or '')[:1000],
                1 if payload.get('fetched_ok', True) else 0,
                str(payload.get('fetch_error') or '')[:500],
                now,
                json.dumps(payload.get('raw') or {}, ensure_ascii=False),
            )
        )
        self._conn().commit()

    def _metadata_http_get_json(self, url: str, timeout_sec: int) -> tuple[bool, dict, str]:
        req = urllib.request.Request(
            url,
            headers={
                'Accept': 'application/json',
                'User-Agent': 'wildkat-tracker/metadata-fetch',
            },
            method='GET',
        )
        try:
            with urllib.request.urlopen(req, timeout=max(1, int(timeout_sec))) as resp:
                data = json.loads(resp.read().decode('utf-8', errors='replace') or '{}')
                return True, (data if isinstance(data, dict) else {}), ''
        except urllib.error.HTTPError as e:
            return False, {}, f'HTTP {e.code}'
        except Exception as e:
            return False, {}, str(e)

    def _metadata_http_url_exists(self, url: str, timeout_sec: int) -> bool:
        target = (url or '').strip()
        if not target:
            return False
        headers = {'User-Agent': 'wildkat-tracker/metadata-fetch'}
        try:
            req = urllib.request.Request(target, headers=headers, method='HEAD')
            with urllib.request.urlopen(req, timeout=max(1, int(timeout_sec))) as resp:
                return int(getattr(resp, 'status', 200) or 200) < 400
        except urllib.error.HTTPError as e:
            # Some origins do not allow HEAD; do a lightweight GET probe instead.
            if int(getattr(e, 'code', 500) or 500) in (403, 405):
                try:
                    req = urllib.request.Request(
                        target,
                        headers={**headers, 'Range': 'bytes=0-0'},
                        method='GET',
                    )
                    with urllib.request.urlopen(req, timeout=max(1, int(timeout_sec))) as resp:
                        return int(getattr(resp, 'status', 200) or 200) < 400
                except Exception:
                    return False
            return False
        except Exception:
            return False

    def _fetch_omdb_metadata(self, imdb_id: str, cfg: dict) -> tuple[bool, dict, str]:
        api_key = (cfg.get('omdb_api_key') or '').strip()
        if not api_key:
            return False, {}, 'OMDb API key is not configured.'
        base = (cfg.get('omdb_base_url') or 'https://www.omdbapi.com/').rstrip('/')
        q = urllib.parse.urlencode({'apikey': api_key, 'i': imdb_id, 'plot': 'short'})
        ok, raw, err = self._metadata_http_get_json(f'{base}/?{q}', int(cfg.get('fetch_timeout_sec', 5)))
        if not ok:
            return False, {}, err
        if str(raw.get('Response', '')).lower() != 'true':
            return False, {}, str(raw.get('Error') or 'OMDb returned no match.')
        rating_val = None
        try:
            rating_val = float(raw.get('imdbRating')) if raw.get('imdbRating') not in (None, 'N/A', '') else None
        except Exception:
            rating_val = None
        rating_count = None
        try:
            rc = str(raw.get('imdbVotes') or '').replace(',', '')
            rating_count = int(rc) if rc.isdigit() else None
        except Exception:
            rating_count = None
        year = None
        try:
            year = int(str(raw.get('Year') or '')[:4])
        except Exception:
            year = None
        runtime = None
        try:
            runtime = int(str(raw.get('Runtime') or '').split(' ')[0])
        except Exception:
            runtime = None
        payload = {
            'title': str(raw.get('Title') or ''),
            'subtitle': _strip_html_text(str(raw.get('Plot') or '')),
            'year': year,
            'media_type': str(raw.get('Type') or ''),
            'genres': [g.strip() for g in str(raw.get('Genre') or '').split(',') if g.strip()],
            'runtime_minutes': runtime,
            'rating_value': rating_val,
            'rating_count': rating_count,
            'network_name': '',
            'poster_url': _normalize_external_image_url('' if str(raw.get('Poster') or '') == 'N/A' else str(raw.get('Poster') or '')),
            'canonical_url': f'https://www.imdb.com/title/{imdb_id}/',
            'episode_url': '',
            'raw': raw,
            'fetched_ok': True,
        }
        return True, payload, ''

    def _search_tvmaze_show(self, query: str, cfg: dict) -> tuple[str, str, str]:
        q = (query or '').strip()
        if not q:
            return '', '', ''
        base = (cfg.get('tvmaze_base_url') or 'https://api.tvmaze.com').rstrip('/')
        url = f'{base}/search/shows?q={urllib.parse.quote(q)}'
        req = urllib.request.Request(
            url,
            headers={'Accept': 'application/json', 'User-Agent': 'wildkat-tracker/metadata-fetch'},
            method='GET',
        )
        try:
            with urllib.request.urlopen(req, timeout=max(1, int(cfg.get('fetch_timeout_sec', 5)))) as resp:
                data = json.loads(resp.read().decode('utf-8', errors='replace') or '[]')
        except Exception:
            return '', '', ''
        if not isinstance(data, list) or not data:
            return '', '', ''

        def _norm(s: str) -> str:
            return re.sub(r'[^a-z0-9]+', '', (s or '').lower())

        qn = _norm(q)
        best = None
        best_score = -1
        for row in data[:10]:
            show = row.get('show') if isinstance(row, dict) else None
            if not isinstance(show, dict):
                continue
            sid = str(show.get('id') or '')
            name = str(show.get('name') or '')
            if not sid.isdigit():
                continue
            sn = _norm(name)
            score = 0
            if sn == qn:
                score = 100
            elif sn.startswith(qn) or qn.startswith(sn):
                score = 80
            else:
                score = 50
            if score > best_score:
                best = (sid, name, str(show.get('url') or f'https://www.tvmaze.com/shows/{sid}'))
                best_score = score
        return best if best else ('', '', '')

    def _fetch_tvmaze_metadata(self, show_id: str, season: int | None, episode: int | None, cfg: dict) -> tuple[bool, dict, str]:
        base = (cfg.get('tvmaze_base_url') or 'https://api.tvmaze.com').rstrip('/')
        timeout_sec = int(cfg.get('fetch_timeout_sec', 5))
        ok_show, show_raw, err_show = self._metadata_http_get_json(f'{base}/shows/{show_id}', timeout_sec)
        if not ok_show:
            return False, {}, err_show
        if not show_raw or ('id' not in show_raw):
            return False, {}, 'TVMaze show not found.'
        episode_raw = {}
        episode_id = ''
        episode_url = ''
        subtitle = _strip_html_text(str(show_raw.get('summary') or ''))
        title = str(show_raw.get('name') or '')
        if season is not None and episode is not None:
            qs = urllib.parse.urlencode({'season': int(season), 'number': int(episode)})
            ok_ep, ep_raw, err_ep = self._metadata_http_get_json(f'{base}/shows/{show_id}/episodebynumber?{qs}', timeout_sec)
            if ok_ep and ep_raw and ('id' in ep_raw):
                episode_raw = ep_raw
                episode_id = str(ep_raw.get('id') or '')
                episode_url = str(ep_raw.get('url') or '')
                subtitle = _strip_html_text(str(ep_raw.get('summary') or subtitle))
                ep_name = str(ep_raw.get('name') or '').strip()
                if ep_name:
                    title = ep_name
        rating_value = None
        try:
            rating_value = float((show_raw.get('rating') or {}).get('average'))
        except Exception:
            rating_value = None
        runtime_minutes = None
        try:
            runtime_minutes = int(show_raw.get('runtime'))
        except Exception:
            runtime_minutes = None
        premiered = str(show_raw.get('premiered') or '')
        year = None
        if len(premiered) >= 4 and premiered[:4].isdigit():
            year = int(premiered[:4])
        payload = {
            'title': title,
            'subtitle': subtitle,
            'year': year,
            'media_type': str(show_raw.get('type') or 'show'),
            'genres': show_raw.get('genres') or [],
            'runtime_minutes': runtime_minutes,
            'rating_value': rating_value,
            'rating_count': None,
            'network_name': str(((show_raw.get('network') or {}).get('name')) or ((show_raw.get('webChannel') or {}).get('name')) or ''),
            'poster_url': _normalize_external_image_url(str(((show_raw.get('image') or {}).get('original')) or ((show_raw.get('image') or {}).get('medium')) or '')),
            'canonical_url': str(show_raw.get('url') or ''),
            'episode_url': episode_url,
            'episode_external_id': episode_id,
            'raw': {'show': show_raw, 'episode': episode_raw},
            'fetched_ok': True,
        }
        return True, payload, ''

    def _fetch_steam_metadata(self, app_id: str, cfg: dict) -> tuple[bool, dict, str]:
        timeout_sec = int(cfg.get('fetch_timeout_sec', 5))
        url = f'https://store.steampowered.com/api/appdetails?appids={urllib.parse.quote(str(app_id))}'
        ok, raw, err = self._metadata_http_get_json(url, timeout_sec)
        if not ok:
            return False, {}, err
        entry = raw.get(str(app_id)) if isinstance(raw, dict) else None
        if not isinstance(entry, dict):
            return False, {}, 'Steam returned no app data.'
        if not bool(entry.get('success')):
            return False, {}, 'Steam app not found.'
        data = entry.get('data')
        if not isinstance(data, dict):
            return False, {}, 'Steam app payload invalid.'
        title = str(data.get('name') or '').strip()
        if not title:
            return False, {}, 'Steam app title missing.'
        subtitle = _strip_html_text(str(data.get('short_description') or ''))
        year = None
        release_date = str((data.get('release_date') or {}).get('date') or '')
        m = re.search(r'(19|20)\d{2}', release_date)
        if m:
            year = int(m.group(0))
        genres = []
        for g in (data.get('genres') or []):
            if isinstance(g, dict):
                desc = str(g.get('description') or '').strip()
                if desc:
                    genres.append(desc)
        rating_value = None
        try:
            score = int((data.get('metacritic') or {}).get('score'))
            if score > 0:
                rating_value = round(score / 10.0, 1)
        except Exception:
            rating_value = None
        payload = {
            'title': title,
            'subtitle': subtitle,
            'year': year,
            'media_type': 'game',
            'genres': genres,
            'runtime_minutes': None,
            'rating_value': rating_value,
            'rating_count': None,
            'network_name': '',
            'poster_url': _normalize_external_image_url(str(data.get('header_image') or '')),
            'canonical_url': f'https://store.steampowered.com/app/{app_id}/',
            'episode_url': '',
            'raw': raw,
            'fetched_ok': True,
        }
        return True, payload, ''

    def _search_omdb_title(self, title_query: str, media_type: str,
                           year: int | None, cfg: dict) -> tuple[bool, dict, str]:
        api_key = (cfg.get('omdb_api_key') or '').strip()
        if not api_key:
            return False, {}, 'OMDb API key is not configured.'
        tq = (title_query or '').strip()
        if not tq:
            return False, {}, 'Missing title query.'
        base = (cfg.get('omdb_base_url') or 'https://www.omdbapi.com/').rstrip('/')
        timeout = int(cfg.get('fetch_timeout_sec', 5))
        # Remove obvious non-title wrappers while preserving year for `y=` query param.
        tq = re.sub(r'\(\s*(19\d{2}|20\d{2})\s*\)', ' ', tq)
        tq = re.sub(r'\s+', ' ', tq).strip()
        title_variants: list[str] = [tq]
        stripped = re.sub(r'(?i)^(the|a|an)\s+', '', tq).strip()
        if stripped and stripped.lower() != tq.lower():
            title_variants.append(stripped)
        # OMDb title matches can be sensitive to "&" vs "and".
        and_amp_variants: list[str] = []
        for title in list(title_variants):
            v1 = re.sub(r'(?i)\band\b', '&', title).strip()
            v2 = title.replace('&', ' and ').strip()
            v2 = re.sub(r'\s+', ' ', v2)
            and_amp_variants.extend([v1, v2])
        for candidate in and_amp_variants:
            if candidate and all(candidate.lower() != existing.lower() for existing in title_variants):
                title_variants.append(candidate)
        # Release names often strip apostrophes (were -> we're). Add conservative variants.
        contraction_map = {
            'were': "we're",
            'youre': "you're",
            'dont': "don't",
            'cant': "can't",
            'wont': "won't",
            'isnt': "isn't",
            'arent': "aren't",
            'doesnt': "doesn't",
            'didnt': "didn't",
            'im': "i'm",
            'ive': "i've",
        }
        contraction_variants: list[str] = []
        for title in list(title_variants):
            words = title.split()
            changed = False
            out: list[str] = []
            for w in words:
                key = re.sub(r"[^a-z0-9]", "", w.lower())
                repl = contraction_map.get(key)
                if repl:
                    out.append(repl)
                    changed = True
                else:
                    out.append(w)
            if changed:
                contraction_variants.append(' '.join(out))
        for candidate in contraction_variants:
            if candidate and all(candidate.lower() != existing.lower() for existing in title_variants):
                title_variants.append(candidate)
        # Possessive fallback: release names often drop apostrophes ("Sisters" vs "Sister's").
        # Generate conservative single-word possessive probes to avoid over-mutating titles.
        possessive_variants: list[str] = []
        for title in list(title_variants):
            words = title.split()
            for idx, w in enumerate(words):
                if "'" in w:
                    continue
                mpos = re.fullmatch(r'([A-Za-z]{3,})s', w)
                if not mpos:
                    continue
                singular = mpos.group(1)
                if len(singular) < 3:
                    continue
                w2 = f"{singular}'s"
                out = list(words)
                out[idx] = w2
                probe = ' '.join(out).strip()
                if probe:
                    possessive_variants.append(probe)
        for candidate in possessive_variants:
            if candidate and all(candidate.lower() != existing.lower() for existing in title_variants):
                title_variants.append(candidate)
        # Compact cleanup for noisy release tokens that can leak into title query.
        compact_variants: list[str] = []
        # Common language/audio tags that should not be part of OMDb title queries.
        stop_words = {
            'true',
            'hindi', 'hin',
            'tamil', 'tam',
            'telugu', 'tel',
            'malayalam', 'mal',
            'kannada', 'kan',
            'english', 'eng',
            'bengali', 'ben',
            'punjabi', 'pan',
            'marathi', 'mar',
            'gujarati', 'guj',
            'urdu',
            'japanese', 'jpn',
            'korean', 'kor',
            'chinese', 'chi',
            'french', 'fre', 'fra',
            'spanish', 'spa',
            'german', 'ger', 'deu',
            'italian', 'ita',
            'russian', 'rus',
            'arabic', 'ara',
            'dubbed', 'subbed', 'esub',
            'multi', 'multi2', 'multi3',
        }
        for title in list(title_variants):
            words = [w for w in re.split(r'\s+', title) if w]
            kept = []
            for w in words:
                key = re.sub(r'[^a-z0-9]+', '', w.lower())
                if key in stop_words:
                    continue
                kept.append(w)
            compact = re.sub(r'\s+', ' ', ' '.join(kept)).strip()
            if compact:
                compact_variants.append(compact)
        for candidate in compact_variants:
            if candidate and all(candidate.lower() != existing.lower() for existing in title_variants):
                title_variants.append(candidate)
        # Generic base-title fallback: long release names often include franchise subtitles
        # that OMDb does not index in `t=` lookup. Try compact leading-token probes.
        words = [w for w in re.split(r'\s+', tq) if w]
        for n in (4, 3):
            if len(words) >= n + 1:
                probe = ' '.join(words[:n]).strip()
                if probe and all(probe.lower() != existing.lower() for existing in title_variants):
                    title_variants.append(probe)
        last_err = 'OMDb returned no match.'

        def _query(title: str, with_year: bool) -> tuple[bool, dict, str]:
            params = {'apikey': api_key, 't': title, 'plot': 'short'}
            if media_type in ('movie', 'series'):
                params['type'] = media_type
            if with_year and year is not None:
                params['y'] = int(year)
            q = urllib.parse.urlencode(params)
            ok, raw, err = self._metadata_http_get_json(f'{base}/?{q}', timeout)
            if ok and str(raw.get('Response', '')).lower() == 'true':
                return True, raw, ''
            return False, {}, (err or str(raw.get('Error') or 'OMDb returned no match.'))

        if year is not None:
            for title in title_variants:
                ok, raw, err = _query(title, with_year=True)
                if ok:
                    return True, raw, ''
                if err:
                    last_err = err
            for title in title_variants:
                ok, raw, err = _query(title, with_year=False)
                if ok:
                    return True, raw, ''
                if err:
                    last_err = err
            return False, {}, last_err

        for title in title_variants:
            ok, raw, err = _query(title, with_year=False)
            if ok:
                return True, raw, ''
            if err:
                last_err = err
        return False, {}, last_err

    def _stage_pending_metadata_preview(self, proposal_id: int) -> None:
        prow = self.get_metadata_proposal(int(proposal_id))
        if not prow:
            return
        self._activate_metadata_link_from_proposal(prow, int(prow['proposed_by_user_id'] or 0),
                                                   str(prow['proposed_by_username'] or ''))
        self._enqueue_metadata_fetch_job(prow)
        self.process_metadata_fetch_jobs()

    def auto_match_torrent_metadata(self, info_hash: str, actor_user_id: int,
                                    actor_username: str, source: str = 'manual') -> tuple[bool, str, str, int]:
        """Attempt automatic metadata match.

        Returns `(ok, message, level, score)` where level is one of:
        `high`, `medium`, `low`, `skip`, `error`.
        """
        ih = (info_hash or '').strip().upper()
        if not re.fullmatch(r'[A-F0-9]{40}', ih):
            return False, 'Invalid torrent hash.', 'error', 0
        trow = self.get_torrent(ih)
        if not trow:
            return False, 'Torrent not found.', 'error', 0
        cfg = self.get_metadata_config()
        if not cfg.get('enabled', True) or not cfg.get('auto_match_enabled', False):
            return False, 'Auto-match is disabled by settings.', 'skip', 0
        cleanup_tags = _parse_torrent_name_cleanup_tags(
            self.get_setting('torrent_name_cleanup_tags', '')
        )
        strip_www_prefix = self.get_setting('torrent_name_cleanup_strip_www_prefix', '1') == '1'
        strip_extensions = self.get_setting('torrent_name_cleanup_strip_extensions', '1') == '1'
        parsed = _parse_release_for_auto_match(
            str(trow['name'] or ''),
            cleanup_tags=cleanup_tags,
            strip_www_prefix=strip_www_prefix,
            strip_extensions=strip_extensions,
        )
        title_query = str(parsed.get('title_query') or '').strip()
        if not title_query:
            return False, 'Unable to infer title from release name.', 'skip', 0
        high_th = int(cfg.get('auto_match_high_threshold', 90))
        med_th = int(cfg.get('auto_match_medium_threshold', 72))
        if med_th >= high_th:
            med_th = max(50, high_th - 5)

        provider = ''
        ext_id = ''
        proposed_url = ''
        season = None
        episode = None
        score = 0
        explain = ''

        def _try_srrdb_imdb_fallback(reason_msg: str) -> tuple[bool, str, str, int] | None:
            try:
                srow = self.get_torrent_srrdb_cache(ih)
            except Exception:
                srow = None
            srrdb_imdb = ''
            if srow:
                srrdb_imdb = _validate_imdb_id(str(srow['imdb_id'] or ''))
            if not srrdb_imdb or self.has_active_metadata_link(ih, 'imdb'):
                return None
            srrdb_url = f'https://www.imdb.com/title/{srrdb_imdb}/'
            ok_fb, fb_result = self.create_metadata_proposal(
                ih, 'imdb', srrdb_imdb, int(actor_user_id), actor_username,
                proposed_url=srrdb_url
            )
            if ok_fb:
                fb_pid = int(fb_result)
                try:
                    self._stage_pending_metadata_preview(fb_pid)
                except Exception:
                    pass
                self.notify_metadata_proposed(fb_pid, actor_username)
                self._log(actor_username, 'metadata_auto_match_srrdb_fallback', ih,
                          f'proposal_id={fb_pid} imdb={srrdb_imdb} score={score} source={source} reason={reason_msg}')
                return True, (
                    f'{reason_msg}; queued SRRDB IMDb fallback proposal ({srrdb_imdb}); '
                    f'pending metadata card was pre-populated.'
                ), 'medium', int(score)
            self._log(actor_username, 'metadata_auto_match_srrdb_fallback_failed', ih,
                      f'imdb={srrdb_imdb} score={score} source={source} reason={reason_msg} err={fb_result}')
            return False, (
                f'{reason_msg}; SRRDB fallback proposal failed ({str(fb_result)}).'
            ), 'low', int(score)

        if parsed.get('kind') == 'tv' and cfg.get('auto_match_tv', True):
            if self.has_active_metadata_link(ih, 'tvmaze'):
                return False, 'TV metadata is already active for this torrent.', 'skip', 0
            season = parsed.get('season')
            episode = parsed.get('episode')
            sid, show_name, show_url = self._search_tvmaze_show(title_query, cfg)
            if sid:
                ok_tv, tv_payload, tv_err = self._fetch_tvmaze_metadata(
                    sid, season, episode, cfg
                )
                if ok_tv:
                    raw = tv_payload.get('raw') if isinstance(tv_payload, dict) else {}
                    show_title = ''
                    if isinstance(raw, dict):
                        show_title = str(((raw.get('show') or {}).get('name')) or '')
                    title_score = _match_ratio(title_query, show_title or show_name)
                    year_score = 0
                    pyear = parsed.get('year')
                    cyear = tv_payload.get('year')
                    if isinstance(pyear, int) and isinstance(cyear, int):
                        if pyear == cyear:
                            year_score = 10
                        elif abs(pyear - cyear) <= 1:
                            year_score = 6
                    se_score = 12 if (season is not None and episode is not None) else 0
                    score = min(100, title_score + year_score + se_score)
                    provider = 'tvmaze'
                    ext_id = sid
                    proposed_url = show_url
                    explain = f'tv title={title_score} year={year_score} se={se_score}'
                else:
                    explain = tv_err or 'tvmaze fetch failed'

        if not provider and cfg.get('auto_match_movies', True):
            if self.has_active_metadata_link(ih, 'imdb'):
                return False, 'IMDb metadata is already active for this torrent.', 'skip', 0
            omdb_type = 'movie' if parsed.get('kind') != 'tv' else 'series'
            ok_omdb, omdb_raw, omdb_err = self._search_omdb_title(
                title_query, omdb_type, parsed.get('year'), cfg
            )
            if ok_omdb:
                imdb_id = _validate_imdb_id(str(omdb_raw.get('imdbID') or ''))
                if imdb_id:
                    cand_title = str(omdb_raw.get('Title') or '')
                    cand_year = None
                    try:
                        cand_year = int(str(omdb_raw.get('Year') or '')[:4])
                    except Exception:
                        cand_year = None
                    pyear = parsed.get('year')
                    if isinstance(pyear, int) and isinstance(cand_year, int) and abs(pyear - cand_year) > 1:
                        explain = f'imdb year mismatch query={pyear} candidate={cand_year}'
                    else:
                        cand_type = str(omdb_raw.get('Type') or '').lower()
                        title_score = _match_ratio(title_query, cand_title)
                        year_score = 0
                        if isinstance(pyear, int) and isinstance(cand_year, int):
                            if pyear == cand_year:
                                year_score = 10
                            elif abs(pyear - cand_year) <= 1:
                                year_score = 6
                        type_score = 6 if ((parsed.get('kind') == 'movie' and cand_type == 'movie') or
                                           (parsed.get('kind') == 'tv' and cand_type in ('series', 'episode'))) else 0
                        score = min(100, title_score + year_score + type_score)
                        provider = 'imdb'
                        ext_id = imdb_id
                        proposed_url = f'https://www.imdb.com/title/{imdb_id}/'
                        explain = f'imdb title={title_score} year={year_score} type={type_score}'
                else:
                    explain = 'omdb response missing imdb id'
            else:
                explain = omdb_err or 'omdb search failed'

        if not provider or not ext_id:
            reason = f'No metadata match found ({explain})'
            fb = _try_srrdb_imdb_fallback(reason)
            if fb is not None:
                return fb
            return False, f'{reason}.', 'low', 0

        level = 'high' if score >= high_th else ('medium' if score >= med_th else 'low')
        if level == 'low':
            self._log(actor_username, 'metadata_auto_match_low', ih,
                      f'provider={provider} id={ext_id} score={score} source={source} {explain}')
            fb = _try_srrdb_imdb_fallback(f'Auto-match score too low ({score})')
            if fb is not None:
                return fb
            return False, f'Auto-match score too low ({score}); no proposal created.', 'low', int(score)

        ok_prop, result = self.create_metadata_proposal(
            ih, provider, ext_id, int(actor_user_id), actor_username,
            proposed_url=proposed_url, season=season, episode=episode
        )
        if not ok_prop:
            return False, str(result), 'error', int(score)
        proposal_id = int(result)

        if level == 'high':
            ok_res, msg_res = self.resolve_metadata_proposal(
                proposal_id, int(actor_user_id), actor_username,
                'approve', f'auto-match high confidence ({score}) [{source}]'
            )
            if ok_res:
                self.notify_metadata_decision(proposal_id, 'approved', actor_username)
                try:
                    self.process_metadata_fetch_jobs()
                except Exception:
                    pass
                self._log(actor_username, 'metadata_auto_match_approved', ih,
                          f'provider={provider} id={ext_id} score={score} source={source} {explain}')
                return True, f'Auto-matched and approved ({provider.upper()} score {score}).', level, int(score)
            return False, msg_res, 'error', int(score)
        if level == 'medium':
            try:
                self._stage_pending_metadata_preview(proposal_id)
            except Exception:
                pass
            self.notify_metadata_proposed(proposal_id, actor_username)
            self._log(actor_username, 'metadata_auto_match_pending', ih,
                      f'provider={provider} id={ext_id} score={score} source={source} {explain}')
            return True, f'Auto-match queued for community review ({provider.upper()} score {score}).', level, int(score)
        return False, 'Auto-match could not classify confidence.', 'error', int(score)

    def _maybe_issue_metadata_rewards(self, proposal) -> None:
        if not proposal:
            return
        if (proposal['status'] or '') != 'approved':
            return
        if proposal['rewards_issued_at']:
            return
        cfg = self.get_metadata_config()
        proposer_reward = float(cfg.get('reward_proposer', 1.0))
        voter_reward = float(cfg.get('reward_voter', 0.25))
        proposal_id = int(proposal['id'])
        proposer_uid = int(proposal['proposed_by_user_id'] or 0)
        proposer_username = str(proposal['proposed_by_username'] or '')
        decider_uid = int(proposal['decided_by_user_id'] or 0)
        decider_name = str(proposal['decided_by_username'] or '')

        # Locked decisions from design: no proposer reward on self-approval; no voter reward on editor/admin override.
        grant_voters = (decider_name == 'system')
        grant_proposer = bool(proposer_uid > 0 and proposer_reward > 0 and proposer_uid != decider_uid)
        now = self._ts()
        c = self._conn()
        if grant_proposer:
            cur = c.execute(
                '''INSERT OR IGNORE INTO torrent_metadata_rewards
                   (proposal_id, user_id, username, reward_kind, reward_points, created_at)
                   VALUES (?,?,?,?,?,?)''',
                (proposal_id, proposer_uid, proposer_username[:64], 'proposer', proposer_reward, now)
            )
            if cur.rowcount and cur.rowcount > 0:
                micro_delta = int(round(float(proposer_reward) * 1000.0))
                if micro_delta > 0:
                    self._award_micro_points_tx(
                        c, proposer_uid, micro_delta,
                        f'metadata proposer micro reward (proposal #{proposal_id})',
                        'metadata_reward', str(proposal_id),
                        conversion_reason=f'metadata micro reward conversion (proposal #{proposal_id})'
                    )
        if grant_voters and voter_reward > 0:
            rows = c.execute(
                '''SELECT voter_user_id, voter_username
                   FROM torrent_metadata_proposal_votes
                   WHERE proposal_id=? AND vote=1
                   ORDER BY id ASC''',
                (proposal_id,)
            ).fetchall()
            today = _today_iso()
            for r in rows:
                uid = int(r['voter_user_id'] or 0)
                if uid <= 0:
                    continue
                usage = c.execute(
                    '''SELECT COALESCE(SUM(reward_points),0) AS pts,
                              COALESCE(SUM(CASE WHEN reward_kind='voter' THEN 1 ELSE 0 END),0) AS votes
                       FROM torrent_metadata_rewards
                       WHERE user_id=? AND substr(created_at,1,10)=?''',
                    (uid, today)
                ).fetchone()
                used_pts = float(usage['pts'] or 0.0)
                used_votes = int(usage['votes'] or 0)
                if used_pts + voter_reward > float(cfg.get('reward_daily_cap_points', 5.0)):
                    continue
                if used_votes >= int(cfg.get('reward_max_votes_per_day', 20)):
                    continue
                cur = c.execute(
                    '''INSERT OR IGNORE INTO torrent_metadata_rewards
                       (proposal_id, user_id, username, reward_kind, reward_points, created_at)
                       VALUES (?,?,?,?,?,?)''',
                    (proposal_id, uid, str(r['voter_username'] or '')[:64], 'voter', voter_reward, now)
                )
                if cur.rowcount and cur.rowcount > 0:
                    micro_delta = int(round(float(voter_reward) * 1000.0))
                    if micro_delta > 0:
                        self._award_micro_points_tx(
                            c, uid, micro_delta,
                            f'metadata voter micro reward (proposal #{proposal_id})',
                            'metadata_reward', str(proposal_id),
                            conversion_reason=f'metadata micro reward conversion (proposal #{proposal_id})'
                        )
        c.execute(
            'UPDATE torrent_metadata_proposals SET rewards_issued_at=?, updated_at=? WHERE id=? AND rewards_issued_at IS NULL',
            (now, now, proposal_id)
        )
        c.commit()

    def process_metadata_fetch_jobs(self) -> tuple[int, int]:
        cfg = self.get_metadata_config()
        if not cfg.get('enabled', True) or not cfg.get('fetch_enabled', True):
            return 0, 0
        now_iso = datetime.datetime.now().isoformat()
        c = self._conn()
        rows = c.execute(
            '''SELECT * FROM torrent_metadata_fetch_jobs
               WHERE status IN ('queued','retry')
                 AND (next_attempt_at IS NULL OR next_attempt_at <= ?)
               ORDER BY id ASC
               LIMIT ?''',
            (now_iso, int(cfg.get('fetch_per_cycle', 2)))
        ).fetchall()
        ok_count = 0
        err_count = 0
        for job in rows:
            jid = int(job['id'])
            attempt = int(job['attempt_count'] or 0) + 1
            c.execute(
                '''UPDATE torrent_metadata_fetch_jobs
                   SET status='processing', attempt_count=?, updated_at=?
                   WHERE id=?''',
                (attempt, self._ts(), jid)
            )
            c.commit()
            provider = str(job['provider'] or '')
            external_id = str(job['external_id'] or '')
            season = int(job['season']) if job['season'] is not None else None
            episode = int(job['episode']) if job['episode'] is not None else None
            ok = False
            payload = {}
            err = ''
            if provider == 'imdb':
                ok, payload, err = self._fetch_omdb_metadata(external_id, cfg)
            elif provider == 'tvmaze':
                ok, payload, err = self._fetch_tvmaze_metadata(external_id, season, episode, cfg)
            elif provider == 'steam':
                ok, payload, err = self._fetch_steam_metadata(external_id, cfg)
            else:
                err = 'Unsupported metadata provider.'
            if ok:
                poster_candidate = str(payload.get('poster_url') or '').strip()
                if poster_candidate and not self._metadata_http_url_exists(
                    poster_candidate, int(cfg.get('fetch_timeout_sec', 5))
                ):
                    payload['poster_url'] = ''
                episode_external_id = str(payload.get('episode_external_id') or '')
                self._upsert_metadata_cache(provider, external_id, payload, episode_external_id=episode_external_id)
                c.execute(
                    '''UPDATE torrent_metadata_links
                       SET canonical_url=?, episode_url=?, episode_external_id=?
                       WHERE source_proposal_id=? AND status='active' ''',
                    (str(payload.get('canonical_url') or '')[:1000],
                     str(payload.get('episode_url') or '')[:1000],
                     episode_external_id[:64],
                     int(job['proposal_id']))
                )
                try:
                    prow = self.get_metadata_proposal(int(job['proposal_id']))
                    if prow:
                        self.classify_torrent(str(prow['info_hash'] or ''))
                except Exception as e:
                    log.debug('classify after metadata fetch deferred (non-fatal): proposal=%s err=%s',
                              int(job['proposal_id']), e)
                c.execute(
                    '''UPDATE torrent_metadata_fetch_jobs
                       SET status='done', last_error='', next_attempt_at=NULL, updated_at=?
                       WHERE id=?''',
                    (self._ts(), jid)
                )
                p = self.get_metadata_proposal(int(job['proposal_id']))
                self._maybe_issue_metadata_rewards(p)
                c.commit()
                ok_count += 1
                continue
            max_tries = int(cfg.get('fetch_max_retries', 3))
            if attempt >= max_tries:
                c.execute(
                    '''UPDATE torrent_metadata_fetch_jobs
                       SET status='failed', last_error=?, next_attempt_at=NULL, updated_at=?
                       WHERE id=?''',
                    (str(err or 'fetch failed')[:500], self._ts(), jid)
                )
            else:
                delay = min(300, 10 * attempt)
                next_try = (datetime.datetime.now() + datetime.timedelta(seconds=delay)).isoformat()
                c.execute(
                    '''UPDATE torrent_metadata_fetch_jobs
                       SET status='retry', last_error=?, next_attempt_at=?, updated_at=?
                       WHERE id=?''',
                    (str(err or 'fetch failed')[:500], next_try, self._ts(), jid)
                )
            c.commit()
            err_count += 1
        return ok_count, err_count

    def get_metadata_curators(self, top_n: int = 10) -> list:
        return [dict(r) for r in self._conn().execute(
            '''SELECT username, ROUND(COALESCE(SUM(reward_points),0), 2) AS metadata_score
               FROM torrent_metadata_rewards
               GROUP BY username
               ORDER BY metadata_score DESC, username ASC
               LIMIT ?''',
            (max(1, int(top_n)),)
        ).fetchall()]

    def list_active_metadata_links(self, info_hash: str) -> list:
        ih = (info_hash or '').strip().upper()
        if not ih:
            return []
        return self._conn().execute(
            '''SELECT * FROM torrent_metadata_links
               WHERE info_hash=? AND status='active'
               ORDER BY id DESC''',
            (ih,)
        ).fetchall()

    def has_active_metadata_link(self, info_hash: str, provider: str) -> bool:
        ih = (info_hash or '').strip().upper()
        p = _normalize_metadata_provider(provider)
        if not ih or not p:
            return False
        row = self._conn().execute(
            '''SELECT 1 FROM torrent_metadata_links
               WHERE info_hash=? AND provider=? AND status='active'
               LIMIT 1''',
            (ih, p)
        ).fetchone()
        return row is not None

    def get_metadata_refresh_remaining_seconds(self, info_hash: str,
                                               is_privileged: bool = False) -> int:
        if is_privileged:
            return 0
        ih = (info_hash or '').strip().upper()
        if not ih:
            return 0
        row = self._conn().execute(
            '''SELECT MAX(last_requested_at) AS last_requested_at
               FROM torrent_metadata_refresh_requests
               WHERE info_hash=?''',
            (ih,)
        ).fetchone()
        if not row:
            return 0
        try:
            last_dt = datetime.datetime.fromisoformat(str(row['last_requested_at'] or ''))
        except Exception:
            return 0
        elapsed = (datetime.datetime.now() - last_dt).total_seconds()
        return max(0, int(METADATA_REFRESH_COOLDOWN_SECONDS - elapsed))

    def request_torrent_metadata_refresh(self, info_hash: str, actor_user_id: int,
                                         actor_username: str, is_privileged: bool = False) -> tuple[bool, str, int]:
        ih = (info_hash or '').strip().upper()
        uid = int(actor_user_id or 0)
        if not re.fullmatch(r'[A-F0-9]{40}', ih):
            return False, 'Invalid torrent hash.', 0
        if uid <= 0:
            return False, 'Invalid actor.', 0
        t = self.get_torrent(ih)
        if not t:
            return False, 'Torrent not found.', 0
        links = self.list_active_metadata_links(ih)
        if not links:
            return False, 'No active metadata is linked to this torrent.', 0
        c = self._conn()
        now = self._ts()
        for attempt in range(8):
            try:
                c.execute('BEGIN IMMEDIATE')
                if not is_privileged:
                    row = c.execute(
                        '''SELECT MAX(last_requested_at) AS last_requested_at
                           FROM torrent_metadata_refresh_requests
                           WHERE info_hash=?''',
                        (ih,)
                    ).fetchone()
                    if row:
                        try:
                            last_dt = datetime.datetime.fromisoformat(str(row['last_requested_at'] or ''))
                            rem = max(0, int(METADATA_REFRESH_COOLDOWN_SECONDS - (datetime.datetime.now() - last_dt).total_seconds()))
                        except Exception:
                            rem = 0
                        if rem > 0:
                            c.execute('ROLLBACK')
                            h = rem // 3600
                            m = (rem % 3600) // 60
                            return False, f'Metadata can be refreshed again in {h}h {m}m.', 0
                c.execute(
                    '''INSERT INTO torrent_metadata_refresh_requests (
                           info_hash, requested_by_user_id, requested_by_username, last_requested_at
                       ) VALUES (?,?,?,?)
                       ON CONFLICT(info_hash, requested_by_user_id)
                       DO UPDATE SET requested_by_username=excluded.requested_by_username,
                                     last_requested_at=excluded.last_requested_at''',
                    (ih, uid, (actor_username or '')[:64], now)
                )
                queued = 0
                already_queued = 0
                for link in links:
                    provider = str(link['provider'] or '')
                    external_id = str(link['external_id'] or '')
                    proposal_id = int(link['source_proposal_id'] or 0)
                    season = None
                    episode = None
                    if proposal_id > 0:
                        prow = c.execute(
                            'SELECT season, episode FROM torrent_metadata_proposals WHERE id=?',
                            (proposal_id,)
                        ).fetchone()
                    else:
                        prow = c.execute(
                            '''SELECT id, season, episode
                               FROM torrent_metadata_proposals
                               WHERE info_hash=? AND provider=? AND proposed_id=?
                               ORDER BY id DESC
                               LIMIT 1''',
                            (ih, provider, external_id)
                        ).fetchone()
                        if prow:
                            proposal_id = int(prow['id'] or 0)
                    if proposal_id <= 0:
                        continue
                    if prow:
                        season = prow['season'] if 'season' in prow.keys() else None
                        episode = prow['episode'] if 'episode' in prow.keys() else None
                    existing = c.execute(
                        '''SELECT 1 FROM torrent_metadata_fetch_jobs
                           WHERE proposal_id=? AND provider=? AND external_id=?
                             AND COALESCE(season,-1)=COALESCE(?, -1)
                             AND COALESCE(episode,-1)=COALESCE(?, -1)
                             AND status IN ('queued','retry','processing')
                           LIMIT 1''',
                        (proposal_id, provider, external_id, season, episode)
                    ).fetchone()
                    if existing:
                        already_queued += 1
                        continue
                    c.execute(
                        '''INSERT INTO torrent_metadata_fetch_jobs (
                               proposal_id, provider, external_id, season, episode, status,
                               attempt_count, last_error, next_attempt_at, created_at, updated_at
                           ) VALUES (?,?,?,?,?,'queued',0,'',NULL,?,?)''',
                        (proposal_id, provider, external_id, season, episode, now, now)
                    )
                    queued += 1
                c.execute('COMMIT')
                self._log(actor_username, 'metadata_refresh_manual', ih,
                          f'queued={queued} already_queued={already_queued} privileged={1 if is_privileged else 0}')
                if queued > 0:
                    return True, f'Metadata refresh queued for {queued} provider(s).', queued
                if already_queued > 0:
                    return True, 'Metadata refresh already queued.', 0
                return False, 'No metadata refresh jobs could be queued.', 0
            except sqlite3.OperationalError as e:
                try:
                    c.execute('ROLLBACK')
                except Exception:
                    pass
                if 'locked' in str(e).lower() and attempt < 7:
                    time.sleep(0.08 * (attempt + 1))
                    continue
                if 'locked' in str(e).lower():
                    log.warning('request_torrent_metadata_refresh lock after retries (non-fatal): ih=%s user=%s err=%s',
                                ih, actor_username, e)
                    return False, 'Database is busy, please retry metadata refresh.', 0
                raise
        return False, 'Database is busy, please retry metadata refresh.', 0

    def _enqueue_metadata_fetch_job(self, proposal) -> None:
        if not proposal:
            return
        self._conn().execute(
            '''INSERT INTO torrent_metadata_fetch_jobs (
                   proposal_id, provider, external_id, season, episode, status,
                   attempt_count, last_error, next_attempt_at, created_at, updated_at
               ) VALUES (?,?,?,?,?,'queued',0,'',NULL,?,?)''',
            (int(proposal['id']), proposal['provider'], proposal['proposed_id'],
             proposal['season'], proposal['episode'], self._ts(), self._ts())
        )
        self._conn().commit()

    def _activate_metadata_link_from_proposal(self, proposal, actor_user_id: int,
                                              actor_username: str) -> None:
        if not proposal:
            return
        ih = str(proposal['info_hash'] or '').upper()
        provider = str(proposal['provider'] or '')
        creator_uid = int(actor_user_id) if int(actor_user_id or 0) > 0 else int(proposal['proposed_by_user_id'] or 0)
        creator_un = (actor_username[:64] if int(actor_user_id or 0) > 0 else str(proposal['proposed_by_username'] or '')[:64])
        c = self._conn()
        # Revoke any existing active link for this provider on this torrent.
        c.execute(
            '''UPDATE torrent_metadata_links
               SET status='revoked', revoked_by_user_id=?, revoked_by_username=?,
                   revoked_reason='superseded by approved proposal', revoked_at=?
               WHERE info_hash=? AND provider=? AND status='active' ''',
            (int(actor_user_id), actor_username[:64], self._ts(), ih, provider)
        )
        c.execute(
            '''INSERT INTO torrent_metadata_links (
                   info_hash, provider, external_id, canonical_url,
                   episode_external_id, episode_url, source_proposal_id, status,
                   created_by_user_id, created_by_username, created_at
               ) VALUES (?,?,?,?,?,?,?,'active',?,?,?)''',
            (ih, provider, str(proposal['proposed_id'] or ''),
             str(proposal['proposed_url'] or ''), None, None, int(proposal['id']),
             creator_uid, creator_un, self._ts())
        )
        c.commit()
        try:
            self.classify_torrent(ih)
        except Exception as e:
            log.debug('classify after metadata activate deferred (non-fatal): ih=%s err=%s', ih, e)

    def resolve_metadata_proposal(self, proposal_id: int, actor_user_id: int,
                                  actor_username: str, decision: str,
                                  reason: str = '') -> tuple[bool, str]:
        p = self.get_metadata_proposal(int(proposal_id))
        if not p:
            return False, 'Proposal not found.'
        if (p['status'] or '') != 'pending':
            return False, 'Proposal is no longer pending.'
        d = (decision or '').strip().lower()
        if d not in ('approve', 'reject', 'expire'):
            return False, 'Invalid decision.'
        target_status = {'approve': 'approved', 'reject': 'rejected', 'expire': 'expired'}[d]
        now = self._ts()
        self._conn().execute(
            '''UPDATE torrent_metadata_proposals
               SET status=?, decision_reason=?, decided_by_user_id=?, decided_by_username=?,
                   decided_at=?, updated_at=?
               WHERE id=? AND status='pending' ''',
            (target_status, (reason or '')[:500], int(actor_user_id), actor_username[:64],
             now, now, int(proposal_id))
        )
        self._conn().commit()
        if d == 'approve':
            p = self.get_metadata_proposal(int(proposal_id))
            self._activate_metadata_link_from_proposal(p, actor_user_id, actor_username)
            self._enqueue_metadata_fetch_job(p)
            # Reward issuance is tied to acceptance/approval event.
            self._maybe_issue_metadata_rewards(p)
        else:
            # Pending previews are rendered as active metadata cards; rejecting/expiring
            # the proposal should revoke its linked preview card.
            self._conn().execute(
                '''UPDATE torrent_metadata_links
                   SET status='revoked', revoked_by_user_id=?, revoked_by_username=?,
                       revoked_reason=?, revoked_at=?
                   WHERE source_proposal_id=? AND status='active' ''',
                (int(actor_user_id), actor_username[:64], f'proposal {target_status}', self._ts(), int(proposal_id))
            )
            self._conn().commit()
        self._log(actor_username, f'metadata_{target_status}',
                  str(p['info_hash'] or ''), f'proposal_id={proposal_id} provider={p["provider"]} id={p["proposed_id"]}')
        return True, f'Proposal {target_status}.'

    def revoke_active_metadata_link(self, info_hash: str, provider: str, actor_user_id: int,
                                    actor_username: str, reason: str = '') -> tuple[bool, str]:
        cfg = self.get_metadata_config()
        p = _normalize_metadata_provider(provider)
        ih = (info_hash or '').strip().upper()
        if not ih or not p:
            return False, 'Invalid metadata target.'
        if cfg.get('revoke_requires_reason', True) and not (reason or '').strip():
            return False, 'Reason is required to revoke metadata.'
        cur = self._conn().execute(
            '''UPDATE torrent_metadata_links
               SET status='revoked', revoked_by_user_id=?, revoked_by_username=?,
                   revoked_reason=?, revoked_at=?
               WHERE info_hash=? AND provider=? AND status='active' ''',
            (int(actor_user_id), actor_username[:64], (reason or '')[:500], self._ts(), ih, p)
        )
        self._conn().commit()
        if cur.rowcount < 1:
            return False, 'No active metadata link to revoke.'
        try:
            self.classify_torrent(ih)
        except Exception as e:
            log.debug('classify after metadata revoke deferred (non-fatal): ih=%s err=%s', ih, e)
        self._log(actor_username, 'metadata_revoked', ih, f'provider={p} reason={(reason or "")[:120]}')
        return True, 'Metadata revoked.'

    def auto_finalize_metadata_proposals(self) -> tuple[int, int]:
        cfg = self.get_metadata_config()
        if not cfg.get('enabled', True) or not cfg.get('auto_finalize_enabled', True):
            return 0, 0
        now_iso = datetime.datetime.now().isoformat()
        rows = self._conn().execute(
            '''SELECT id FROM torrent_metadata_proposals
               WHERE status='pending' AND auto_finalize_at <= ?
               ORDER BY id ASC LIMIT 200''',
            (now_iso,)
        ).fetchall()
        approved = 0
        rejected = 0
        for r in rows:
            pid = int(r['id'])
            summary = self.get_metadata_proposal_vote_summary(pid)
            unique_voters = int(summary.get('unique_voters', 0))
            net = int(summary.get('net', 0))
            if unique_voters == 0:
                ok, _ = self.resolve_metadata_proposal(pid, 0, 'system', 'approve', 'auto-accepted with no community votes')
                if ok:
                    self.notify_metadata_decision(pid, 'approved', 'system')
                    approved += 1
            elif net >= 1:
                ok, _ = self.resolve_metadata_proposal(pid, 0, 'system', 'approve', 'auto-approved by community vote')
                if ok:
                    self.notify_metadata_decision(pid, 'approved', 'system')
                    approved += 1
            else:
                ok, _ = self.resolve_metadata_proposal(pid, 0, 'system', 'reject', 'auto-rejected by community vote')
                if ok:
                    self.notify_metadata_decision(pid, 'rejected', 'system')
                    rejected += 1
        if approved or rejected:
            self._log('system', 'metadata_auto_finalize', '', f'approved={approved} rejected={rejected}')
        return approved, rejected

    # ── Torrent Reports ───────────────────────────────────────

    def _report_moderator_rows(self) -> list:
        return self._conn().execute(
            '''SELECT id, username FROM users
               WHERE is_disabled=0 AND (username=? OR is_admin=1 OR is_editor=1)
               ORDER BY CASE
                 WHEN username=? THEN 0
                 WHEN is_admin=1 THEN 1
                 WHEN is_editor=1 THEN 2
                 ELSE 3 END,
               username ASC''',
            (SUPER_USER, SUPER_USER)
        ).fetchall()

    def _report_editor_rows(self) -> list:
        return self._conn().execute(
            '''SELECT id, username FROM users
               WHERE is_disabled=0 AND is_editor=1
               ORDER BY username ASC'''
        ).fetchall()

    def _report_moderator_user_ids(self) -> list[int]:
        return [int(r['id']) for r in self._report_moderator_rows()]

    def _report_editor_user_ids(self) -> list[int]:
        return [int(r['id']) for r in self._report_editor_rows()]

    def list_report_moderators(self) -> list:
        return [dict(r) for r in self._report_moderator_rows()]

    def list_report_editors(self) -> list:
        return [dict(r) for r in self._report_editor_rows()]

    def create_torrent_report(self, info_hash: str, reporter_user_id: int,
                              reporter_username: str, reason: str,
                              notes: str = '') -> tuple[bool, str, int]:
        ih = (info_hash or '').strip().upper()
        uid = int(reporter_user_id or 0)
        normalized_reason = _normalize_report_reason(reason)
        if not ih or not re.fullmatch(r'[A-F0-9]{40}', ih):
            return False, 'Invalid info hash.', 0
        if uid <= 0:
            return False, 'Invalid reporter.', 0
        if not normalized_reason:
            return False, 'Invalid report reason.', 0
        clean_notes = (notes or '').strip()[:1000]
        if normalized_reason == 'other' and not clean_notes:
            return False, 'Reason details are required when selecting Other.', 0
        severity = _report_reason_severity(normalized_reason)
        now_dt = datetime.datetime.now()
        now_ts = self._ts()
        cooldown_cutoff = (now_dt - datetime.timedelta(seconds=REPORT_SUBMISSION_COOLDOWN_SECONDS)).isoformat()
        c = self._conn()
        for attempt in range(8):
            try:
                c.execute('BEGIN IMMEDIATE')
                t = c.execute(
                    'SELECT info_hash,name FROM torrents WHERE info_hash=?',
                    (ih,)
                ).fetchone()
                if not t:
                    c.execute('ROLLBACK')
                    return False, 'Torrent not found.', 0
                existing = c.execute(
                    '''SELECT id FROM torrent_reports
                       WHERE info_hash=? AND reporter_user_id=? AND reason=?
                         AND status IN ('open','in_review')
                       ORDER BY id DESC LIMIT 1''',
                    (ih, uid, normalized_reason)
                ).fetchone()
                if existing:
                    c.execute('ROLLBACK')
                    return False, 'You already have an open report for this reason on this torrent.', 0
                recent = c.execute(
                    '''SELECT id FROM torrent_reports
                       WHERE info_hash=? AND reporter_user_id=? AND created_at>=?
                       ORDER BY id DESC LIMIT 1''',
                    (ih, uid, cooldown_cutoff)
                ).fetchone()
                if recent:
                    c.execute('ROLLBACK')
                    return False, 'Report cooldown active. Please wait before submitting again.', 0
                c.execute(
                    '''INSERT INTO torrent_reports (
                           info_hash, reporter_user_id, reason, notes, severity,
                           status, assigned_user_id, created_at, updated_at, resolved_at
                       ) VALUES (?,?,?,?,?,'open',NULL,?,?,NULL)''',
                    (ih, uid, normalized_reason, clean_notes, severity, now_ts, now_ts)
                )
                report_id = int(c.execute('SELECT last_insert_rowid()').fetchone()[0])
                c.execute(
                    '''INSERT INTO torrent_report_actions (
                           report_id, actor_user_id, actor_username, action,
                           from_status, to_status, note, created_at
                       ) VALUES (?,?,?,?,?,?,?,?)''',
                    (report_id, uid, reporter_username[:64], 'created', '', 'open', clean_notes, now_ts)
                )
                c.execute(
                    'INSERT INTO events (timestamp,actor,action,target,detail) VALUES (?,?,?,?,?)',
                    (now_ts, reporter_username[:64], 'report_create', ih,
                     f'report_id={report_id} reason={normalized_reason} severity={severity}')
                )
                c.execute('COMMIT')
                return True, 'Report submitted.', report_id
            except sqlite3.OperationalError as e:
                try:
                    c.execute('ROLLBACK')
                except Exception:
                    pass
                if 'locked' in str(e).lower() and attempt < 7:
                    time.sleep(0.08 * (attempt + 1))
                    continue
                if 'locked' in str(e).lower():
                    log.warning('create_torrent_report lock after retries (non-fatal): ih=%s uid=%s err=%s',
                                ih, uid, e)
                    return False, 'Database is busy, please retry report submission.', 0
                raise
        return False, 'Database is busy, please retry report submission.', 0

    def list_torrent_reports(self, limit: int = 50, offset: int = 0,
                             q_status: str = '', q_severity: str = '', q_reason: str = '',
                             q_reporter: str = '', q_info_hash: str = '', q_owner: str = '') -> tuple[list, int]:
        clauses = []
        params: list[Any] = []
        status = _normalize_report_status(q_status)
        if status:
            clauses.append('r.status=?')
            params.append(status)
        sev = (q_severity or '').strip().lower()
        if sev in ('normal', 'high'):
            clauses.append('r.severity=?')
            params.append(sev)
        reason = _normalize_report_reason(q_reason)
        if reason:
            clauses.append('r.reason=?')
            params.append(reason)
        if q_reporter:
            clauses.append('ru.username LIKE ?')
            params.append(f'%{q_reporter.strip()}%')
        if q_info_hash:
            clauses.append('r.info_hash LIKE ?')
            params.append(f'%{q_info_hash.strip().upper()}%')
        if q_owner:
            clauses.append('t.uploaded_by_username LIKE ?')
            params.append(f'%{q_owner.strip()}%')
        where = ('WHERE ' + ' AND '.join(clauses)) if clauses else ''
        sql = (
            'SELECT r.*, '
            ' ru.username AS reporter_username, '
            ' au.username AS assigned_username, '
            ' t.name AS torrent_name, '
            ' t.uploaded_by_username AS owner_username '
            'FROM torrent_reports r '
            'LEFT JOIN users ru ON ru.id=r.reporter_user_id '
            'LEFT JOIN users au ON au.id=r.assigned_user_id '
            'LEFT JOIN torrents t ON t.info_hash=r.info_hash '
            f"{where} ORDER BY CASE "
            "WHEN r.severity='high' AND r.status IN ('open','in_review') THEN 0 "
            "WHEN r.status IN ('open','in_review') THEN 1 "
            "ELSE 2 END, r.id DESC LIMIT ? OFFSET ?"
        )
        rows = self._conn().execute(sql, params + [int(limit), int(offset)]).fetchall()
        total = self._conn().execute(
            'SELECT COUNT(*) FROM torrent_reports r '
            'LEFT JOIN users ru ON ru.id=r.reporter_user_id '
            'LEFT JOIN torrents t ON t.info_hash=r.info_hash '
            f'{where}',
            params
        ).fetchone()[0]
        return [dict(r) for r in rows], int(total)

    def get_torrent_report(self, report_id: int):
        row = self._conn().execute(
            '''SELECT r.*,
                      ru.username AS reporter_username,
                      au.username AS assigned_username,
                      t.name AS torrent_name,
                      t.ingestion_source AS torrent_ingestion_source,
                      t.uploaded_by_id AS owner_user_id,
                      t.uploaded_by_username AS owner_username
               FROM torrent_reports r
               LEFT JOIN users ru ON ru.id=r.reporter_user_id
               LEFT JOIN users au ON au.id=r.assigned_user_id
               LEFT JOIN torrents t ON t.info_hash=r.info_hash
               WHERE r.id=?''',
            (int(report_id),)
        ).fetchone()
        return dict(row) if row else None

    def list_torrent_report_actions(self, report_id: int, limit: int = 200) -> list:
        rows = self._conn().execute(
            '''SELECT a.*, u.username AS actor_username_current
               FROM torrent_report_actions a
               LEFT JOIN users u ON u.id=a.actor_user_id
               WHERE a.report_id=?
               ORDER BY a.id DESC LIMIT ?''',
            (int(report_id), int(limit))
        ).fetchall()
        return [dict(r) for r in rows]

    def apply_torrent_report_action(self, report_id: int, actor_user_id: int,
                                    actor_username: str, action: str,
                                    note: str = '', assign_user_id: int = 0) -> tuple[bool, str]:
        rid = int(report_id or 0)
        uid = int(actor_user_id or 0)
        act = (action or '').strip().lower()
        clean_note = (note or '').strip()[:500]
        if rid <= 0 or uid <= 0:
            return False, 'Invalid report action.'
        if act not in ('open', 'in_review', 'resolved', 'dismissed', 'assign', 'unassign', 'note'):
            return False, 'Invalid report action.'
        now = self._ts()
        c = self._conn()
        for attempt in range(8):
            try:
                c.execute('BEGIN IMMEDIATE')
                row = c.execute(
                    'SELECT * FROM torrent_reports WHERE id=?',
                    (rid,)
                ).fetchone()
                if not row:
                    c.execute('ROLLBACK')
                    return False, 'Report not found.'
                old_status = str(row['status'] or 'open')
                changed = False
                event_action = ''
                event_detail = ''
                if act in ('open', 'in_review', 'resolved', 'dismissed'):
                    if old_status != act:
                        resolved_at = now if act in ('resolved', 'dismissed') else None
                        c.execute(
                            'UPDATE torrent_reports SET status=?,updated_at=?,resolved_at=? WHERE id=?',
                            (act, now, resolved_at, rid)
                        )
                        c.execute(
                            '''INSERT INTO torrent_report_actions (
                                   report_id, actor_user_id, actor_username, action,
                                   from_status, to_status, note, created_at
                               ) VALUES (?,?,?,?,?,?,?,?)''',
                            (rid, uid, actor_username[:64], 'status_change', old_status, act, clean_note, now)
                        )
                        event_action = 'report_status_change'
                        event_detail = f'report_id={rid} from={old_status} to={act}'
                        if clean_note:
                            event_detail += f' note={clean_note[:120]}'
                        changed = True
                elif act in ('assign', 'unassign'):
                    to_uid = int(assign_user_id or 0) if act == 'assign' else 0
                    if to_uid > 0:
                        valid_mod = c.execute(
                            'SELECT 1 FROM users WHERE id=? AND is_disabled=0 AND (username=? OR is_admin=1 OR is_editor=1)',
                            (to_uid, SUPER_USER)
                        ).fetchone()
                        if not valid_mod:
                            c.execute('ROLLBACK')
                            return False, 'Selected assignee is not an active moderator.'
                    c.execute(
                        'UPDATE torrent_reports SET assigned_user_id=?,updated_at=? WHERE id=?',
                        (to_uid if to_uid > 0 else None, now, rid)
                    )
                    c.execute(
                        '''INSERT INTO torrent_report_actions (
                               report_id, actor_user_id, actor_username, action,
                               from_status, to_status, note, created_at
                           ) VALUES (?,?,?,?,?,?,?,?)''',
                        (rid, uid, actor_username[:64], 'assign', '', '', f'assigned_user_id={to_uid}', now)
                    )
                    event_action = 'report_assign'
                    event_detail = f'report_id={rid} assigned_user_id={to_uid}'
                    changed = True
                elif act == 'note':
                    if not clean_note:
                        c.execute('ROLLBACK')
                        return False, 'Note is required.'
                    c.execute(
                        'UPDATE torrent_reports SET updated_at=? WHERE id=?',
                        (now, rid)
                    )
                    c.execute(
                        '''INSERT INTO torrent_report_actions (
                               report_id, actor_user_id, actor_username, action,
                               from_status, to_status, note, created_at
                           ) VALUES (?,?,?,?,?,?,?,?)''',
                        (rid, uid, actor_username[:64], 'note', '', '', clean_note, now)
                    )
                    event_action = 'report_note'
                    event_detail = f'report_id={rid} note={clean_note[:120]}'
                    changed = True
                if changed:
                    c.execute(
                        'INSERT INTO events (timestamp,actor,action,target,detail) VALUES (?,?,?,?,?)',
                        (now, actor_username[:64], event_action, str(row['info_hash'] or ''), event_detail)
                    )
                c.execute('COMMIT')
                return True, 'Report updated.' if changed else 'No changes applied.'
            except sqlite3.OperationalError as e:
                try:
                    c.execute('ROLLBACK')
                except Exception:
                    pass
                if 'locked' in str(e).lower() and attempt < 7:
                    time.sleep(0.08 * (attempt + 1))
                    continue
                if 'locked' in str(e).lower():
                    log.warning('apply_torrent_report_action lock after retries (non-fatal): report_id=%s actor=%s err=%s',
                                rid, actor_username, e)
                    return False, 'Database is busy, please retry this report action.'
                raise
        return False, 'Database is busy, please retry this report action.'

    def _add_notification_with_retry(self, user_id: int, ntype: str, from_username: str,
                                     info_hash: str, torrent_name: str, comment_id: int,
                                     retries: int = 5) -> bool:
        for attempt in range(max(1, int(retries))):
            try:
                self.add_notification(user_id, ntype, from_username, info_hash, torrent_name, comment_id)
                return True
            except sqlite3.OperationalError as e:
                if 'locked' in str(e).lower() and attempt < (max(1, int(retries)) - 1):
                    time.sleep(0.06 * (attempt + 1))
                    continue
                if 'locked' in str(e).lower():
                    return False
                raise
        return False

    def notify_torrent_report_created(self, report_id: int, actor_username: str) -> int:
        report = self.get_torrent_report(int(report_id))
        if not report:
            return 0
        rid = int(report.get('id') or 0)
        reason = str(report.get('reason') or '')
        severity = str(report.get('severity') or 'normal')
        ih = str(report.get('info_hash') or '').upper()
        tname = str(report.get('torrent_name') or ih)[:120]
        recipients: set[int] = set()
        # Super/admin always receive report notifications.
        admin_rows = self._conn().execute(
            'SELECT id FROM users WHERE is_disabled=0 AND (username=? OR is_admin=1)',
            (SUPER_USER,)
        ).fetchall()
        recipients.update(int(r['id']) for r in admin_rows)
        # Editors only receive bad_metadata reports.
        if reason == 'bad_metadata':
            recipients.update(self._report_editor_user_ids())
        owner_uid = int(report.get('owner_user_id') or 0)
        if owner_uid > 0:
            recipients.add(owner_uid)
        reporter_uid = int(report.get('reporter_user_id') or 0)
        ntype = 'torrent_report_high' if severity == 'high' else 'torrent_report_open'
        sent = 0
        for uid in sorted(recipients):
            if uid <= 0 or uid == reporter_uid:
                continue
            if self._add_notification_with_retry(uid, ntype, actor_username, ih, tname, rid):
                sent += 1
            else:
                log.warning('notify_torrent_report_created skipped recipient due to db lock: report_id=%s uid=%s',
                            rid, uid)
        self._log(actor_username, 'report_notify_create', ih,
                  f'report_id={rid} reason={reason} severity={severity} recipients={sent}')
        return sent

    def notify_torrent_report_update(self, report_id: int, actor_username: str,
                                     update_label: str = 'updated') -> int:
        report = self.get_torrent_report(int(report_id))
        if not report:
            return 0
        rid = int(report.get('id') or 0)
        ih = str(report.get('info_hash') or '').upper()
        tname = str(report.get('torrent_name') or ih)[:120]
        actor_uid = 0
        if (actor_username or '').strip().lower() != 'system':
            a = self.get_user(actor_username)
            actor_uid = int(a['id'] or 0) if a else 0
        reason = str(report.get('reason') or '')
        recipients: set[int] = set()
        admin_rows = self._conn().execute(
            'SELECT id FROM users WHERE is_disabled=0 AND (username=? OR is_admin=1)',
            (SUPER_USER,)
        ).fetchall()
        recipients.update(int(r['id']) for r in admin_rows)
        if reason == 'bad_metadata':
            recipients.update(self._report_editor_user_ids())
        reporter_uid = int(report.get('reporter_user_id') or 0)
        owner_uid = int(report.get('owner_user_id') or 0)
        if reporter_uid > 0:
            recipients.add(reporter_uid)
        if owner_uid > 0:
            recipients.add(owner_uid)
        reporter_type_map = {
            'open': 'torrent_report_opened',
            'in_review': 'torrent_report_reviewing',
            'resolved': 'torrent_report_resolved',
            'dismissed': 'torrent_report_dismissed',
            'assign': 'torrent_report_assigned_to_reporter',
            'unassign': 'torrent_report_unassigned_from_reporter',
            'note': 'torrent_report_noted',
        }
        generic_type_map = {
            'open': 'torrent_report_open_generic',
            'in_review': 'torrent_report_reviewing_generic',
            'resolved': 'torrent_report_resolved_generic',
            'dismissed': 'torrent_report_dismissed_generic',
            'assign': 'torrent_report_assigned_generic',
            'unassign': 'torrent_report_unassigned_generic',
            'note': 'torrent_report_noted',
        }
        action_key = (update_label or '').strip().lower()
        sent = 0
        for uid in sorted(recipients):
            if uid <= 0:
                continue
            if actor_uid > 0 and uid == actor_uid:
                continue
            ntype = reporter_type_map.get(action_key, 'torrent_report_update') if uid == reporter_uid else generic_type_map.get(action_key, 'torrent_report_update')
            if self._add_notification_with_retry(uid, ntype, actor_username, ih, tname, rid):
                sent += 1
            else:
                log.warning('notify_torrent_report_update skipped recipient due to db lock: report_id=%s uid=%s',
                            rid, uid)
        self._log(actor_username, 'report_notify_update', ih,
                  f'report_id={rid} action={update_label[:32]} recipients={sent}')
        return sent

    def notify_torrent_report_note_assignee(self, report_id: int, actor_username: str) -> int:
        report = self.get_torrent_report(int(report_id))
        if not report:
            return 0
        rid = int(report.get('id') or 0)
        ih = str(report.get('info_hash') or '').upper()
        tname = str(report.get('torrent_name') or ih)[:120]
        assignee_uid = int(report.get('assigned_user_id') or 0)
        if assignee_uid <= 0:
            return 0
        actor_uid = 0
        if (actor_username or '').strip().lower() != 'system':
            a = self.get_user(actor_username)
            actor_uid = int(a['id'] or 0) if a else 0
        if actor_uid > 0 and assignee_uid == actor_uid:
            return 0
        if self._add_notification_with_retry(
            assignee_uid, 'torrent_report_noted_assignee', actor_username, ih, tname, rid
        ):
            self._log(actor_username, 'report_notify_note', ih,
                      f'report_id={rid} recipient={assignee_uid}')
            return 1
        log.warning('notify_torrent_report_note_assignee skipped recipient due to db lock: report_id=%s uid=%s',
                    rid, assignee_uid)
        return 0

    # ── Bounty System ─────────────────────────────────────────

    def create_bounty(self, username: str, description: str) -> tuple[bool, str]:
        """Create a new bounty. Spends points. Returns (ok, message_or_id)."""
        min_cost = int(self.get_setting('bounty_min_cost', '50'))
        ok = self.spend_points(
            self.get_user(username)['id'], min_cost,
            f'bounty created: {description[:40]}', 'bounty', ''
        )
        if not ok:
            return False, f'Insufficient points. Minimum bounty cost is {min_cost} pts.'
        expiry = (datetime.datetime.now() +
                  datetime.timedelta(days=int(self.get_setting('bounty_expiry_days', '90')))
                  ).date().isoformat()
        c = self._conn()
        cur = c.execute(
            'INSERT INTO bounties (created_by, description, status, initial_cost, total_escrow, created_at, expires_at)'
            ' VALUES (?,?,?,?,?,?,?)',
            (username, description, 'open', min_cost, min_cost, self._ts(), expiry)
        )
        c.commit()
        bid = cur.lastrowid
        # Record the contribution
        c.execute('INSERT INTO bounty_contributions (bounty_id,username,amount,contributed_at) VALUES (?,?,?,?)',
                  (bid, username, min_cost, self._ts()))
        c.commit()
        # Notify opted-in non-basic users, excluding creator.
        recipients = c.execute(
            '''SELECT username FROM users
               WHERE is_disabled=0
                 AND COALESCE(bounty_alerts, 1)=1
                 AND username != ?
                 AND (is_standard=1 OR is_admin=1 OR username=?)''',
            (username, SUPER_USER)
        ).fetchall()
        for r in recipients:
            self._notify_bounty(r['username'], 'bounty_new', username, bid, description, 0)
        self._log(username, 'bounty_create', str(bid), description[:60])
        return True, str(bid)

    def contribute_to_bounty(self, bounty_id: int, username: str, amount: int) -> tuple[bool, str]:
        """Add points to an existing open bounty."""
        b = self.get_bounty(bounty_id)
        if not b:
            return False, 'Bounty not found.'
        if b['status'] not in ('open', 'pending'):
            return False, 'Bounty is no longer active.'
        user = self.get_user(username)
        if not user:
            return False, 'User not found.'
        if amount < 1:
            return False, 'Amount must be at least 1.'
        ok = self.spend_points(user['id'], amount,
                               f'contributed {amount} pts to bounty #{bounty_id}',
                               'bounty_contrib', str(bounty_id))
        if not ok:
            return False, 'Insufficient points.'
        c = self._conn()
        c.execute('UPDATE bounties SET total_escrow=total_escrow+? WHERE id=?', (amount, bounty_id))
        c.execute('INSERT INTO bounty_contributions (bounty_id,username,amount,contributed_at) VALUES (?,?,?,?)',
                  (bounty_id, username, amount, self._ts()))
        c.commit()
        # Notify bounty creator
        creator = b['created_by']
        if creator != username:
            self._notify_bounty(creator, 'bounty_contribution', username, bounty_id,
                                b['description'], amount)
        self._log(username, 'bounty_contribute', str(bounty_id), f'+{amount} pts')
        return True, 'Contributed successfully.'

    def claim_bounty(self, bounty_id: int, claimer: str, info_hash: str) -> tuple[bool, str]:
        """Submit an infohash as fulfillment. First valid submission wins."""
        b = self.get_bounty(bounty_id)
        if not b:
            return False, 'Bounty not found.'
        if b['status'] != 'open':
            return False, 'Bounty is not open for claims.'
        if b['created_by'] == claimer:
            return False, 'You cannot claim your own bounty.'
        ih = info_hash.strip().upper()
        torrent = self.get_torrent(ih)
        if not torrent:
            return False, 'No torrent with that info hash is registered on this tracker.'
        now = datetime.datetime.now()
        expiry_dt = datetime.datetime.fromisoformat(b['expires_at'] + 'T23:59:59')
        if now > expiry_dt:
            return False, 'This bounty has expired.'
        c = self._conn()
        c.execute(
            'UPDATE bounties SET status=?,claimed_infohash=?,claimed_by=?,claimed_at=? WHERE id=?',
            ('pending', ih, claimer, self._ts(), bounty_id)
        )
        c.commit()
        self._log(claimer, 'bounty_claim', str(bounty_id), f'ih={ih} torrent={torrent["name"]}')
        # Notify all contributors
        contributors = self._get_bounty_contributor_usernames(bounty_id)
        for u in contributors:
            if u != claimer:
                self._notify_bounty(u, 'bounty_claimed', claimer, bounty_id,
                                    b['description'], 0, ih)
        return True, 'Claim submitted. Awaiting confirmation.'

    def confirm_bounty(self, bounty_id: int, confirmer: str) -> tuple[bool, str]:
        """Requestor confirms fulfillment. Pays out escrow."""
        b = self.get_bounty(bounty_id)
        if not b:
            return False, 'Bounty not found.'
        if b['status'] != 'pending':
            return False, 'No pending claim to confirm.'
        if b['created_by'] != confirmer:
            return False, 'Only the bounty creator can confirm.'
        return self._fulfill_bounty(bounty_id, refund_requestor=True)

    def reject_bounty_claim(self, bounty_id: int, rejecter: str) -> tuple[bool, str]:
        """Requestor rejects the claim. Bounty returns to open. Claimer penalised."""
        b = self.get_bounty(bounty_id)
        if not b:
            return False, 'Bounty not found.'
        if b['status'] != 'pending':
            return False, 'No pending claim to reject.'
        if b['created_by'] != rejecter:
            return False, 'Only the bounty creator can reject a claim.'
        claimer = b['claimed_by']
        penalty = int(self.get_setting('bounty_reject_penalty', '10'))
        claimer_user = self.get_user(claimer)
        if claimer_user:
            self.award_points(claimer_user['id'], -penalty,
                              f'bounty #{bounty_id} claim rejected', 'bounty_reject', str(bounty_id))
        c = self._conn()
        c.execute(
            'UPDATE bounties SET status=?,claimed_infohash=NULL,claimed_by=NULL,claimed_at=NULL WHERE id=?',
            ('open', bounty_id)
        )
        c.commit()
        self._log(rejecter, 'bounty_reject', str(bounty_id), f'claimer={claimer}')
        if claimer_user:
            self._notify_bounty(claimer, 'bounty_rejected', rejecter, bounty_id,
                                b['description'], 0)
        return True, 'Claim rejected. Bounty is open again.'

    def vote_bounty_fulfilled(self, bounty_id: int, voter: str) -> tuple[bool, str]:
        """Community vote that a pending claim is legitimate."""
        b = self.get_bounty(bounty_id)
        if not b:
            return False, 'Bounty not found.'
        if b['status'] != 'pending':
            return False, 'No pending claim to vote on.'
        if b['created_by'] == voter or b['claimed_by'] == voter:
            return False, 'Requestor and claimer cannot vote.'
        c = self._conn()
        try:
            c.execute('INSERT INTO bounty_votes (bounty_id,username,voted_at) VALUES (?,?,?)',
                      (bounty_id, voter, self._ts()))
            c.commit()
        except sqlite3.IntegrityError:
            self._rollback_quiet(c)
            return False, 'You have already voted.'
        # Check if threshold reached
        vote_count = c.execute('SELECT COUNT(*) FROM bounty_votes WHERE bounty_id=?',
                               (bounty_id,)).fetchone()[0]
        threshold = int(self.get_setting('bounty_confirm_votes', '3'))
        if vote_count >= threshold:
            self._fulfill_bounty(bounty_id, refund_requestor=False)
        return True, 'Vote recorded.'

    def admin_remove_bounty(self, bounty_id: int, actor: str, reason: str = '') -> tuple[bool, str]:
        """Moderation remove for spam/abuse bounties.

        Allowed states: open, pending. Escrow contributions are fully refunded.
        """
        b = self.get_bounty(bounty_id)
        if not b:
            return False, 'Bounty not found.'
        if b['status'] == 'removed':
            return False, 'Bounty is already removed.'
        if b['status'] not in ('open', 'pending'):
            return False, 'Only open or pending bounties can be removed.'

        c = self._conn()
        refunded_total = 0
        refunded_by_user: dict[str, int] = {}
        try:
            c.execute('BEGIN IMMEDIATE')
            contribs = c.execute(
                'SELECT username, amount FROM bounty_contributions WHERE bounty_id=?',
                (bounty_id,)
            ).fetchall()
            for row in contribs:
                amount = int(row['amount'] or 0)
                if amount <= 0:
                    continue
                u = c.execute('SELECT id FROM users WHERE username=?', (row['username'],)).fetchone()
                if not u:
                    continue
                self._award_points_tx(
                    c, int(u['id']), amount,
                    f'bounty #{bounty_id} removed by moderation — refunded contribution',
                    'bounty_refund_admin', str(bounty_id)
                )
                refunded_total += amount
                refunded_by_user[row['username']] = refunded_by_user.get(row['username'], 0) + amount
            c.execute(
                "UPDATE bounties SET status='removed', claimed_infohash=NULL, claimed_by=NULL, claimed_at=NULL "
                "WHERE id=?",
                (bounty_id,)
            )
            c.execute('COMMIT')
        except Exception:
            try:
                c.execute('ROLLBACK')
            except Exception:
                pass
            raise

        detail = f'from={b["status"]} refunded={refunded_total}'
        if reason:
            detail += f' reason={reason[:180]}'
        self._log(actor, 'bounty_remove_admin', str(bounty_id), detail)

        impacted = set(self._get_bounty_contributor_usernames(bounty_id))
        impacted.add(str(b['created_by'] or ''))
        if b['status'] == 'pending' and b['claimed_by']:
            impacted.add(str(b['claimed_by']))
        impacted.discard('')
        reason_text = reason.strip() or 'No reason provided.'
        notice_desc = f'{b["description"]} — reason: {reason_text}'
        for uname in impacted:
            self._notify_bounty(uname, 'bounty_removed', actor, bounty_id, notice_desc[:120], 0)
        for uname, amount in refunded_by_user.items():
            if amount > 0:
                refund_desc = f'{b["description"]} — refunded {amount} pts'
                self._notify_bounty(uname, 'bounty_refund_admin', actor, bounty_id, refund_desc[:120], amount)

        return True, f'Bounty removed. Refunded {refunded_total} pts to contributors.'

    def _fulfill_bounty(self, bounty_id: int, refund_requestor: bool) -> tuple[bool, str]:
        """Internal: pay out escrow and close bounty as fulfilled."""
        c = self._conn()
        promoted_user_ids: set[int] = set()
        try:
            c.execute('BEGIN IMMEDIATE')
            b = c.execute(
                "SELECT * FROM bounties WHERE id=? AND status='pending'",
                (bounty_id,)
            ).fetchone()
            if not b:
                c.execute('ROLLBACK')
                return False, 'Bounty is no longer pending.'

            claimer = b['claimed_by']
            ih = b['claimed_infohash']
            escrow = int(b['total_escrow'] or 0)
            torrent = c.execute(
                'SELECT uploaded_by_username FROM torrents WHERE info_hash=?',
                ((ih or '').upper(),)
            ).fetchone() if ih else None
            uploader = torrent['uploaded_by_username'] if torrent else None

            claimer_pct = int(self.get_setting('bounty_claimer_pct', '70')) / 100
            uploader_pct = int(self.get_setting('bounty_uploader_pct', '15')) / 100
            claimer_pay = int(escrow * claimer_pct)
            if uploader and uploader != claimer:
                uploader_pay = int(escrow * uploader_pct)
            else:
                uploader_pay = 0
                claimer_pay = int(escrow * (claimer_pct + uploader_pct))

            claimer_user = c.execute('SELECT id FROM users WHERE username=?', (claimer,)).fetchone()
            if claimer_user and claimer_pay > 0:
                self._award_points_tx(
                    c, int(claimer_user['id']), claimer_pay,
                    f'bounty #{bounty_id} fulfilled (claimer share)',
                    'bounty_payout', str(bounty_id)
                )
                promoted_user_ids.add(int(claimer_user['id']))

            if uploader_pay > 0:
                up_user = c.execute('SELECT id FROM users WHERE username=?', (uploader,)).fetchone()
                if up_user:
                    self._award_points_tx(
                        c, int(up_user['id']), uploader_pay,
                        f'your torrent fulfilled bounty #{bounty_id}',
                        'bounty_payout', str(bounty_id)
                    )
                    promoted_user_ids.add(int(up_user['id']))

            if refund_requestor:
                refund_pct = int(self.get_setting('bounty_refund_pct', '25')) / 100
                refund_amt = int(int(b['initial_cost'] or 0) * refund_pct)
                if refund_amt > 0:
                    req_user = c.execute('SELECT id FROM users WHERE username=?', (b['created_by'],)).fetchone()
                    if req_user:
                        self._award_points_tx(
                            c, int(req_user['id']), refund_amt,
                            f'bounty #{bounty_id} confirmed — partial refund',
                            'bounty_refund', str(bounty_id)
                        )
                        promoted_user_ids.add(int(req_user['id']))

            updated = c.execute(
                "UPDATE bounties SET status='fulfilled', fulfilled_by=?, fulfilled_at=? "
                "WHERE id=? AND status='pending'",
                (claimer, self._ts(), bounty_id)
            )
            if updated.rowcount != 1:
                c.execute('ROLLBACK')
                return False, 'Bounty state changed during fulfillment.'
            c.execute('COMMIT')
        except Exception:
            try:
                c.execute('ROLLBACK')
            except Exception:
                pass
            raise

        self._log('system', 'bounty_fulfilled', str(bounty_id),
                  f'claimer={claimer} escrow={escrow} refund={refund_requestor}')
        if uploader_pay > 0 and uploader and uploader != claimer:
            self._notify_bounty(uploader, 'bounty_uploader_payout', claimer, bounty_id,
                                b['description'], uploader_pay, ih)
        if claimer:
            self._notify_bounty(claimer, 'bounty_fulfilled', b['created_by'], bounty_id,
                                b['description'], claimer_pay, ih)
            self._notify_bounty(claimer, 'bounty_claimer_payout', b['created_by'], bounty_id,
                                b['description'], claimer_pay, ih)
            self.notify_followers_bounty_fulfilled(claimer, bounty_id, b['description'])
        for uid in promoted_user_ids:
            self.check_auto_promote(uid)
        return True, 'Bounty fulfilled.'

    def expire_bounties(self):
        """Called periodically to expire stale bounties and destroy their escrow."""
        today = _today_iso()
        c = self._conn()
        expired = c.execute(
            "SELECT * FROM bounties WHERE status IN ('open','pending') AND expires_at <= ?",
            (today,)
        ).fetchall()
        for b in expired:
            c.execute("UPDATE bounties SET status='expired' WHERE id=?", (b['id'],))
            c.commit()
            contributors = self._get_bounty_contributor_usernames(b['id'])
            for u in contributors:
                self._notify_bounty(u, 'bounty_expired', 'system', b['id'],
                                    b['description'], 0)
            self._log('system', 'bounty_expired', str(b['id']),
                      f'{b["total_escrow"]} pts destroyed')

    def get_bounty(self, bounty_id: int):
        return self._conn().execute(
            'SELECT * FROM bounties WHERE id=?', (bounty_id,)
        ).fetchone()

    def list_bounties(self, status: str | None = None, sort: str = 'points',
                      page: int = 1, per_page: int = 20) -> tuple[list, int]:
        c = self._conn()
        where = "WHERE status!='removed'"
        args: list = []
        if status:
            where = 'WHERE status=?'
            args.append(status)
        order = {
            'points':  'total_escrow DESC',
            'newest':  'created_at DESC',
            'oldest':  'created_at ASC',
        }.get(sort, 'total_escrow DESC')
        total = c.execute(f'SELECT COUNT(*) FROM bounties {where}', args).fetchone()[0]
        offset = (page - 1) * per_page
        rows = c.execute(
            f'SELECT * FROM bounties {where} ORDER BY {order} LIMIT ? OFFSET ?',
            args + [per_page, offset]
        ).fetchall()
        return rows, total

    def get_bounty_contributions(self, bounty_id: int) -> list:
        return self._conn().execute(
            'SELECT * FROM bounty_contributions WHERE bounty_id=? ORDER BY contributed_at',
            (bounty_id,)
        ).fetchall()

    def get_bounty_votes(self, bounty_id: int) -> list:
        return self._conn().execute(
            'SELECT * FROM bounty_votes WHERE bounty_id=? ORDER BY voted_at',
            (bounty_id,)
        ).fetchall()

    def get_leaderboard(self, top_n: int = 10) -> dict:
        """Return ranked lists for each leaderboard category."""
        c = self._conn()
        def _rows(sql, *args):
            return [dict(r) for r in c.execute(sql, args).fetchall()]

        holders = _rows(
            'SELECT username, points FROM users WHERE is_standard=1 OR is_admin=1 '
            'ORDER BY points DESC LIMIT ?', top_n)

        earners = _rows(
            'SELECT u.username, COALESCE(SUM(pl.delta),0) AS total_earned '
            'FROM users u LEFT JOIN points_ledger pl ON pl.user_id=u.id AND pl.delta>0 '
            'WHERE u.is_standard=1 OR u.is_admin=1 '
            'GROUP BY u.id ORDER BY total_earned DESC LIMIT ?', top_n)

        uploaders = _rows(
            'SELECT uploaded_by_username AS username, COUNT(*) AS torrent_count '
            'FROM torrents GROUP BY uploaded_by_username '
            'ORDER BY torrent_count DESC LIMIT ?', top_n)

        bounty_hunters = _rows(
            'SELECT fulfilled_by AS username, COUNT(*) AS fulfilled_count '
            "FROM bounties WHERE status='fulfilled' AND fulfilled_by IS NOT NULL "
            'GROUP BY fulfilled_by ORDER BY fulfilled_count DESC LIMIT ?', top_n)

        streaks = _rows(
            'SELECT username, login_streak FROM users '
            'WHERE (is_standard=1 OR is_admin=1) AND login_streak > 0 '
            'ORDER BY login_streak DESC LIMIT ?', top_n)

        chatty = _rows(
            'SELECT u.username, COUNT(cm.id) AS comment_count '
            'FROM users u JOIN comments cm ON cm.username=u.username '
            'WHERE u.is_standard=1 OR u.is_admin=1 '
            'GROUP BY u.username ORDER BY comment_count DESC LIMIT ?', top_n)

        popular = _rows(
            'SELECT u.username, COUNT(f.id) AS follower_count '
            'FROM users u LEFT JOIN user_follows f ON f.followed_user_id=u.id '
            'WHERE u.is_standard=1 OR u.is_admin=1 '
            'GROUP BY u.id ORDER BY follower_count DESC, u.username ASC LIMIT ?', top_n)
        metadata_curators = self.get_metadata_curators(top_n)

        return {
            'holders':       holders,
            'earners':       earners,
            'uploaders':     uploaders,
            'bounty_hunters':bounty_hunters,
            'streaks':       streaks,
            'chatty':        chatty,
            'popular':       popular,
            'metadata_curators': metadata_curators,
        }

    def list_bounties_by_user(self, username: str) -> dict:
        """Return dicts of created and fulfilled bounties for profile display."""
        c = self._conn()
        created   = c.execute(
            'SELECT * FROM bounties WHERE created_by=? ORDER BY created_at DESC', (username,)
        ).fetchall()
        fulfilled = c.execute(
            'SELECT * FROM bounties WHERE fulfilled_by=? ORDER BY fulfilled_at DESC', (username,)
        ).fetchall()
        return {'created': created, 'fulfilled': fulfilled}

    def _get_bounty_contributor_usernames(self, bounty_id: int) -> list[str]:
        rows = self._conn().execute(
            'SELECT DISTINCT username FROM bounty_contributions WHERE bounty_id=?', (bounty_id,)
        ).fetchall()
        return [r['username'] for r in rows]

    def _notify_bounty(self, recipient: str, ntype: str, actor: str,
                       bounty_id: int, description: str, amount: int,
                       info_hash: str = '') -> None:
        """Insert a bounty notification using existing notification schema fields.
        Schema mapping is intentional:
        - info_hash carries "BOUNTY:{id}" sentinel
        - torrent_name carries bounty description text
        - comment_id carries numeric amount payload for payout-style messages
        """
        user = self.get_user(recipient)
        if not user:
            return
        # Use a "BOUNTY:" info_hash prefix to distinguish bounty notifications.
        self._conn().execute(
            'INSERT INTO notifications (user_id,type,from_username,info_hash,torrent_name,'
            'comment_id,created_at,is_read) VALUES (?,?,?,?,?,?,?,0)',
            (user['id'], ntype, actor,
             f'BOUNTY:{bounty_id}',
             description[:120],
             amount, self._ts())
        )
        self._conn().commit()

    def list_invite_codes(self, created_by_username: str | None = None) -> list:
        """All codes (admin view) or codes for a specific user."""
        if created_by_username:
            return self._conn().execute(
                'SELECT * FROM invite_codes WHERE created_by_username=?'
                ' ORDER BY created_at DESC', (created_by_username,)
            ).fetchall()
        return self._conn().execute(
            'SELECT * FROM invite_codes ORDER BY created_at DESC'
        ).fetchall()

    def delete_invite_code(self, code: str, actor: str) -> bool:
        """Delete an invite code. Returns True if it existed."""
        cur = self._conn().execute(
            'DELETE FROM invite_codes WHERE code=? AND consumed_at IS NULL', (code,)
        )
        self._conn().commit()
        if cur.rowcount:
            self._log(actor, 'delete_invite', code[:12] + '...')
            return True
        return False

    def consume_invite_code(self, code: str, new_username: str) -> bool:
        """Mark invite as consumed. Returns True if valid & unconsumed."""
        cur = self._conn().execute(
            'UPDATE invite_codes SET consumed_at=?, consumed_by_username=?'
            ' WHERE code=? AND consumed_at IS NULL',
            (self._ts(), new_username, code)
        )
        self._conn().commit()
        return cur.rowcount > 0

    def get_invite_code(self, code: str):
        """Return invite row or None."""
        return self._conn().execute(
            'SELECT * FROM invite_codes WHERE code=?', (code,)
        ).fetchone()

    def is_registered(self, ih_upper: str) -> bool:
        row = self._conn().execute(
            'SELECT id FROM torrents WHERE info_hash=?', (ih_upper,)
        ).fetchone()
        return row is not None

    @staticmethod
    def _build_search_clauses(query: str):
        """Split query into tokens, return (where_fragment, params_list).
        Each token must match either the name (with separators normalised to spaces)
        or the raw name or the info_hash.  Dots/dashes/underscores are treated as
        spaces so 'ubuntu server' matches 'Ubuntu.Server.2025...'
        """
        import re
        # Normalise separators in the query too, then split on whitespace
        tokens = re.split(r'[\s.\-_]+', query.strip())
        tokens = [t for t in tokens if t]  # drop empties
        if not tokens:
            tokens = [query.strip()]
        clauses = []
        params = []
        for tok in tokens:
            like = f'%{tok}%'
            # Match raw name, separator-normalised name, or info_hash
            clauses.append(
                '(name LIKE ? OR '
                'REPLACE(REPLACE(REPLACE(name,\'.\',\' \'),\'-\',\' \'),\'_\',\' \') LIKE ? OR '
                'info_hash LIKE ?)'
            )
            params.extend([like, like, like])
        where = ' AND '.join(clauses)
        return where, params

    @staticmethod
    def _parse_special_torrent_search(query: str) -> tuple[str, str]:
        q = (query or '').strip()
        m = re.fullmatch(r'(?i)imdb\s*:\s*(tt[0-9]{4,12})', q)
        if m:
            return 'imdb', m.group(1).lower()
        m = re.fullmatch(r'(?i)tvmaze\s*:\s*([0-9]{1,12})', q)
        if m:
            return 'tvmaze', m.group(1)
        m = re.fullmatch(r'(?i)steam\s*:\s*([0-9]{1,12})', q)
        if m:
            return 'steam', m.group(1)
        return '', ''

    @classmethod
    def _facet_clauses(cls, facets: dict[str, str] | None, table_alias: str = '') -> tuple[str, list[str]]:
        if not facets:
            return '', []
        alias = f'{table_alias}.' if table_alias else ''
        clauses: list[str] = []
        params: list[str] = []
        media_type = str(facets.get('media_type') or '').strip().lower()
        if media_type in ('movie', 'tv', 'game'):
            clauses.append(f'LOWER(COALESCE({alias}media_type,\'\'))=?')
            params.append(media_type)
        elif media_type == 'other':
            clauses.append(f'LOWER(COALESCE({alias}media_type,\'\')) NOT IN (\'movie\',\'tv\',\'game\')')
        resolution = str(facets.get('release_resolution') or '').strip().lower()
        if resolution in ('2160p', '1080p', '720p', '480p'):
            clauses.append(f'LOWER(COALESCE({alias}release_resolution,\'\'))=?')
            params.append(resolution)
        source = str(facets.get('release_source_class') or '').strip().lower()
        if source in ('web-dl', 'webrip', 'web', 'bluray', 'dvdrip', 'remux'):
            clauses.append(f'LOWER(COALESCE({alias}release_source_class,\'\'))=?')
            params.append(source)
        provider = str(facets.get('release_provider') or '').strip().lower()
        if provider in ('amzn', 'nf', 'dsnp', 'atvp', 'hmax', 'pmtp', 'pcok', 'hulu', 'now', 'roku', 'ma', 'plex', 'lbxd'):
            clauses.append(f'LOWER(COALESCE({alias}release_provider,\'\'))=?')
            params.append(provider)
        genre = cls._normalize_genre_token(str(facets.get('genre') or ''))
        if genre:
            clauses.append(cls._csv_contains_token_sql(f'{alias}content_genres'))
            params.append(f',{genre},')
        audio_feature = cls._normalize_csv_token(str(facets.get('audio_feature') or ''))
        if audio_feature:
            clauses.append(cls._csv_contains_token_sql(f'{alias}release_audio_features'))
            params.append(f',{audio_feature},')
        hdr_flag = cls._normalize_csv_token(str(facets.get('hdr_flag') or ''))
        if hdr_flag in ('hdr', 'dv'):
            clauses.append(cls._csv_contains_token_sql(f'{alias}release_hdr_flags'))
            params.append(f',{hdr_flag},')
        if not clauses:
            return '', []
        return ' AND '.join(clauses), params

    @staticmethod
    def _exclude_uploader_clause(exclude_uploader_ids: list[int] | None,
                                 column_expr: str = 'uploaded_by_id') -> tuple[str, list[int]]:
        ids: list[int] = []
        for raw in (exclude_uploader_ids or []):
            try:
                v = int(raw)
            except Exception:
                continue
            if v > 0 and v not in ids:
                ids.append(v)
        if not ids:
            return '', []
        placeholders = ','.join('?' for _ in ids)
        return f' AND COALESCE({column_expr},0) NOT IN ({placeholders})', ids

    def search_torrents(self, query: str, user_id: int | None = None,
                        page: int = 1, per_page: int = 50,
                        facets: dict[str, str] | None = None,
                        exclude_uploader_ids: list[int] | None = None) -> list:
        mode, value = self._parse_special_torrent_search(query)
        where, params = self._build_search_clauses(query)
        facet_sql, facet_params = self._facet_clauses(facets, table_alias='t')
        facet_sql_plain, facet_params_plain = self._facet_clauses(facets, table_alias='')
        exclude_t_sql, exclude_t_params = self._exclude_uploader_clause(exclude_uploader_ids, 't.uploaded_by_id')
        exclude_plain_sql, exclude_plain_params = self._exclude_uploader_clause(exclude_uploader_ids, 'uploaded_by_id')
        offset = (max(1, page) - 1) * per_page
        if mode == 'imdb':
            if user_id is None:
                tail = (f' AND {facet_sql}' if facet_sql else '') + exclude_t_sql
                return self._conn().execute(
                    '''SELECT t.* FROM torrents t
                       JOIN torrent_metadata_links l
                         ON l.info_hash=t.info_hash
                      WHERE l.status='active' AND l.provider='imdb' AND LOWER(l.external_id)=?
                      ''' + tail + '''
                      ORDER BY t.registered_at DESC LIMIT ? OFFSET ?''',
                    (value, *facet_params, *exclude_t_params, per_page, offset)
                ).fetchall()
            tail = (f' AND {facet_sql}' if facet_sql else '') + exclude_t_sql
            return self._conn().execute(
                '''SELECT t.* FROM torrents t
                   JOIN torrent_metadata_links l
                     ON l.info_hash=t.info_hash
                  WHERE t.uploaded_by_id=? AND l.status='active'
                    AND l.provider='imdb' AND LOWER(l.external_id)=?
                  ''' + tail + '''
                  ORDER BY t.registered_at DESC LIMIT ? OFFSET ?''',
                (user_id, value, *facet_params, *exclude_t_params, per_page, offset)
            ).fetchall()
        if mode == 'tvmaze':
            if user_id is None:
                tail = (f' AND {facet_sql}' if facet_sql else '') + exclude_t_sql
                return self._conn().execute(
                    '''SELECT t.* FROM torrents t
                       JOIN torrent_metadata_links l
                         ON l.info_hash=t.info_hash
                      WHERE l.status='active' AND l.provider='tvmaze' AND l.external_id=?
                      ''' + tail + '''
                      ORDER BY t.registered_at DESC LIMIT ? OFFSET ?''',
                    (value, *facet_params, *exclude_t_params, per_page, offset)
                ).fetchall()
            tail = (f' AND {facet_sql}' if facet_sql else '') + exclude_t_sql
            return self._conn().execute(
                '''SELECT t.* FROM torrents t
                   JOIN torrent_metadata_links l
                     ON l.info_hash=t.info_hash
                  WHERE t.uploaded_by_id=? AND l.status='active'
                    AND l.provider='tvmaze' AND l.external_id=?
                  ''' + tail + '''
                  ORDER BY t.registered_at DESC LIMIT ? OFFSET ?''',
                (user_id, value, *facet_params, *exclude_t_params, per_page, offset)
            ).fetchall()
        if mode == 'steam':
            if user_id is None:
                tail = (f' AND {facet_sql}' if facet_sql else '') + exclude_t_sql
                return self._conn().execute(
                    '''SELECT t.* FROM torrents t
                       JOIN torrent_metadata_links l
                         ON l.info_hash=t.info_hash
                      WHERE l.status='active' AND l.provider='steam' AND l.external_id=?
                      ''' + tail + '''
                      ORDER BY t.registered_at DESC LIMIT ? OFFSET ?''',
                    (value, *facet_params, *exclude_t_params, per_page, offset)
                ).fetchall()
            tail = (f' AND {facet_sql}' if facet_sql else '') + exclude_t_sql
            return self._conn().execute(
                '''SELECT t.* FROM torrents t
                   JOIN torrent_metadata_links l
                     ON l.info_hash=t.info_hash
                  WHERE t.uploaded_by_id=? AND l.status='active'
                    AND l.provider='steam' AND l.external_id=?
                  ''' + tail + '''
                  ORDER BY t.registered_at DESC LIMIT ? OFFSET ?''',
                (user_id, value, *facet_params, *exclude_t_params, per_page, offset)
            ).fetchall()
        if user_id is None:
            facet_tail = (f' AND ({facet_sql_plain})' if facet_sql_plain else '') + exclude_plain_sql
            return self._conn().execute(
                f'SELECT * FROM torrents WHERE {where} '
                f'{facet_tail} '
                'ORDER BY registered_at DESC LIMIT ? OFFSET ?',
                (*params, *facet_params_plain, *exclude_plain_params, per_page, offset)
            ).fetchall()
        facet_tail = (f' AND ({facet_sql_plain})' if facet_sql_plain else '') + exclude_plain_sql
        return self._conn().execute(
            f'SELECT * FROM torrents WHERE uploaded_by_id=? AND ({where}) '
            f'{facet_tail} '
            'ORDER BY registered_at DESC LIMIT ? OFFSET ?',
            (user_id, *params, *facet_params_plain, *exclude_plain_params, per_page, offset)
        ).fetchall()

    def count_search_torrents(self, query: str, user_id: int | None = None,
                              facets: dict[str, str] | None = None,
                              exclude_uploader_ids: list[int] | None = None) -> int:
        mode, value = self._parse_special_torrent_search(query)
        where, params = self._build_search_clauses(query)
        facet_sql, facet_params = self._facet_clauses(facets, table_alias='t')
        facet_sql_plain, facet_params_plain = self._facet_clauses(facets, table_alias='')
        exclude_t_sql, exclude_t_params = self._exclude_uploader_clause(exclude_uploader_ids, 't.uploaded_by_id')
        exclude_plain_sql, exclude_plain_params = self._exclude_uploader_clause(exclude_uploader_ids, 'uploaded_by_id')
        if mode == 'imdb':
            if user_id is None:
                tail = (f' AND {facet_sql}' if facet_sql else '') + exclude_t_sql
                return self._conn().execute(
                    '''SELECT COUNT(*) FROM torrents t
                       JOIN torrent_metadata_links l
                         ON l.info_hash=t.info_hash
                      WHERE l.status='active' AND l.provider='imdb' AND LOWER(l.external_id)=?''' + tail,
                    (value, *facet_params, *exclude_t_params)
                ).fetchone()[0]
            tail = (f' AND {facet_sql}' if facet_sql else '') + exclude_t_sql
            return self._conn().execute(
                '''SELECT COUNT(*) FROM torrents t
                   JOIN torrent_metadata_links l
                     ON l.info_hash=t.info_hash
                  WHERE t.uploaded_by_id=? AND l.status='active'
                    AND l.provider='imdb' AND LOWER(l.external_id)=?''' + tail,
                (user_id, value, *facet_params, *exclude_t_params)
            ).fetchone()[0]
        if mode == 'tvmaze':
            if user_id is None:
                tail = (f' AND {facet_sql}' if facet_sql else '') + exclude_t_sql
                return self._conn().execute(
                    '''SELECT COUNT(*) FROM torrents t
                       JOIN torrent_metadata_links l
                         ON l.info_hash=t.info_hash
                      WHERE l.status='active' AND l.provider='tvmaze' AND l.external_id=?''' + tail,
                    (value, *facet_params, *exclude_t_params)
                ).fetchone()[0]
            tail = (f' AND {facet_sql}' if facet_sql else '') + exclude_t_sql
            return self._conn().execute(
                '''SELECT COUNT(*) FROM torrents t
                   JOIN torrent_metadata_links l
                     ON l.info_hash=t.info_hash
                  WHERE t.uploaded_by_id=? AND l.status='active'
                    AND l.provider='tvmaze' AND l.external_id=?''' + tail,
                (user_id, value, *facet_params, *exclude_t_params)
            ).fetchone()[0]
        if mode == 'steam':
            if user_id is None:
                tail = (f' AND {facet_sql}' if facet_sql else '') + exclude_t_sql
                return self._conn().execute(
                    '''SELECT COUNT(*) FROM torrents t
                       JOIN torrent_metadata_links l
                         ON l.info_hash=t.info_hash
                      WHERE l.status='active' AND l.provider='steam' AND l.external_id=?''' + tail,
                    (value, *facet_params, *exclude_t_params)
                ).fetchone()[0]
            tail = (f' AND {facet_sql}' if facet_sql else '') + exclude_t_sql
            return self._conn().execute(
                '''SELECT COUNT(*) FROM torrents t
                   JOIN torrent_metadata_links l
                     ON l.info_hash=t.info_hash
                  WHERE t.uploaded_by_id=? AND l.status='active'
                    AND l.provider='steam' AND l.external_id=?''' + tail,
                (user_id, value, *facet_params, *exclude_t_params)
            ).fetchone()[0]
        if user_id is None:
            facet_tail = (f' AND ({facet_sql_plain})' if facet_sql_plain else '') + exclude_plain_sql
            return self._conn().execute(
                f'SELECT COUNT(*) FROM torrents WHERE {where}{facet_tail}',
                (*params, *facet_params_plain, *exclude_plain_params)
            ).fetchone()[0]
        facet_tail = (f' AND ({facet_sql_plain})' if facet_sql_plain else '') + exclude_plain_sql
        return self._conn().execute(
            f'SELECT COUNT(*) FROM torrents WHERE uploaded_by_id=? AND ({where}){facet_tail}',
            (user_id, *params, *facet_params_plain, *exclude_plain_params)
        ).fetchone()[0]

    def count_torrents(self, user_id: int | None = None,
                       facets: dict[str, str] | None = None,
                       exclude_uploader_ids: list[int] | None = None) -> int:
        facet_sql, facet_params = self._facet_clauses(facets, table_alias='')
        exclude_sql, exclude_params = self._exclude_uploader_clause(exclude_uploader_ids, 'uploaded_by_id')
        if user_id is None:
            where_parts: list[str] = []
            if facet_sql:
                where_parts.append(f'({facet_sql})')
            if exclude_sql:
                where_parts.append(exclude_sql[5:])  # strip leading " AND "
            if where_parts:
                where = ' WHERE ' + ' AND '.join(where_parts)
                return self._conn().execute(
                    f'SELECT COUNT(*) FROM torrents{where}',
                    (*facet_params, *exclude_params)
                ).fetchone()[0]
            return self._conn().execute('SELECT COUNT(*) FROM torrents').fetchone()[0]
        where_parts = ['uploaded_by_id=?']
        query_params: list[Any] = [user_id]
        if facet_sql:
            where_parts.append(f'({facet_sql})')
            query_params.extend(facet_params)
        if exclude_sql:
            where_parts.append(exclude_sql[5:])  # strip leading " AND "
            query_params.extend(exclude_params)
        where = ' AND '.join(where_parts)
        return self._conn().execute(
            f'SELECT COUNT(*) FROM torrents WHERE {where}',
            tuple(query_params)
        ).fetchone()[0]

    def list_torrents(self, user_id: int | None = None,
                      page: int = 1, per_page: int = 0,
                      facets: dict[str, str] | None = None,
                      exclude_uploader_ids: list[int] | None = None) -> list:
        """Return torrents. per_page=0 means no pagination (all rows)."""
        facet_sql, facet_params = self._facet_clauses(facets, table_alias='')
        exclude_sql, exclude_params = self._exclude_uploader_clause(exclude_uploader_ids, 'uploaded_by_id')
        if per_page <= 0:
            if user_id is None:
                if facet_sql or exclude_sql:
                    where_parts: list[str] = []
                    if facet_sql:
                        where_parts.append(f'({facet_sql})')
                    if exclude_sql:
                        where_parts.append(exclude_sql[5:])  # strip leading " AND "
                    where = ' AND '.join(where_parts)
                    return self._conn().execute(
                        f'SELECT * FROM torrents WHERE {where} ORDER BY registered_at DESC',
                        (*facet_params, *exclude_params)
                    ).fetchall()
                return self._conn().execute(
                    'SELECT * FROM torrents ORDER BY registered_at DESC'
                ).fetchall()
            where_parts = ['uploaded_by_id=?']
            query_params: list[Any] = [user_id]
            if facet_sql:
                where_parts.append(f'({facet_sql})')
                query_params.extend(facet_params)
            if exclude_sql:
                where_parts.append(exclude_sql[5:])  # strip leading " AND "
                query_params.extend(exclude_params)
            where = ' AND '.join(where_parts)
            return self._conn().execute(
                f'SELECT * FROM torrents WHERE {where} ORDER BY registered_at DESC',
                tuple(query_params)
            ).fetchall()
        offset = (max(1, page) - 1) * per_page
        if user_id is None:
            if facet_sql or exclude_sql:
                where_parts: list[str] = []
                if facet_sql:
                    where_parts.append(f'({facet_sql})')
                if exclude_sql:
                    where_parts.append(exclude_sql[5:])  # strip leading " AND "
                where = ' AND '.join(where_parts)
                return self._conn().execute(
                    f'SELECT * FROM torrents WHERE {where} ORDER BY registered_at DESC LIMIT ? OFFSET ?',
                    (*facet_params, *exclude_params, per_page, offset)
                ).fetchall()
            return self._conn().execute(
                'SELECT * FROM torrents ORDER BY registered_at DESC LIMIT ? OFFSET ?',
                (per_page, offset)
            ).fetchall()
        where_parts = ['uploaded_by_id=?']
        query_params: list[Any] = [user_id]
        if facet_sql:
            where_parts.append(f'({facet_sql})')
            query_params.extend(facet_params)
        if exclude_sql:
            where_parts.append(exclude_sql[5:])  # strip leading " AND "
            query_params.extend(exclude_params)
        where = ' AND '.join(where_parts)
        query_params.extend([per_page, offset])
        return self._conn().execute(
            f'SELECT * FROM torrents WHERE {where} ORDER BY registered_at DESC LIMIT ? OFFSET ?',
            tuple(query_params)
        ).fetchall()

    def delete_torrent(self, ih: str, actor: str):
        ih_upper = ih.upper()
        # Fetch name before deleting so we can log it
        row = self._conn().execute(
            'SELECT name FROM torrents WHERE info_hash=?', (ih_upper,)
        ).fetchone()
        torrent_name = row['name'] if row else ih_upper
        for attempt in range(4):
            c = None
            try:
                # Use a fresh dedicated writer connection so deletion is not
                # affected by any thread-local transaction state.
                c = sqlite3.connect(
                    self._path,
                    timeout=30,
                    check_same_thread=False,
                    factory=_WKSQLiteConnection,
                )
                c.row_factory = sqlite3.Row
                c.execute('PRAGMA journal_mode=WAL')
                c.execute('PRAGMA foreign_keys=ON')
                c.execute('PRAGMA busy_timeout=30000')
                c.execute('BEGIN IMMEDIATE')
                # Expunge all comments and notifications tied to this torrent
                c.execute('DELETE FROM comments WHERE info_hash=?', (ih_upper,))
                c.execute('DELETE FROM notifications WHERE info_hash=?', (ih_upper,))
                c.execute('DELETE FROM torrent_votes WHERE info_hash=?', (ih_upper,))
                c.execute('DELETE FROM torrent_report_actions WHERE report_id IN (SELECT id FROM torrent_reports WHERE info_hash=?)',
                          (ih_upper,))
                c.execute('DELETE FROM torrent_reports WHERE info_hash=?', (ih_upper,))
                c.execute('DELETE FROM torrents WHERE info_hash=?', (ih_upper,))
                c.execute('COMMIT')
                self._log(actor, 'delete_torrent', ih_upper, torrent_name)
                return True, ''
            except sqlite3.OperationalError as e:
                try:
                    if c is not None:
                        c.execute('ROLLBACK')
                except Exception:
                    pass
                if 'locked' in str(e).lower() and attempt < 3:
                    time.sleep(0.35 * (attempt + 1))
                    continue
                if 'locked' in str(e).lower():
                    log.warning('delete_torrent lock after retries (non-fatal): ih=%s actor=%s err=%s',
                                ih_upper, actor, e)
                    return False, 'Database is busy, please retry deleting this torrent.'
                raise
            finally:
                if c is not None:
                    try:
                        c.close()
                    except Exception:
                        pass

    def backup_to_bytes(self) -> bytes:
        """Return a gzip-compressed snapshot of the live DB as raw bytes."""
        import gzip
        import tempfile
        import os
        with tempfile.NamedTemporaryFile(suffix='.db', delete=False) as tf:
            tmp_path = tf.name
        try:
            dst = sqlite3.connect(tmp_path)
            self._conn().backup(dst)
            dst.close()
            with open(tmp_path, 'rb') as f:
                raw = f.read()
        finally:
            os.unlink(tmp_path)
        gz_buf = io.BytesIO()
        with gzip.GzipFile(fileobj=gz_buf, mode='wb', compresslevel=9) as gz:
            gz.write(raw)
        return gz_buf.getvalue()

    def restore_from_bytes(self, gz_data: bytes, actor: str) -> None:
        """Replace the live DB with a gzip-compressed SQLite backup."""
        import gzip
        import tempfile
        import os
        import shutil
        try:
            raw = gzip.decompress(gz_data)
        except Exception:
            raise ValueError('Not a valid gzip file')
        if not raw.startswith(b'SQLite format 3\x00'):
            raise ValueError('File is not a valid SQLite database')
        with tempfile.NamedTemporaryFile(suffix='.db', delete=False) as tf:
            tf.write(raw)
            tmp_path = tf.name
        try:
            # Validate integrity before touching the live DB
            check = sqlite3.connect(tmp_path)
            result = check.execute('PRAGMA integrity_check').fetchone()
            check.close()
            if result[0] != 'ok':
                raise ValueError('Backup database failed integrity check')
            with self._restore_lock:
                # Close this thread's connection and flush WAL
                conn = getattr(self._local, 'conn', None)
                if conn:
                    try:
                        conn.execute('PRAGMA wal_checkpoint(TRUNCATE)')
                        conn.close()
                    except Exception:
                        pass
                    self._local.conn = None
                # Overwrite the DB file on disk
                shutil.copy2(tmp_path, self._path)
                # Remove any stale WAL / SHM files so they don't override the restore
                for ext in ('-wal', '-shm'):
                    sidecar = self._path + ext
                    if os.path.exists(sidecar):
                        try:
                            os.unlink(sidecar)
                        except Exception:
                            pass
                # Bump generation — every thread will reopen on next DB call
                self._restore_gen += 1
        finally:
            os.unlink(tmp_path)
        # Log using the freshly-reopened connection
        self._log(actor, 'db_restore', '', 'Database restored from backup')

    def delete_all_comments_global(self, actor: str) -> int:
        """Hard-delete every comment and notification in the system."""
        count = self._conn().execute('SELECT COUNT(*) FROM comments').fetchone()[0]
        self._conn().execute('DELETE FROM comments')
        self._conn().execute('DELETE FROM notifications')
        self._conn().commit()
        self._log(actor, 'delete_all_comments_global', '', f'{count} comment(s) removed')
        return count

    def system_wipe(self, actor: str):
        """Wipe all data except the super user account and system settings."""
        c = self._conn()
        # Keep only the super account itself; wipe all runtime/user-generated data.
        c.execute('DELETE FROM users WHERE username != ?', (actor,))
        c.execute('DELETE FROM torrents')
        c.execute('DELETE FROM comments')
        c.execute('DELETE FROM notifications')
        c.execute('DELETE FROM torrent_votes')
        c.execute('DELETE FROM torrent_reports')
        c.execute('DELETE FROM torrent_report_actions')
        c.execute('DELETE FROM invite_codes')
        c.execute('DELETE FROM points_ledger')
        c.execute('DELETE FROM bounties')
        c.execute('DELETE FROM bounty_contributions')
        c.execute('DELETE FROM bounty_votes')
        c.execute('DELETE FROM direct_messages')
        c.execute('DELETE FROM dm_blocklist')
        c.execute('DELETE FROM ip_allowlist')
        c.execute('DELETE FROM login_history')
        c.execute('DELETE FROM user_follows')
        c.execute('DELETE FROM account_delete_challenges')
        c.execute('DELETE FROM webauthn_challenges')
        c.execute('DELETE FROM tfa_challenges')
        c.execute('DELETE FROM tfa_recovery_events')
        c.execute('DELETE FROM topup_reconciliation_actions')
        c.execute('DELETE FROM topup_webhook_events')
        c.execute('DELETE FROM topup_orders')
        c.execute('DELETE FROM sessions WHERE user_id NOT IN (SELECT id FROM users)')
        # Reset mutable account state for remaining account(s).
        c.execute(
            '''UPDATE users
               SET is_locked=0,
                   locked_at=NULL,
                   is_disabled=0,
                   failed_attempts=0,
                   last_login=NULL,
                   login_count=0,
                   credits=0,
                   credits_awarded=0,
                   points=0,
                   points_micro=0,
                   login_streak=0,
                   longest_streak=0,
                   last_login_date=NULL,
                   comment_pts_date=NULL,
                   comment_pts_today=0,
                   last_seen=NULL'''
        )
        c.execute('DELETE FROM events')
        c.commit()
        self._log(actor, 'SYSTEM_WIPE', '', 'All data wiped except super account')

