    # ── TFA / TOTP ───────────────────────────────────────────

    def _encode_tfa_secret(self, secret_b32: str) -> str:
        text = (secret_b32 or '').strip()
        if not text:
            return ''
        if self._tfa_fernet:
            try:
                token = self._tfa_fernet.encrypt(text.encode('utf-8')).decode('ascii')
                return f'enc:v2:{token}'
            except Exception:
                pass
        # Backward-compatible fallback when encryption backend/key is unavailable.
        return 'plain:v1:' + base64.urlsafe_b64encode(text.encode('utf-8')).decode('ascii')

    def _decode_tfa_secret(self, encoded: str) -> str:
        raw = (encoded or '').strip()
        if not raw:
            return ''
        if raw.startswith('enc:v2:'):
            if not self._tfa_fernet:
                return ''
            try:
                return self._tfa_fernet.decrypt(raw[len('enc:v2:'):].encode('ascii')).decode('utf-8')
            except (InvalidToken, Exception):
                return ''
        if raw.startswith('plain:v1:'):
            raw = raw[len('plain:v1:'):]
        try:
            return base64.urlsafe_b64decode(raw.encode('ascii')).decode('utf-8')
        except Exception:
            return ''

    def reserve_user_tfa_totp_counter(self, user_id: int, counter: int) -> bool:
        """Atomically reserve a strictly newer TOTP counter for this user."""
        cur = self._conn().execute(
            '''UPDATE users
               SET tfa_last_verified_at=?, tfa_last_counter=?
               WHERE id=? AND COALESCE(tfa_last_counter, -1) < ?''',
            (self._ts(), int(counter), user_id, int(counter))
        )
        self._conn().commit()
        return bool(cur.rowcount)

    def migrate_legacy_tfa_secrets(self, actor: str = 'system') -> tuple[int, int]:
        """Re-encrypt legacy plain/base64 TFA secrets into enc:v2 format."""
        if not self._tfa_fernet:
            return 0, 0
        c = self._conn()
        rows = c.execute(
            "SELECT id,tfa_secret_enc FROM users WHERE tfa_secret_enc IS NOT NULL AND TRIM(tfa_secret_enc)<>''"
        ).fetchall()
        migrated = 0
        for row in rows:
            raw = (row['tfa_secret_enc'] or '').strip()
            if not raw or raw.startswith('enc:v2:'):
                continue
            secret = self._decode_tfa_secret(raw)
            if not re.fullmatch(r'[A-Z2-7]{16,128}', secret or ''):
                continue
            new_val = self._encode_tfa_secret(secret)
            if not new_val.startswith('enc:v2:'):
                continue
            c.execute('UPDATE users SET tfa_secret_enc=?, tfa_secret_ver=2 WHERE id=?',
                      (new_val, int(row['id'])))
            migrated += 1
        c.commit()
        remaining = int(c.execute(
            "SELECT COUNT(*) FROM users WHERE tfa_secret_enc IS NOT NULL AND TRIM(tfa_secret_enc)<>'' AND tfa_secret_enc NOT LIKE 'enc:v2:%'"
        ).fetchone()[0])
        if migrated > 0 or remaining > 0:
            self._log(actor, 'tfa_secret_migration', '', f'migrated={migrated} remaining={remaining}')
        return migrated, remaining

    def get_user_tfa_secret(self, user_id: int) -> str:
        row = self._conn().execute(
            'SELECT tfa_secret_enc FROM users WHERE id=?',
            (user_id,)
        ).fetchone()
        return self._decode_tfa_secret(row['tfa_secret_enc']) if row else ''

    def set_user_tfa_enrollment(self, user_id: int, secret_b32: str,
                                backup_codes_plain: list[str], method: str = 'totp') -> bool:
        secret_enc = self._encode_tfa_secret(secret_b32)
        if not secret_enc:
            return False
        code_hashes = []
        for code in (backup_codes_plain or []):
            norm = re.sub(r'[^A-Za-z0-9]', '', (code or '')).upper()
            if not norm:
                continue
            salt = secrets.token_hex(8)
            code_hashes.append(f'v2${salt}${_tfa_hash_backup_code(norm, salt=salt)}')
        now = self._ts()
        self._conn().execute(
            '''UPDATE users
               SET tfa_enabled=1, tfa_method=?, tfa_enrolled_at=?, tfa_secret_enc=?, tfa_secret_ver=1,
                   tfa_backup_codes_hash=?, tfa_backup_codes_remaining=?, tfa_last_verified_at=?, tfa_last_counter=-1, tfa_recovery_locked=0
               WHERE id=?''',
            (method[:20], now, secret_enc, json.dumps(code_hashes), len(code_hashes), now, user_id)
        )
        self._conn().commit()
        self.record_tfa_recovery_event(user_id, 'system', 'enroll_finish', f'method={method}', '')
        return True

    def touch_user_tfa_verified(self, user_id: int):
        self._conn().execute(
            'UPDATE users SET tfa_last_verified_at=? WHERE id=?',
            (self._ts(), user_id)
        )
        self._conn().commit()

    def clear_user_tfa(self, user_id: int, actor: str = 'system', detail: str = ''):
        c = self._conn()
        c.execute(
            '''UPDATE users
               SET tfa_enabled=0, tfa_method='', tfa_enrolled_at=NULL, tfa_secret_enc='', tfa_secret_ver=0,
                   tfa_backup_codes_hash='', tfa_backup_codes_remaining=0, tfa_last_verified_at=NULL, tfa_last_counter=-1, tfa_recovery_locked=0
               WHERE id=?''',
            (user_id,)
        )
        c.execute('DELETE FROM tfa_challenges WHERE user_id=?', (user_id,))
        c.commit()
        self.record_tfa_recovery_event(user_id, actor, 'admin_reset', detail[:255], '')

    def verify_and_consume_tfa_backup_code(self, user_id: int, code: str) -> bool:
        norm = re.sub(r'[^A-Za-z0-9]', '', (code or '')).upper()
        if not norm:
            return False
        c = self._conn()
        row = c.execute(
            'SELECT tfa_backup_codes_hash,tfa_backup_codes_remaining FROM users WHERE id=?',
            (user_id,)
        ).fetchone()
        if not row:
            return False
        try:
            hashes = json.loads(row['tfa_backup_codes_hash'] or '[]')
        except Exception:
            hashes = []
        match_index = -1
        for idx, stored in enumerate(hashes):
            s = str(stored or '').strip()
            candidate = ''
            expected = ''
            if s.startswith('v2$'):
                parts = s.split('$', 2)
                if len(parts) == 3:
                    salt = parts[1]
                    expected = parts[2]
                    candidate = _tfa_hash_backup_code(norm, salt=salt)
            else:
                expected = s
                candidate = _tfa_hash_backup_code(norm)
            if expected and candidate and hmac.compare_digest(candidate, expected) and match_index < 0:
                match_index = idx
        if match_index < 0:
            return False
        hashes = [h for i, h in enumerate(hashes) if i != match_index]
        c.execute(
            'UPDATE users SET tfa_backup_codes_hash=?, tfa_backup_codes_remaining=?, tfa_last_verified_at=? WHERE id=?',
            (json.dumps(hashes), len(hashes), self._ts(), user_id)
        )
        c.commit()
        self.record_tfa_recovery_event(user_id, 'self', 'backup_code_used', '', '')
        return True

    def record_tfa_recovery_event(self, user_id: int, actor: str, action: str,
                                  detail: str = '', ip: str = ''):
        self._conn().execute(
            'INSERT INTO tfa_recovery_events (user_id,actor,action,detail,ip,created_at) VALUES (?,?,?,?,?,?)',
            (user_id, (actor or 'system')[:64], (action or 'event')[:48], (detail or '')[:255], (ip or '')[:64], self._ts())
        )
        self._conn().commit()

    def create_tfa_challenge(self, user_id: int, flow_type: str = 'login',
                             ttl_seconds: int = TFA_CHALLENGE_TTL_SECONDS,
                             client_ip: str = '', user_agent: str = '') -> tuple[int, str]:
        token = secrets.token_urlsafe(24)
        now_dt = datetime.datetime.now()
        now = now_dt.isoformat(timespec='seconds')
        ttl = max(60, min(1800, int(ttl_seconds)))
        exp = (now_dt + datetime.timedelta(seconds=ttl)).isoformat(timespec='seconds')
        cur = self._conn().execute(
            '''INSERT INTO tfa_challenges
               (user_id,flow_type,challenge_token,created_at,expires_at,client_ip,user_agent)
               VALUES (?,?,?,?,?,?,?)''',
            (user_id, flow_type[:20], token, now, exp, client_ip[:64], user_agent[:255])
        )
        self._conn().commit()
        return int(cur.lastrowid), token

    def get_tfa_challenge_wait_seconds(self, challenge_id: int) -> int:
        row = self._conn().execute(
            'SELECT blocked_until FROM tfa_challenges WHERE id=? AND used_at IS NULL',
            (challenge_id,)
        ).fetchone()
        if not row:
            return 0
        return _seconds_until_iso(row['blocked_until'] or '')

    def register_tfa_challenge_failure(self, challenge_id: int) -> tuple[int, int]:
        c = self._conn()
        row = c.execute(
            'SELECT auth_attempts FROM tfa_challenges WHERE id=? AND used_at IS NULL',
            (challenge_id,)
        ).fetchone()
        if not row:
            return 0, 0
        attempts = int(row['auth_attempts'] or 0) + 1
        wait = min(TFA_CHALLENGE_BACKOFF_MAX_SECONDS,
                   TFA_CHALLENGE_BACKOFF_BASE_SECONDS * (2 ** max(0, attempts - 1)))
        blocked_until = (datetime.datetime.now() + datetime.timedelta(seconds=wait)).isoformat(timespec='seconds')
        c.execute(
            'UPDATE tfa_challenges SET auth_attempts=?, last_attempt_at=?, blocked_until=? WHERE id=?',
            (attempts, self._ts(), blocked_until, challenge_id)
        )
        c.commit()
        return attempts, wait

    def clear_tfa_challenge_failures(self, challenge_id: int):
        self._conn().execute(
            'UPDATE tfa_challenges SET auth_attempts=0, last_attempt_at=NULL, blocked_until=NULL WHERE id=?',
            (challenge_id,)
        )
        self._conn().commit()

