    # ── Comments ──────────────────────────────────────────────

    def add_comment(self, info_hash: str, user_id: int, username: str,
                    body: str, parent_id: int | None = None) -> int:
        c = self._conn()
        cur = c.execute(
            'INSERT INTO comments (info_hash,user_id,username,parent_id,body,created_at)'
            ' VALUES (?,?,?,?,?,?)',
            (info_hash.upper(), user_id, username, parent_id, body, self._ts())
        )
        c.commit()
        return cur.lastrowid

    def get_comments(self, info_hash: str) -> list:
        return self._conn().execute(
            'SELECT * FROM comments WHERE info_hash=? ORDER BY id ASC',
            (info_hash.upper(),)
        ).fetchall()

    def get_comment(self, comment_id: int):
        return self._conn().execute(
            'SELECT * FROM comments WHERE id=?', (comment_id,)
        ).fetchone()

    def edit_comment(self, comment_id: int, user_id: int, body: str, is_admin: bool) -> bool:
        row = self.get_comment(comment_id)
        if not row or row['is_deleted']:
            return False
        if not is_admin and row['user_id'] != user_id:
            return False
        self._conn().execute(
            'UPDATE comments SET body=?, edited_at=? WHERE id=?',
            (body, self._ts(), comment_id)
        )
        self._conn().commit()
        return True

    def delete_comment(self, comment_id: int, user_id: int, is_admin: bool) -> bool:
        row = self.get_comment(comment_id)
        if not row:
            return False
        if not is_admin and row['user_id'] != user_id:
            return False
        parent_id = row['parent_id']
        # Hard delete if no replies exist, soft delete if replies must be preserved
        has_replies = self._conn().execute(
            'SELECT COUNT(*) FROM comments WHERE parent_id=?', (comment_id,)
        ).fetchone()[0]
        if has_replies:
            self._conn().execute(
                'UPDATE comments SET is_deleted=1, body=? WHERE id=?',
                ('[deleted]', comment_id)
            )
        else:
            self._conn().execute('DELETE FROM comments WHERE id=?', (comment_id,))
            # If this was a reply, check if the parent is a soft-deleted comment
            # with no remaining replies — if so, clean it up too
            if parent_id:
                parent = self.get_comment(parent_id)
                if parent and parent['is_deleted']:
                    remaining = self._conn().execute(
                        'SELECT COUNT(*) FROM comments WHERE parent_id=?', (parent_id,)
                    ).fetchone()[0]
                    if not remaining:
                        self._conn().execute(
                            'DELETE FROM comments WHERE id=?', (parent_id,)
                        )
        self._conn().commit()
        return True

    # ── Notifications ──────────────────────────────────────────

    def add_notification(self, user_id: int, ntype: str, from_username: str,
                         info_hash: str, torrent_name: str, comment_id: int):
        c = self._conn()
        c.execute(
            'INSERT INTO notifications'
            ' (user_id,type,from_username,info_hash,torrent_name,comment_id,created_at)'
            ' VALUES (?,?,?,?,?,?,?)',
            (user_id, ntype, from_username, info_hash.upper(),
             torrent_name, comment_id, self._ts())
        )
        c.commit()
        # Prune to 100 per user
        c.execute(
            'DELETE FROM notifications WHERE user_id=? AND id NOT IN'
            ' (SELECT id FROM notifications WHERE user_id=? ORDER BY id DESC LIMIT 100)',
            (user_id, user_id)
        )
        c.commit()

    def notify_followed_user_new_follower(self, followed_user_id: int,
                                          follower_user_id: int,
                                          follower_username: str) -> None:
        self.add_notification(
            followed_user_id, 'follow_new_follower', follower_username,
            'FOLLOW:USER', 'started following you', follower_user_id
        )

    def notify_followers_torrent_upload(self, actor_user_id: int,
                                        actor_username: str,
                                        info_hash: str,
                                        torrent_name: str) -> int:
        follower_ids = self.list_follower_user_ids(actor_user_id)
        sent = 0
        for fid in follower_ids:
            if fid == actor_user_id:
                continue
            self.add_notification(
                fid, 'followed_upload', actor_username, info_hash, torrent_name, 0
            )
            sent += 1
        return sent

    def notify_torrent_vote(self, recipient_user_id: int, voter_username: str,
                            info_hash: str, torrent_name: str, vote: int) -> None:
        ntype = 'torrent_vote_up' if int(vote) > 0 else 'torrent_vote_down'
        self.add_notification(
            recipient_user_id, ntype, voter_username, info_hash.upper(), torrent_name, 0
        )

    def notify_comment_vote(self, recipient_user_id: int, voter_username: str,
                            info_hash: str, torrent_name: str, comment_id: int,
                            vote: int) -> None:
        ntype = 'comment_vote_up' if int(vote) > 0 else 'comment_vote_down'
        self.add_notification(
            recipient_user_id, ntype, voter_username, info_hash.upper(),
            torrent_name, int(comment_id)
        )

    def notify_magnet_job_success(self, recipient_user_id: int, actor_username: str,
                                  info_hash: str, torrent_name: str, job_id: int) -> None:
        self.add_notification(
            int(recipient_user_id), 'magnet_job_done', actor_username,
            str(info_hash or '').upper(), str(torrent_name or '')[:120], int(job_id)
        )

    def notify_magnet_job_failure(self, recipient_user_id: int, actor_username: str,
                                  job_id: int, detail: str, info_hash: str = '') -> None:
        ih = str(info_hash or '').strip().upper()
        detail_text = str(detail or 'Magnet job failed.')
        if re.fullmatch(r'[A-F0-9]{40}', ih):
            detail_text = f'{detail_text} (IH: {ih})'
        self.add_notification(
            int(recipient_user_id), 'magnet_job_failed', actor_username,
            f'MAGNET:{int(job_id)}', detail_text[:200], int(job_id)
        )

    def _metadata_proposal_recipient_user_ids(self, info_hash: str) -> list[int]:
        ih = (info_hash or '').strip().upper()
        if not ih:
            return []
        t = self.get_torrent(ih)
        owner_id = int(t['uploaded_by_id'] or 0) if t else 0
        return [owner_id] if owner_id > 0 else []

    def notify_metadata_proposed(self, proposal_id: int, actor_username: str) -> int:
        p = self.get_metadata_proposal(int(proposal_id))
        if not p:
            return 0
        t = self.get_torrent(str(p['info_hash'] or '').upper())
        tname = (t['name'][:120] if t else str(p['info_hash'] or '')[:120])
        sent = 0
        for uid in self._metadata_proposal_recipient_user_ids(str(p['info_hash'] or '')):
            if uid == int(p['proposed_by_user_id'] or 0):
                continue
            self.add_notification(
                uid, 'metadata_proposed', actor_username,
                str(p['info_hash'] or ''), tname, int(proposal_id)
            )
            sent += 1
        return sent

    def notify_metadata_decision(self, proposal_id: int, decision_type: str,
                                 actor_username: str) -> int:
        p = self.get_metadata_proposal(int(proposal_id))
        if not p:
            return 0
        ntype = {
            'approved': 'metadata_approved',
            'rejected': 'metadata_rejected',
            'expired': 'metadata_rejected',
            'revoked': 'metadata_revoked',
        }.get((decision_type or '').strip().lower())
        if not ntype:
            return 0
        t = self.get_torrent(str(p['info_hash'] or '').upper())
        tname = (t['name'][:120] if t else str(p['info_hash'] or '')[:120])
        actor_uid = 0
        if (actor_username or '').strip().lower() != 'system':
            a = self.get_user(actor_username)
            actor_uid = int(a['id'] or 0) if a else 0
        recipients = {
            int(p['proposed_by_user_id'] or 0),
            int(t['uploaded_by_id'] or 0) if t else 0,
        }
        sent = 0
        for uid in recipients:
            if uid <= 0:
                continue
            if actor_uid > 0 and uid == actor_uid:
                continue
            self.add_notification(
                uid, ntype, actor_username,
                str(p['info_hash'] or ''), tname, int(proposal_id)
            )
            sent += 1
        return sent

    def notify_followers_bounty_fulfilled(self, actor_username: str,
                                          bounty_id: int,
                                          description: str) -> int:
        actor = self.get_user(actor_username)
        if not actor:
            return 0
        follower_ids = self.list_follower_user_ids(actor['id'])
        sent = 0
        for fid in follower_ids:
            if fid == actor['id']:
                continue
            self._conn().execute(
                'INSERT INTO notifications (user_id,type,from_username,info_hash,torrent_name,'
                'comment_id,created_at,is_read) VALUES (?,?,?,?,?,?,?,0)',
                (fid, 'followed_bounty_fulfilled', actor_username,
                 f'BOUNTY:{bounty_id}', description[:120], 0, self._ts())
            )
            sent += 1
        if sent:
            self._conn().commit()
        return sent

