    def _get_dashboard(self):
        user = self._get_session_user()
        log.debug('DASHBOARD session_found=%s', user is not None)
        if not user:
            return self._redirect('/manage')
        role    = _user_role(user)
        per_page = int(REGISTRATION_DB.get_setting('torrents_per_page', '50'))
        page     = _get_page_param(self.path)
        qs = urllib.parse.parse_qs(urllib.parse.urlparse(self.path).query)
        facets = _parse_torrent_facets_from_qs(qs)
        uid      = None if role in ('super', 'admin', 'editor', 'standard') else user['id']
        blocked_ids: list[int] = []
        if role not in ('super', 'admin'):
            blocked_rows = REGISTRATION_DB.list_blocked_uploaders(int(user['id']), limit=1000)
            blocked_ids = [int(r['id']) for r in blocked_rows if int(r['id'] or 0) > 0]
        total = REGISTRATION_DB.count_torrents(
            user_id=uid, facets=facets,
            exclude_uploader_ids=blocked_ids
        )
        torrents = REGISTRATION_DB.list_torrents(
            user_id=uid, page=page, per_page=per_page, facets=facets,
            exclude_uploader_ids=blocked_ids
        )
        total_pages = max(1, (total + per_page - 1) // per_page)
        page = min(page, total_pages)
        msg = urllib.parse.unquote(qs.get('msg', [''])[0])
        msg_type = qs.get('msg_type', ['info'])[0]
        self._send_html(_render_dashboard(user, torrents, page=page,
                                          total_pages=total_pages, total=total,
                                          msg=msg, msg_type=msg_type,
                                          facets=facets))

    def _get_admin(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        is_super = user['username'] == SUPER_USER
        if not (user['is_admin'] or is_super):
            return self._redirect('/manage/dashboard')
        qs           = urllib.parse.parse_qs(urllib.parse.urlparse(self.path).query)
        per_page     = int(REGISTRATION_DB.get_setting('torrents_per_page', '50'))
        # torrent pagination
        page         = _get_page_param(self.path)
        total        = REGISTRATION_DB.count_torrents()
        all_torrents = REGISTRATION_DB.list_torrents(page=page, per_page=per_page)
        total_pages  = max(1, (total + per_page - 1) // per_page)
        page         = min(page, total_pages)
        # user pagination + search
        uquery       = qs.get('uq', [''])[0].strip()
        upage        = _get_named_page_param(self.path, 'upage')
        users_pp     = 50
        if uquery:
            utotal   = REGISTRATION_DB.count_search_users(uquery)
            all_users = REGISTRATION_DB.search_users(uquery, page=upage, per_page=users_pp)
        else:
            utotal   = REGISTRATION_DB.count_users()
            all_users = REGISTRATION_DB.list_users(page=upage, per_page=users_pp)
        utotal_pages = max(1, (utotal + users_pp - 1) // users_pp)
        upage        = min(upage, utotal_pages)
        # event log pagination + search
        epage        = _get_named_page_param(self.path, 'epage')
        events_pp    = 50
        e_q_any      = qs.get('eq', [''])[0].strip()
        e_q_actor    = qs.get('eactor', [''])[0].strip()
        e_q_action   = qs.get('eaction', [''])[0].strip()
        e_q_target   = qs.get('etarget', [''])[0].strip()
        events, ev_total = REGISTRATION_DB.list_events(
            limit=events_pp,
            offset=(epage - 1) * events_pp,
            q_any=e_q_any,
            q_actor=e_q_actor,
            q_action=e_q_action,
            q_target=e_q_target,
        )
        ev_total_pages = max(1, (ev_total + events_pp - 1) // events_pp)
        if epage > ev_total_pages:
            epage = ev_total_pages
            events, ev_total = REGISTRATION_DB.list_events(
                limit=events_pp,
                offset=(epage - 1) * events_pp,
                q_any=e_q_any,
                q_actor=e_q_actor,
                q_action=e_q_action,
                q_target=e_q_target,
            )
        # security log pagination + search
        spage = _get_named_page_param(self.path, 'spage')
        security_pp = 50
        s_view = qs.get('sview', ['events'])[0].strip().lower()
        if s_view not in ('events', 'bans'):
            s_view = 'events'
        s_trigger = qs.get('strigger', [''])[0].strip()
        s_status = qs.get('sstatus', [''])[0].strip()
        s_ip = qs.get('sip', [''])[0].strip()
        security_bans = []
        if s_view == 'bans':
            security_events = []
            security_bans, security_total = REGISTRATION_DB.security_list_bans(
                state='active', q_ip=s_ip,
                limit=security_pp,
                offset=(spage - 1) * security_pp,
            )
        else:
            security_events, security_total = REGISTRATION_DB.security_list_events(
                limit=security_pp,
                offset=(spage - 1) * security_pp,
                q_trigger=s_trigger,
                q_status=s_status,
                q_ip=s_ip,
            )
        security_total_pages = max(1, (security_total + security_pp - 1) // security_pp)
        if spage > security_total_pages:
            spage = security_total_pages
            if s_view == 'bans':
                security_bans, security_total = REGISTRATION_DB.security_list_bans(
                    state='active', q_ip=s_ip,
                    limit=security_pp,
                    offset=(spage - 1) * security_pp,
                )
            else:
                security_events, security_total = REGISTRATION_DB.security_list_events(
                    limit=security_pp,
                    offset=(spage - 1) * security_pp,
                    q_trigger=s_trigger,
                    q_status=s_status,
                    q_ip=s_ip,
                )
        # report queue pagination + search
        rpage = _get_named_page_param(self.path, 'rpage')
        reports_pp = 50
        r_status = qs.get('rstatus', [''])[0].strip()
        r_severity = qs.get('rseverity', [''])[0].strip()
        r_reason = qs.get('rreason', [''])[0].strip()
        r_reporter = qs.get('rreporter', [''])[0].strip()
        r_info_hash = qs.get('rih', [''])[0].strip()
        r_owner = qs.get('rowner', [''])[0].strip()
        reports, reports_total = REGISTRATION_DB.list_torrent_reports(
            limit=reports_pp,
            offset=(rpage - 1) * reports_pp,
            q_status=r_status,
            q_severity=r_severity,
            q_reason=r_reason,
            q_reporter=r_reporter,
            q_info_hash=r_info_hash,
            q_owner=r_owner,
        )
        reports_total_pages = max(1, (reports_total + reports_pp - 1) // reports_pp)
        if rpage > reports_total_pages:
            rpage = reports_total_pages
            reports, reports_total = REGISTRATION_DB.list_torrent_reports(
                limit=reports_pp,
                offset=(rpage - 1) * reports_pp,
                q_status=r_status,
                q_severity=r_severity,
                q_reason=r_reason,
                q_reporter=r_reporter,
                q_info_hash=r_info_hash,
                q_owner=r_owner,
            )
        # wild intake reports pagination + search
        wpage = _get_named_page_param(self.path, 'wpage')
        wild_pp = 50
        w_status = qs.get('wstatus', [''])[0].strip().lower()
        w_query = qs.get('wq', [''])[0].strip()
        wild_reports, wild_total = REGISTRATION_DB.list_wild_intake_reports(
            limit=wild_pp,
            offset=(wpage - 1) * wild_pp,
            q_status=w_status,
            q_search=w_query,
        )
        wild_total_pages = max(1, (wild_total + wild_pp - 1) // wild_pp)
        if wpage > wild_total_pages:
            wpage = wild_total_pages
            wild_reports, wild_total = REGISTRATION_DB.list_wild_intake_reports(
                limit=wild_pp,
                offset=(wpage - 1) * wild_pp,
                q_status=w_status,
                q_search=w_query,
            )
        trackers     = REGISTRATION_DB.list_magnet_trackers()
        settings     = REGISTRATION_DB.get_all_settings()
        msg      = urllib.parse.unquote(qs.get('msg',      [''])[0])
        msg_type = qs.get('msg_type', ['error'])[0]
        tab      = qs.get('tab',      [''])[0]
        if not tab:
            # Keep Add User context if a create/validation message is present but tab was lost.
            if qs.get('new_username', [''])[0]:
                tab = 'adduser'
            elif msg.startswith('User ') and ' created as ' in msg:
                tab = 'adduser'
            elif qs.get('strigger', [''])[0] or qs.get('sstatus', [''])[0] or qs.get('sip', [''])[0] or qs.get('sview', [''])[0]:
                tab = 'security'
            elif (qs.get('rstatus', [''])[0] or qs.get('rseverity', [''])[0] or qs.get('rreason', [''])[0]
                  or qs.get('rreporter', [''])[0] or qs.get('rih', [''])[0] or qs.get('rowner', [''])[0]):
                tab = 'reports'
            elif qs.get('wstatus', [''])[0] or qs.get('wq', [''])[0]:
                tab = 'wild-intake'
        self._send_html(_render_admin(user, all_torrents, all_users, events, trackers, settings,
                                      page=page, total_pages=total_pages, total=total,
                                      upage=upage, utotal_pages=utotal_pages, utotal=utotal,
                                      epage=epage, ev_total_pages=ev_total_pages, events_pp=events_pp,
                                      uquery=uquery, msg=msg, msg_type=msg_type, tab=tab,
                                      new_username=urllib.parse.unquote(qs.get('new_username',[''])[0]),
                                      ev_total=ev_total,
                                      eq=qs.get('eq', [''])[0],
                                      eactor=qs.get('eactor', [''])[0],
                                      eaction=qs.get('eaction', [''])[0],
                                      etarget=qs.get('etarget', [''])[0],
                                      security_events=security_events,
                                      security_bans=security_bans,
                                      spage=spage,
                                      security_total_pages=security_total_pages,
                                      security_total=security_total,
                                      security_pp=security_pp,
                                      strigger=s_trigger,
                                      sstatus=s_status,
                                      sip=s_ip,
                                      sview=s_view,
                                      reports=reports,
                                      rpage=rpage,
                                      reports_total_pages=reports_total_pages,
                                      reports_total=reports_total,
                                      reports_pp=reports_pp,
                                      rstatus=r_status,
                                      rseverity=r_severity,
                                      rreason=r_reason,
                                      rreporter=r_reporter,
                                      rih=r_info_hash,
                                      rowner=r_owner,
                                      wild_reports=wild_reports,
                                      wpage=wpage,
                                      wild_total_pages=wild_total_pages,
                                      wild_total=wild_total,
                                      wild_pp=wild_pp,
                                      wstatus=w_status,
                                      wq=w_query))

    def _get_admin_event_detail(self, event_id_raw: str):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        is_super = user['username'] == SUPER_USER
        if not (user['is_admin'] or is_super):
            return self._redirect('/manage/dashboard')
        event_id_str = (event_id_raw or '').strip('/')
        if not event_id_str.isdigit():
            return self._redirect('/manage/admin?tab=events&msg=Invalid+event+id.&msg_type=error')
        event_id = int(event_id_str)
        event = REGISTRATION_DB.get_event(event_id)
        if not event:
            return self._redirect('/manage/admin?tab=events&msg=Event+not+found.&msg_type=error')
        qs = urllib.parse.parse_qs(urllib.parse.urlparse(self.path).query)
        back = urllib.parse.unquote(qs.get('back', [''])[0]).strip()
        if not back.startswith('/manage/admin'):
            back = '/manage/admin?tab=events'
        self._send_html(_render_admin_event_detail(user, event, back_url=back))

    def _get_admin_security_event_detail(self, event_id_raw: str):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        is_super = user['username'] == SUPER_USER
        if not (user['is_admin'] or is_super):
            return self._redirect('/manage/dashboard')
        event_id_str = (event_id_raw or '').strip('/')
        if not event_id_str.isdigit():
            return self._redirect('/manage/admin?tab=security&msg=Invalid+security+event+id.&msg_type=error')
        event_id = int(event_id_str)
        event = REGISTRATION_DB.security_get_event(event_id)
        if not event:
            return self._redirect('/manage/admin?tab=security&msg=Security+event+not+found.&msg_type=error')
        ban = REGISTRATION_DB.security_get_ban(int(event['ban_id'])) if event.get('ban_id') else None
        actions = REGISTRATION_DB.security_list_actions(event_id=event_id, limit=300)
        qs = urllib.parse.parse_qs(urllib.parse.urlparse(self.path).query)
        back = urllib.parse.unquote(qs.get('back', [''])[0]).strip()
        if not back.startswith('/manage/admin'):
            back = '/manage/admin?tab=security'
        msg = urllib.parse.unquote(qs.get('msg', [''])[0])
        msg_type = qs.get('msg_type', ['error'])[0]
        self._send_html(_render_admin_security_event_detail(
            user, event, ban, actions, back_url=back, msg=msg, msg_type=msg_type
        ))

    def _editor_can_review_report(self, user, report: dict | None) -> bool:
        if not user or not report:
            return False
        if _user_role(user) != 'editor':
            return False
        return str(report.get('reason') or '') == 'bad_metadata'

    def _get_admin_report_detail(self, report_id_raw: str):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        role = _user_role(user)
        if role not in ('super', 'admin', 'editor'):
            return self._redirect('/manage/dashboard')
        report_id_str = (report_id_raw or '').strip('/')
        if not report_id_str.isdigit():
            if role == 'editor':
                return self._redirect('/manage/dashboard')
            return self._redirect('/manage/admin?tab=reports&msg=Invalid+report+id.&msg_type=error')
        report_id = int(report_id_str)
        report = REGISTRATION_DB.get_torrent_report(report_id)
        if not report:
            if role == 'editor':
                return self._redirect('/manage/dashboard')
            return self._redirect('/manage/admin?tab=reports&msg=Report+not+found.&msg_type=error')
        if role == 'editor' and not self._editor_can_review_report(user, report):
            q = urllib.parse.quote_plus('Editors may only review bad metadata reports.')
            return self._redirect(f'/manage/dashboard?msg={q}&msg_type=error')
        actions = REGISTRATION_DB.list_torrent_report_actions(report_id, limit=300)
        moderators = REGISTRATION_DB.list_report_editors() if role == 'editor' else REGISTRATION_DB.list_report_moderators()
        qs = urllib.parse.parse_qs(urllib.parse.urlparse(self.path).query)
        back = urllib.parse.unquote(qs.get('back', [''])[0]).strip()
        if role == 'editor':
            back = '/manage/dashboard'
        elif not back.startswith('/manage/admin'):
            back = '/manage/admin?tab=reports'
        msg = urllib.parse.unquote(qs.get('msg', [''])[0])
        msg_type = qs.get('msg_type', ['error'])[0]
        active_token = self._current_valid_session_token()
        active_csrf = _csrf_token(active_token) if active_token else ''
        self._send_html(_render_admin_report_detail(
            user, report, actions, moderators, back_url=back, msg=msg, msg_type=msg_type,
            csrf_token=active_csrf
        ))

