    def _post_admin_security_action(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        is_super = user['username'] == SUPER_USER
        if not (user['is_admin'] or is_super):
            return self._redirect('/manage/dashboard')
        body = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        action = (fields.get('action', '') or '').strip()
        try:
            event_id = int(fields.get('event_id', '0'))
        except Exception:
            event_id = 0
        if event_id <= 0:
            return self._redirect('/manage/admin?tab=security&msg=Missing+security+event+id.&msg_type=error')
        event = REGISTRATION_DB.security_get_event(event_id)
        if not event:
            return self._redirect('/manage/admin?tab=security&msg=Security+event+not+found.&msg_type=error')
        if action == 'clear_ban':
            try:
                ban_id = int(fields.get('ban_id', '0'))
            except Exception:
                ban_id = 0
            if ban_id <= 0:
                ban_id = int(event.get('ban_id') or 0)
            clear_reason = (fields.get('clear_reason', '') or '').strip()[:240]
            if ban_id <= 0:
                return self._redirect(f'/manage/admin/security/event/{event_id}?msg=No+linked+ban+found.&msg_type=error')
            ban_row = REGISTRATION_DB.security_get_ban(ban_id)
            if not ban_row:
                return self._redirect(f'/manage/admin/security/event/{event_id}?msg=Ban+record+not+found.&msg_type=error')
            if str(ban_row.get('firewall_backend') or '') == 'system_fw':
                fw_ok, fw_detail = _security_firewall_run(
                    'clear',
                    str(ban_row.get('ip') or ''),
                    ban_id=ban_id,
                    reason=(clear_reason or 'admin_clear')
                )
                if not fw_ok:
                    q = urllib.parse.quote_plus(f'Firewall clear failed: {fw_detail}')
                    return self._redirect(f'/manage/admin/security/event/{event_id}?msg={q}&msg_type=error')
            ok = REGISTRATION_DB.security_clear_ban(ban_id, user['username'], clear_reason)
            if not ok:
                return self._redirect(f'/manage/admin/security/event/{event_id}?msg=Ban+already+cleared+or+missing.&msg_type=error')
            REGISTRATION_DB.security_add_action(
                event_id=event_id,
                ban_id=ban_id,
                action_type='manual_clear_ban',
                actor=user['username'],
                detail=clear_reason or 'manual clear from admin security view'
            )
            return self._redirect(f'/manage/admin/security/event/{event_id}?msg=Ban+cleared.&msg_type=success')
        if action == 'disable_member':
            uid = int(event.get('member_user_id') or 0)
            if uid <= 0:
                return self._redirect(f'/manage/admin/security/event/{event_id}?msg=No+member+attribution+for+this+event.&msg_type=error')
            if not REGISTRATION_DB.security_disable_user_by_id(uid, user['username'], f'security_event_id={event_id} manual_disable=1'):
                return self._redirect(f'/manage/admin/security/event/{event_id}?msg=Unable+to+disable+account.&msg_type=error')
            REGISTRATION_DB.security_add_action(
                event_id=event_id,
                ban_id=int(event.get('ban_id') or 0) or None,
                action_type='manual_disable_member',
                actor=user['username'],
                detail=f'user_id={uid}'
            )
            return self._redirect(f'/manage/admin/security/event/{event_id}?msg=Attributed+member+disabled.&msg_type=success')
        if action == 'enable_member':
            uid = int(event.get('member_user_id') or 0)
            if uid <= 0:
                return self._redirect(f'/manage/admin/security/event/{event_id}?msg=No+member+attribution+for+this+event.&msg_type=error')
            if not REGISTRATION_DB.security_enable_user_by_id(uid, user['username'], f'security_event_id={event_id} manual_enable=1'):
                return self._redirect(f'/manage/admin/security/event/{event_id}?msg=Unable+to+enable+account.&msg_type=error')
            REGISTRATION_DB.security_add_action(
                event_id=event_id,
                ban_id=int(event.get('ban_id') or 0) or None,
                action_type='manual_enable_member',
                actor=user['username'],
                detail=f'user_id={uid}'
            )
            return self._redirect(f'/manage/admin/security/event/{event_id}?msg=Attributed+member+enabled.&msg_type=success')
        if action == 'close_event':
            if not REGISTRATION_DB.security_close_event(event_id, user['username']):
                return self._redirect(f'/manage/admin/security/event/{event_id}?msg=Unable+to+resolve+security+event.&msg_type=error')
            return self._redirect(f'/manage/admin/security/event/{event_id}?msg=Security+event+marked+resolved.&msg_type=success')
        return self._redirect(f'/manage/admin/security/event/{event_id}?msg=Unknown+security+action.&msg_type=error')

    def _post_admin_report_action(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        role = _user_role(user)
        if role not in ('super', 'admin', 'editor'):
            return self._redirect('/manage/dashboard')
        body = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        try:
            report_id = int(fields.get('report_id', '0'))
        except Exception:
            report_id = 0
        action = (fields.get('action', '') or '').strip().lower()
        note = (fields.get('note', '') or '').strip()
        try:
            assign_uid = int(fields.get('assign_user_id', '0') or 0)
        except Exception:
            assign_uid = 0
        if report_id <= 0:
            if role == 'editor':
                return self._redirect('/manage/dashboard')
            return self._redirect('/manage/admin?tab=reports&msg=Missing+report+id.&msg_type=error')
        if role == 'editor':
            report = REGISTRATION_DB.get_torrent_report(report_id)
            if not self._editor_can_review_report(user, report):
                q = urllib.parse.quote_plus('Editors may only review bad metadata reports.')
                return self._redirect(f'/manage/dashboard?msg={q}&msg_type=error')
            if action == 'assign':
                assignee = REGISTRATION_DB.get_user_by_id(assign_uid) if assign_uid > 0 else None
                if not assignee or int(assignee['is_editor'] if 'is_editor' in assignee.keys() else 0) != 1:
                    q = urllib.parse.quote_plus('Editors can only assign reports to editors.')
                    return self._redirect(f'/manage/admin/report/{report_id}?msg={q}&msg_type=error')
        ok, msg = REGISTRATION_DB.apply_torrent_report_action(
            report_id, int(user['id']), user['username'], action, note=note, assign_user_id=assign_uid
        )
        if ok and action in ('open', 'in_review', 'resolved', 'dismissed', 'assign', 'unassign'):
            try:
                REGISTRATION_DB.notify_torrent_report_update(report_id, user['username'], update_label=action)
            except sqlite3.OperationalError as e:
                if 'locked' in str(e).lower():
                    log.warning('notify_torrent_report_update failed (non-fatal): report_id=%s err=%s', report_id, e)
                else:
                    raise
        elif ok and action == 'note':
            try:
                REGISTRATION_DB.notify_torrent_report_note_assignee(report_id, user['username'])
            except sqlite3.OperationalError as e:
                if 'locked' in str(e).lower():
                    log.warning('notify_torrent_report_note_assignee failed (non-fatal): report_id=%s err=%s', report_id, e)
                else:
                    raise
        q = urllib.parse.quote_plus(msg)
        return self._redirect(f'/manage/admin/report/{report_id}?msg={q}&msg_type={"success" if ok else "error"}')

    def _post_admin_wild_intake_action(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        role = _user_role(user)
        if role not in ('super', 'admin'):
            return self._redirect('/manage/dashboard')
        body = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        if not self._check_csrf(fields):
            return self._redirect('/manage?msg=csrf')
        info_hash = (fields.get('info_hash', '') or '').strip().upper()
        action = (fields.get('action', '') or '').strip().lower()
        note = (fields.get('note', '') or '').strip()
        reason = (fields.get('reason', '') or '').strip()
        from_report_id = (fields.get('from_report_id', '') or '').strip()
        back = self._safe_manage_redirect(
            fields.get('back', ''),
            fallback='/manage/admin?tab=wild-intake',
            allowed_prefixes=('/manage/admin',)
        )
        ok, msg = REGISTRATION_DB.apply_wild_intake_action(
            info_hash, int(user['id']), user['username'],
            action, note=note, reason=reason
        )
        q = urllib.parse.quote_plus(msg)
        if from_report_id.isdigit():
            return self._redirect(
                f'/manage/admin/report/{int(from_report_id)}?msg={q}&msg_type={"success" if ok else "error"}'
            )
        if back.startswith('/manage/admin'):
            sep = '&' if '?' in back else '?'
            return self._redirect(f'{back}{sep}msg={q}&msg_type={"success" if ok else "error"}')
        if re.fullmatch(r'[A-F0-9]{40}', info_hash):
            return self._redirect(f'/manage/admin/wild-intake/{info_hash}?msg={q}&msg_type={"success" if ok else "error"}')
        return self._redirect(f'/manage/admin?tab=wild-intake&msg={q}&msg_type={"success" if ok else "error"}')

