    def _get_tfa_challenge(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        if not _tfa_login_enabled():
            return self._redirect('/manage/dashboard')
        token = self._current_valid_session_token()
        pending_id = REGISTRATION_DB.get_session_pending_tfa_challenge_id(token) if token else 0
        ch = REGISTRATION_DB.get_tfa_challenge_by_id(pending_id, 'login') if pending_id else None
        if not ch:
            if token and REGISTRATION_DB.session_primary_auth_ok(token):
                REGISTRATION_DB.set_session_pending_tfa_challenge(token, None)
                return self._redirect('/manage/dashboard')
            if token:
                ttl_sec = int(REGISTRATION_DB.get_setting('tfa_challenge_ttl_sec', str(TFA_CHALLENGE_TTL_SECONDS)) or TFA_CHALLENGE_TTL_SECONDS)
                new_id, _ = REGISTRATION_DB.create_tfa_challenge(
                    int(user['id']),
                    flow_type='login',
                    ttl_seconds=ttl_sec,
                    client_ip=self.client_address[0] if self.client_address else '',
                    user_agent=self.headers.get('User-Agent', '')
                )
                REGISTRATION_DB.set_session_pending_tfa_challenge(token, new_id)
            return self._redirect('/manage/tfa/challenge')
        msg = ''
        msg_type = 'error'
        try:
            qs = urllib.parse.parse_qs(urllib.parse.urlparse(self.path).query)
            msg = urllib.parse.unquote(qs.get('msg', [''])[0])
            msg_type = qs.get('msg_type', ['error'])[0]
        except Exception:
            pass
        self._send_html(_render_tfa_challenge_page(user, msg=msg, msg_type=msg_type))

    def _do_logout(self):
        cookie_hdr = self.headers.get('Cookie', '')
        # Identify who is logging out before we delete the session
        logout_user = self._get_session_user()
        for part in cookie_hdr.split(';'):
            part = part.strip()
            if part.startswith('wksession='):
                REGISTRATION_DB.delete_session(part[10:])
        if logout_user:
            REGISTRATION_DB._log(logout_user['username'], 'logout',
                                 self.client_address[0])
        self.send_response(303)
        self._clear_session_cookie()
        self.send_header('Location', '/manage')
        self.send_header('Content-Length', '0')
        self.end_headers()

    # ── POST handlers ────────────────────────────────────────

    def _post_tfa_setup_start(self):
        # Present setup page (secret/URI are generated at render time).
        self._redirect('/manage/tfa/setup')

    def _post_tfa_setup_verify(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        if not _tfa_login_enabled():
            return self._redirect('/manage/dashboard')
        body = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        secret = re.sub(r'\s+', '', fields.get('secret', '').strip().upper())
        code = fields.get('code', '').strip()
        period = int(REGISTRATION_DB.get_setting('tfa_totp_period_sec', '30') or 30)
        digits = int(REGISTRATION_DB.get_setting('tfa_totp_digits', '6') or 6)
        skew = int(REGISTRATION_DB.get_setting('tfa_totp_skew_steps', '1') or 1)
        if not re.fullmatch(r'[A-Z2-7]{16,128}', secret):
            return self._send_html(_render_tfa_setup_page(user, msg='Invalid TOTP secret payload.', msg_type='error'))
        setup_match = _totp_verify_counter(secret, code, period=period, digits=digits, skew_steps=skew)
        if setup_match is None:
            return self._send_html(_render_tfa_setup_page(user, msg='Invalid authenticator code. Try again.', msg_type='error'))
        if not REGISTRATION_DB._tfa_fernet:
            return self._send_html(_render_tfa_setup_page(
                user,
                msg='TFA secret encryption key is not configured on this server.',
                msg_type='error'
            ))
        setup_counter, setup_offset = setup_match
        # Persist the current time-step counter (not the raw matched skew window):
        # - blocks same-window alternate-code reuse after a back-skew match
        # - avoids next-step lockout after a +1 future-skew match
        persist_counter = int(setup_counter - setup_offset)
        backup_count = int(REGISTRATION_DB.get_setting('tfa_backup_codes_count', '10') or 10)
        backup_codes = _tfa_generate_backup_codes(backup_count)
        REGISTRATION_DB.set_user_tfa_enrollment(int(user['id']), secret, backup_codes, method='totp')
        REGISTRATION_DB.reserve_user_tfa_totp_counter(int(user['id']), persist_counter)
        token = self._current_valid_session_token()
        if token:
            REGISTRATION_DB.set_session_tfa_enroll(token, False)
            # Keep the in-progress session valid after successful enrollment.
            # Without this, stale-session protection can invalidate this same
            # session because created_at precedes tfa_enrolled_at by a few seconds.
            REGISTRATION_DB.touch_session_created_at(token)
        REGISTRATION_DB._log(user['username'], 'tfa_enroll_finish', user['username'], f'backup_codes={len(backup_codes)}')
        delete_flow_active = bool(REGISTRATION_DB.get_active_account_delete_challenge(int(user['id'])))
        self._send_html(_render_tfa_setup_page(
            REGISTRATION_DB.get_user_by_id(int(user['id'])) or user,
            msg='TFA is now enabled. Save your backup codes.',
            msg_type='success',
            backup_codes=backup_codes,
            delete_flow_active=delete_flow_active
        ))

    def _post_tfa_challenge(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        client_ip = self.client_address[0] if self.client_address else ''
        if not _auth_rate_limit_allow('tfa_challenge', client_ip):
            q = urllib.parse.quote('Too many verification attempts. Please wait and try again.')
            return self._redirect(f'/manage/tfa/challenge?msg={q}&msg_type=error')
        token = self._current_valid_session_token()
        if not token:
            return self._redirect('/manage')
        pending_id = REGISTRATION_DB.get_session_pending_tfa_challenge_id(token)
        challenge = REGISTRATION_DB.get_tfa_challenge_by_id(pending_id, 'login') if pending_id else None
        if not challenge:
            REGISTRATION_DB.set_session_pending_tfa_challenge(token, None)
            REGISTRATION_DB.delete_session(token)
            return self._redirect('/manage?msg=session_expired')
        wait_left = REGISTRATION_DB.get_tfa_challenge_wait_seconds(int(challenge['id']))
        if wait_left > 0:
            q = urllib.parse.quote(f'Too many attempts. Wait {wait_left}s and try again.')
            return self._redirect(f'/manage/tfa/challenge?msg={q}&msg_type=error')
        body = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        code = fields.get('code', '').strip()
        period = int(REGISTRATION_DB.get_setting('tfa_totp_period_sec', '30') or 30)
        digits = int(REGISTRATION_DB.get_setting('tfa_totp_digits', '6') or 6)
        skew = int(REGISTRATION_DB.get_setting('tfa_totp_skew_steps', '1') or 1)
        secret = REGISTRATION_DB.get_user_tfa_secret(int(user['id']))
        ok = False
        used_backup = False
        used_counter = None
        used_offset = 0
        if secret:
            used_match = _totp_verify_counter(secret, code, period=period, digits=digits, skew_steps=skew)
            if used_match is not None:
                used_counter, used_offset = used_match
                # Persist current time-step counter (used_counter - offset).
                # This blocks same-window alternate-code reuse and avoids +1 lockout.
                persist_counter = int(used_counter - used_offset)
                if REGISTRATION_DB.reserve_user_tfa_totp_counter(int(user['id']), persist_counter):
                    ok = True
                else:
                    log.warning('TFA challenge replay blocked user=%s challenge_id=%s counter=%s',
                                user['username'], challenge['id'], used_counter)
        if (not ok) and REGISTRATION_DB.verify_and_consume_tfa_backup_code(int(user['id']), code):
            ok = True
            used_backup = True
        if not ok:
            attempts, wait = REGISTRATION_DB.register_tfa_challenge_failure(int(challenge['id']))
            self._security_probe(
                'tfa_fail_burst',
                _security_cfg_int('security_tfa_fail_threshold', 10, 2, 500),
                _security_cfg_int('security_tfa_fail_window_sec', 120, 1, 1800),
                'high', 0.85,
                path='/manage/tfa/challenge', method='POST', status=403
            )
            if attempts >= TFA_CHALLENGE_MAX_ATTEMPTS:
                REGISTRATION_DB.consume_tfa_challenge(int(challenge['id']))
                REGISTRATION_DB.delete_session(token)
                log.warning('TFA challenge exhausted user=%s challenge_id=%s attempts=%s',
                            user['username'], challenge['id'], attempts)
                q = urllib.parse.quote('Too many invalid codes. Please sign in again.')
                return self._redirect(f'/manage?msg={q}&msg_type=error')
            log.warning('TFA challenge failed user=%s challenge_id=%s attempts=%s backoff_sec=%s',
                        user['username'], challenge['id'], attempts, wait)
            q = urllib.parse.quote(f'Invalid authenticator or backup code. Try again in {wait}s.')
            return self._redirect(f'/manage/tfa/challenge?msg={q}&msg_type=error')
        REGISTRATION_DB.clear_tfa_challenge_failures(int(challenge['id']))
        REGISTRATION_DB.consume_tfa_challenge(int(challenge['id']))
        REGISTRATION_DB.mark_session_tfa_verified(token)
        if used_backup:
            REGISTRATION_DB.touch_user_tfa_verified(int(user['id']))
        REGISTRATION_DB._log(user['username'], 'tfa_challenge_success', user['username'],
                             'backup=1' if used_backup else 'backup=0')
        if self._session_requires_passkey_enroll():
            return self._redirect('/manage/passkey-enroll')
        if self._session_requires_tfa_enroll():
            return self._redirect('/manage/tfa/setup')
        delete_challenge = REGISTRATION_DB.get_active_account_delete_challenge(user['id'])
        return self._redirect('/manage/account/delete/confirm' if delete_challenge else '/manage/dashboard')

    def _post_tfa_preferences(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        if not _tfa_login_enabled():
            return self._redirect('/manage/profile?msg=Operator+must+enable+TFA+login+before+changing+TFA+preferences.&msg_type=error')
        body = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        required = fields.get('tfa_required') == '1'
        policy = _auth_factor_policy_for_user(user)
        admin_required = bool(policy.get('tfa_admin_user_required'))
        server_required = bool(policy.get('tfa_sitewide') or policy.get('tfa_admin_scope'))
        if admin_required or server_required:
            required = True
        REGISTRATION_DB.set_user_tfa_required(int(user['id']), required)
        REGISTRATION_DB._log(
            user['username'],
            'tfa_preferences',
            user['username'],
            f'required={1 if required else 0} admin_required={1 if admin_required else 0} server_required={1 if server_required else 0}'
        )
        if admin_required or server_required:
            return self._redirect('/manage/profile?msg=TFA+is+required+by+policy+for+this+account.&msg_type=error')
        return self._redirect('/manage/profile?msg=TFA+settings+saved.&msg_type=success')

    def _post_tfa_disable(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        policy = _auth_factor_policy_for_user(user)
        if policy.get('tfa_sitewide') or policy.get('tfa_admin_scope') or policy.get('tfa_admin_user_required'):
            q = urllib.parse.quote('TFA cannot be disabled while policy enforcement is active.')
            return self._redirect(f'/manage/profile?msg={q}&msg_type=error')
        REGISTRATION_DB.set_user_tfa_preferences(int(user['id']), enabled=False, required=False)
        REGISTRATION_DB.record_tfa_recovery_event(int(user['id']), user['username'], 'self_disable', 'via_profile', self.client_address[0] if self.client_address else '')
        REGISTRATION_DB._log(user['username'], 'tfa_disabled', user['username'], 'self_disable=1')
        q = urllib.parse.quote('Two-factor authentication disabled.')
        return self._redirect(f'/manage/profile?msg={q}&msg_type=success')

    def _post_login(self):
        body   = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        username = fields.get('username', '').strip()
        password = fields.get('password', '')
        invalid_login_msg = 'Invalid credentials.'
        reveal_lockout_msg = REGISTRATION_DB.get_setting('login_reveal_lockout_message', '0') == '1'
        locked_login_msg = (
            '⚠️ This account is temporarily locked due to failed sign-in attempts. '
            'Please try again later or contact an administrator.'
            if reveal_lockout_msg else invalid_login_msg
        )
        client_ip, _ = self._client_ip_info()
        if not _auth_rate_limit_allow('login', client_ip):
            log.warning('LOGIN rate_limited ip=%s user=%r', client_ip, username)
            self._send_html(_render_login('Too many sign-in attempts. Please wait and try again.'))
            return
        log.debug('LOGIN attempt user=%r ip=%s', username, client_ip)
        user_probe = REGISTRATION_DB.get_user(username) if username else None
        if user_probe and user_probe['is_locked'] and not user_probe['is_disabled']:
            # Only reveal lockout state when the submitted password is valid.
            # This avoids turning lockout messaging into broad username enumeration.
            if reveal_lockout_msg:
                if _verify_password(password, user_probe['password_hash'], user_probe['salt']):
                    log.info('LOGIN blocked_locked user=%r ip=%s', username, client_ip)
                    REGISTRATION_DB._log(username, 'login_locked', client_ip)
                    self._send_html(_render_login(locked_login_msg))
                    return
            else:
                # Reveal flag disabled, skip bcrypt and let generic flow handle it.
                pass
        if user_probe and not user_probe['is_disabled'] and not user_probe['is_locked']:
            policy = _auth_factor_policy_for_user(user_probe)
            if policy.get('password_blocked'):
                log.info('LOGIN password_blocked_passkey_required user=%r ip=%s policy=%s',
                         username, client_ip, policy)
                REGISTRATION_DB._log(username, 'login_password_blocked_passkey_required', client_ip)
                self._send_html(_render_login('Password sign-in is disabled for this account. Use Sign in with Passkey.'))
                return
        user = REGISTRATION_DB.authenticate(username, password)
        if user is None:
            log.debug('LOGIN failed user=%r', username)
            REGISTRATION_DB._log(username or '(unknown)', 'login_failed',
                                 client_ip)
            self._security_probe(
                'login_fail_burst',
                _security_cfg_int('security_login_fail_burst_threshold', 10, 2, 500),
                _security_cfg_int('security_login_fail_window_sec', 60, 1, 1800),
                'high', 0.85,
                path='/manage/login', method='POST', status=403
            )
            self._send_html(_render_login(invalid_login_msg))
            return
        if not REGISTRATION_DB.is_ip_allowed(user['id'], client_ip):
            log.warning('LOGIN blocked by IP allowlist user=%r ip=%s', username, client_ip)
            REGISTRATION_DB._log(username, 'login_ip_blocked', client_ip)
            self._send_html(_render_login(
                f'Sign-in denied from this IP address ({client_ip}). '
                'This account is restricted to allowed IP addresses.'
            ))
            return
        policy = _auth_factor_policy_for_user(user)
        needs_tfa_challenge = bool(policy.get('tfa_challenge_required'))
        token = REGISTRATION_DB.create_session(
            user['id'],
            must_enroll_passkey=bool(policy.get('must_enroll_passkey')),
            primary_auth_ok=not needs_tfa_challenge,
            must_enroll_tfa=bool(policy.get('must_enroll_tfa')),
        )
        REGISTRATION_DB.record_login_ip(user['id'], client_ip)
        REGISTRATION_DB.daily_login_check(user['id'])
        REGISTRATION_DB._log(username, 'login', client_ip)
        login_redirect = self._resolve_post_auth_redirect(
            user, token, policy,
            client_ip=client_ip,
            user_agent=self.headers.get('User-Agent', '')
        )
        log.debug('LOGIN success user=%r token=%s...', username, token[:8])
        self.send_response(303)
        try:
            self._set_session_cookie(token)
        except Exception as exc:
            log.error('LOGIN _set_session_cookie failed: %s', exc, exc_info=True)
            raise
        self.send_header('Location', login_redirect)
        self.send_header('Content-Length', '0')
        self.end_headers()
        log.debug('LOGIN 303 sent for user=%r location=%s', username, login_redirect)

    def _webauthn_rp_id(self) -> str:
        configured = ''
        if REGISTRATION_DB:
            configured = (REGISTRATION_DB.get_setting('webauthn_rp_id', '') or '').strip().lower()
        if not configured:
            configured = (WEB_CONFIG.get('domain', '') or '').strip().split(':')[0].lower()
        if configured:
            return configured
        host = (self.headers.get('Host', '') or '').strip().split(':')[0].lower()
        return host or 'localhost'

    def _webauthn_server(self):
        if not _WEBAUTHN_LIB_AVAILABLE:
            return None
        rp_id = self._webauthn_rp_id()
        host = (self.headers.get('Host', '') or '').strip().split(':')[0].lower()
        configured = ''
        if REGISTRATION_DB:
            configured = (REGISTRATION_DB.get_setting('webauthn_rp_id', '') or '').strip().lower()
        if not configured:
            configured = (WEB_CONFIG.get('domain', '') or '').strip().split(':')[0].lower()
        if not configured and host not in ('', 'localhost', '127.0.0.1', '::1'):
            log.warning('WEBAUTHN rp_id is not configured; refusing host-derived rp_id for host=%s', host)
            return None
        if host and rp_id:
            host_ok = (host == rp_id) or host.endswith(f'.{rp_id}')
            if not host_ok:
                log.warning('WEBAUTHN host/rp mismatch host=%s rp_id=%s', host, rp_id)
                return None
        try:
            return Fido2Server({'id': rp_id, 'name': 'Wildkat Tracker'})
        except Exception:
            return None

    def _webauthn_guard(self) -> tuple[bool, str]:
        if not _WEBAUTHN_LIB_AVAILABLE:
            return False, 'WebAuthn verifier backend is not installed on this server.'
        if not REGISTRATION_DB or REGISTRATION_DB.get_setting('webauthn_login_enabled', '0') != '1':
            return False, 'WebAuthn login is currently disabled by the operator.'
        return True, ''

    def _post_webauthn_auth_start(self):
        ok, err = self._webauthn_guard()
        if not ok:
            return self._send_json({'ok': False, 'error': err}, 400)
        client_ip, _ = self._client_ip_info()
        if not _auth_rate_limit_allow('webauthn_auth_start', client_ip):
            log.warning('WEBAUTHN auth start rate_limited ip=%s', client_ip)
            return self._send_json({'ok': False, 'error': 'Invalid credentials.'}, 429)
        payload = self._read_json_body()
        username = str(payload.get('username', '')).strip()
        all_credentials = bool(payload.get('all_credentials'))
        if not username:
            return self._send_json({'ok': False, 'error': 'Username is required.'}, 400)
        generic_fail = {'ok': False, 'error': 'Invalid credentials.'}
        user = REGISTRATION_DB.get_user(username)
        lock_allows_passkey = _webauthn_allow_locked_accounts()
        if not user or user['is_disabled'] or (user['is_locked'] and not lock_allows_passkey):
            self._security_probe(
                'webauthn_fail_burst',
                _security_cfg_int('security_webauthn_fail_threshold', 10, 2, 500),
                _security_cfg_int('security_webauthn_fail_window_sec', 120, 1, 1800),
                'high', 0.85,
                path='/manage/webauthn/auth/start', method='POST', status=403
            )
            return self._send_json(generic_fail, 403)
        policy = _auth_factor_policy_for_user(user)
        user_enabled = _flag_true(user['webauthn_enabled']) if ('webauthn_enabled' in user.keys()) else False
        if not user_enabled and not policy.get('passkey_required'):
            log.warning('WEBAUTHN auth start denied user=%s reason=account_passkey_disabled', username)
            self._security_probe(
                'webauthn_fail_burst',
                _security_cfg_int('security_webauthn_fail_threshold', 10, 2, 500),
                _security_cfg_int('security_webauthn_fail_window_sec', 120, 1, 1800),
                'high', 0.85,
                path='/manage/webauthn/auth/start', method='POST', status=403
            )
            return self._send_json(generic_fail, 403)
        if not user_enabled and policy.get('passkey_required'):
            log.debug('WEBAUTHN auth start user flag disabled; proceeding due to policy user=%s policy_required=1',
                      username)
        rows = REGISTRATION_DB.list_webauthn_credentials(user['id'])
        if not rows:
            log.warning('WEBAUTHN auth start denied user=%s reason=no_registered_passkeys', username)
            self._security_probe(
                'webauthn_fail_burst',
                _security_cfg_int('security_webauthn_fail_threshold', 10, 2, 500),
                _security_cfg_int('security_webauthn_fail_window_sec', 120, 1, 1800),
                'high', 0.85,
                path='/manage/webauthn/auth/start', method='POST', status=403
            )
            return self._send_json(generic_fail, 403)
        server = self._webauthn_server()
        if not server:
            return self._send_json({'ok': False, 'error': 'Unable to initialize WebAuthn server.'}, 500)
        preferred_cookie = self._get_cookie_value(f'wk_last_passkey_{int(user["id"])}').strip()
        primary_row = next((r for r in rows if int(r['is_primary'] or 0) == 1), None)
        selected_rows = list(rows)
        used_preferred = False
        preferred_source = ''
        if not all_credentials and primary_row:
            selected_rows = [primary_row]
            used_preferred = True
            preferred_source = 'primary'
            log.debug('WEBAUTHN auth start user=%s using primary credential', username)
        elif not all_credentials and preferred_cookie:
            narrowed = [r for r in rows if str(r['credential_id'] or '').strip() == preferred_cookie]
            if narrowed:
                selected_rows = narrowed
                used_preferred = True
                preferred_source = 'cookie'
                log.debug('WEBAUTHN auth start user=%s using preferred credential cookie', username)
        creds = []
        for r in selected_rows:
            try:
                creds.append(AttestedCredentialData(bytes(r['public_key_cose'])))
            except Exception:
                continue
        if not creds and used_preferred:
            # Cookie points to stale/invalid credential; fall back to full credential list.
            used_preferred = False
            preferred_source = ''
            for r in rows:
                try:
                    creds.append(AttestedCredentialData(bytes(r['public_key_cose'])))
                except Exception:
                    continue
        if not creds:
            return self._send_json({'ok': False, 'error': 'Stored passkey data is invalid.'}, 500)
        try:
            auth_data, state = server.authenticate_begin(creds, user_verification='preferred')
            options = auth_data.get('publicKey', auth_data)
            state_blob = _webauthn_state_pack(state)
            challenge = options.get('challenge')
            challenge_b64 = _b64url_encode(challenge if isinstance(challenge, (bytes, bytearray)) else bytes(challenge))
            challenge_id = REGISTRATION_DB.create_webauthn_challenge(
                user['id'],
                'auth',
                challenge_b64,
                state_blob,
                session_hint='',
                client_ip=self.client_address[0] if self.client_address else '',
                user_agent=self.headers.get('User-Agent', '')
            )
            options_json = _json_safe_obj(options)
            REGISTRATION_DB._log(username, 'webauthn_auth_start', username, f'challenge_id={challenge_id}')
            return self._send_json({
                'ok': True,
                'challenge_id': challenge_id,
                'publicKey': options_json,
                'used_preferred': used_preferred,
                'preferred_source': preferred_source,
                'can_try_all': (used_preferred and len(rows) > 1),
            })
        except Exception as e:
            log.exception('WEBAUTHN auth start failed user=%s: %s', username, e)
            return self._send_json({'ok': False, 'error': 'Unable to start passkey authentication.'}, 500)

    def _post_webauthn_auth_finish(self):
        ok, err = self._webauthn_guard()
        if not ok:
            return self._send_json({'ok': False, 'error': err}, 400)
        client_ip, _ = self._client_ip_info()
        if not _auth_rate_limit_allow('webauthn_auth_finish', client_ip):
            log.warning('WEBAUTHN auth finish rate_limited ip=%s', client_ip)
            return self._send_json({'ok': False, 'error': 'Passkey authentication failed.'}, 429)
        payload = self._read_json_body()
        try:
            challenge_id = int(payload.get('challenge_id', 0))
        except Exception:
            challenge_id = 0
        cred = payload.get('credential') if isinstance(payload.get('credential'), dict) else {}
        if not challenge_id or not cred:
            return self._send_json({'ok': False, 'error': 'Missing authentication payload.'}, 400)
        ch = REGISTRATION_DB.get_webauthn_challenge(challenge_id, 'auth')
        if not ch:
            return self._send_json({'ok': False, 'error': 'Authentication challenge expired or invalid.'}, 400)
        server = self._webauthn_server()
        if not server:
            return self._send_json({'ok': False, 'error': 'Unable to initialize WebAuthn server.'}, 500)
        user = REGISTRATION_DB.get_user_by_id(int(ch['user_id'])) if ch['user_id'] else None
        if not user:
            return self._send_json({'ok': False, 'error': 'Account not found.'}, 404)
        lock_allows_passkey = _webauthn_allow_locked_accounts()
        if user['is_disabled'] or (user['is_locked'] and not lock_allows_passkey):
            self._security_probe(
                'webauthn_fail_burst',
                _security_cfg_int('security_webauthn_fail_threshold', 10, 2, 500),
                _security_cfg_int('security_webauthn_fail_window_sec', 120, 1, 1800),
                'high', 0.85,
                path='/manage/webauthn/auth/finish', method='POST', status=403
            )
            return self._send_json({'ok': False, 'error': 'Invalid credentials.'}, 403)
        client_ip = self.client_address[0] if self.client_address else ''
        if not REGISTRATION_DB.is_ip_allowed(user['id'], client_ip):
            log.warning('WEBAUTHN auth blocked by IP allowlist user=%r ip=%s', user['username'], client_ip)
            REGISTRATION_DB._log(user['username'], 'webauthn_auth_ip_blocked', client_ip)
            ip_msg = urllib.parse.quote_plus(
                f'Sign-in denied from this IP address ({client_ip}). '
                'This account is restricted to allowed IP addresses.'
            )
            return self._send_json(
                {
                    'ok': False,
                    'error': f'Sign-in denied from this IP address ({client_ip}).',
                    'redirect': f'/manage?msg={ip_msg}&msg_type=error',
                },
                403
            )
        rows = REGISTRATION_DB.list_webauthn_credentials(user['id'])
        stored = []
        by_cred_id = {}
        for r in rows:
            try:
                acd = AttestedCredentialData(bytes(r['public_key_cose']))
                stored.append(acd)
                by_cred_id[_b64url_encode(acd.credential_id)] = r
            except Exception:
                continue
        try:
            state = _webauthn_state_unpack(ch['state_json'])
            if state is None:
                log.warning('WEBAUTHN auth finish invalid challenge state challenge_id=%s', challenge_id)
                return self._send_json({'ok': False, 'error': 'Authentication challenge expired or invalid.'}, 400)
            cred_id_b64 = str(cred.get('id', '')).strip()
            resp = cred.get('response', {}) if isinstance(cred.get('response'), dict) else {}
            client_data = CollectedClientData(_b64url_decode(str(resp.get('clientDataJSON', ''))))
            auth_data = AuthenticatorData(_b64url_decode(str(resp.get('authenticatorData', ''))))
            signature = _b64url_decode(str(resp.get('signature', '')))
            cred_id_raw = _b64url_decode(cred_id_b64)
            server.authenticate_complete(state, stored, cred_id_raw, client_data, auth_data, signature)
            REGISTRATION_DB.consume_webauthn_challenge(challenge_id)
            row = by_cred_id.get(cred_id_b64)
            if row:
                stored_sign_count = int(row['sign_count'] or 0)
                new_sign_count = int(auth_data.counter or 0)
                if stored_sign_count > 0 and new_sign_count <= stored_sign_count:
                    REGISTRATION_DB._log(
                        user['username'],
                        'webauthn_clone_detected',
                        user['username'],
                        f'cred_id={cred_id_b64[:14]}... old={stored_sign_count} new={new_sign_count}'
                    )
                    log.warning('WEBAUTHN clone suspected user=%s cred=%s old=%s new=%s',
                                user['username'], cred_id_b64[:14], stored_sign_count, new_sign_count)
                    self._security_probe(
                        'webauthn_fail_burst',
                        _security_cfg_int('security_webauthn_fail_threshold', 10, 2, 500),
                        _security_cfg_int('security_webauthn_fail_window_sec', 120, 1, 1800),
                        'high', 0.90,
                        path='/manage/webauthn/auth/finish', method='POST', status=403
                    )
                    return self._send_json({'ok': False, 'error': 'Passkey authentication failed.'}, 403)
                REGISTRATION_DB.touch_webauthn_credential(int(row['id']), int(auth_data.counter))
                REGISTRATION_DB.set_webauthn_primary_credential(int(user['id']), int(row['id']))
            policy = _auth_factor_policy_for_user(user)
            needs_tfa_challenge = bool(policy.get('tfa_challenge_required'))
            token = REGISTRATION_DB.create_session(
                user['id'],
                must_enroll_passkey=bool(policy.get('must_enroll_passkey')),
                primary_auth_ok=not needs_tfa_challenge,
                must_enroll_tfa=bool(policy.get('must_enroll_tfa')),
                allow_locked_passkey=bool(user['is_locked'] and _webauthn_allow_locked_accounts()),
            )
            REGISTRATION_DB.record_login_ip(user['id'], client_ip)
            REGISTRATION_DB.daily_login_check(user['id'])
            REGISTRATION_DB._log(user['username'], 'webauthn_auth_success', user['username'],
                                 f'challenge_id={challenge_id}')
            redirect = self._resolve_post_auth_redirect(
                user, token, policy,
                client_ip=client_ip,
                user_agent=self.headers.get('User-Agent', '')
            )
            self.send_response(200)
            self._set_session_cookie(token)
            if row and str(row['credential_id'] or '').strip():
                self._set_cookie(
                    f'wk_last_passkey_{int(user["id"])}',
                    str(row['credential_id']).strip(),
                    hours=24 * 30,
                    http_only=False,
                    same_site='Lax',
                    path='/manage',
                )
            body = json.dumps({'ok': True, 'redirect': redirect}).encode('utf-8')
            self.send_header('Content-Type', 'application/json')
            self.send_header('Content-Length', str(len(body)))
            self.send_header('Cache-Control', 'no-store')
            self.end_headers()
            self.wfile.write(body)
            return
        except Exception as e:
            REGISTRATION_DB._log(user['username'], 'webauthn_auth_failed', user['username'],
                                 f'challenge_id={challenge_id}')
            log.warning('WEBAUTHN auth finish failed user=%s challenge_id=%s err=%s',
                        user['username'], challenge_id, e)
            self._security_probe(
                'webauthn_fail_burst',
                _security_cfg_int('security_webauthn_fail_threshold', 10, 2, 500),
                _security_cfg_int('security_webauthn_fail_window_sec', 120, 1, 1800),
                'high', 0.85,
                path='/manage/webauthn/auth/finish', method='POST', status=403
            )
            return self._send_json({'ok': False, 'error': 'Passkey authentication failed.'}, 403)

    def _post_webauthn_register_start(self):
        user = self._get_session_user()
        if not user:
            return self._send_json({'ok': False, 'error': 'Authentication required.'}, 401)
        ok, err = self._webauthn_guard()
        if not ok:
            return self._send_json({'ok': False, 'error': err}, 400)
        server = self._webauthn_server()
        if not server:
            return self._send_json({'ok': False, 'error': 'Unable to initialize WebAuthn server.'}, 500)
        rows = REGISTRATION_DB.list_webauthn_credentials(user['id'])
        existing = []
        for r in rows:
            try:
                existing.append(AttestedCredentialData(bytes(r['public_key_cose'])))
            except Exception:
                continue
        user_entity = {
            'id': str(user['id']).encode('utf-8'),
            'name': user['username'],
            'displayName': user['username'],
        }
        try:
            reg_data, state = server.register_begin(
                user_entity,
                credentials=existing,
                user_verification='preferred',
            )
            options = reg_data.get('publicKey', reg_data)
            challenge = options.get('challenge')
            challenge_b64 = _b64url_encode(challenge if isinstance(challenge, (bytes, bytearray)) else bytes(challenge))
            state_blob = _webauthn_state_pack(state)
            challenge_id = REGISTRATION_DB.create_webauthn_challenge(
                user['id'],
                'register',
                challenge_b64,
                state_blob,
                client_ip=self.client_address[0] if self.client_address else '',
                user_agent=self.headers.get('User-Agent', '')
            )
            REGISTRATION_DB._log(user['username'], 'webauthn_register_start', user['username'],
                                 f'challenge_id={challenge_id}')
            return self._send_json({'ok': True, 'challenge_id': challenge_id, 'publicKey': _json_safe_obj(options)})
        except Exception as e:
            log.exception('WEBAUTHN register start failed user=%s: %s', user['username'], e)
            return self._send_json({'ok': False, 'error': 'Unable to start passkey registration.'}, 500)

    def _post_webauthn_register_finish(self):
        user = self._get_session_user()
        if not user:
            return self._send_json({'ok': False, 'error': 'Authentication required.'}, 401)
        ok, err = self._webauthn_guard()
        if not ok:
            return self._send_json({'ok': False, 'error': err}, 400)
        payload = self._read_json_body()
        try:
            challenge_id = int(payload.get('challenge_id', 0))
        except Exception:
            challenge_id = 0
        nickname = str(payload.get('nickname', '')).strip()
        cred = payload.get('credential') if isinstance(payload.get('credential'), dict) else {}
        if not challenge_id or not cred:
            return self._send_json({'ok': False, 'error': 'Missing registration payload.'}, 400)
        ch = REGISTRATION_DB.get_webauthn_challenge(challenge_id, 'register')
        if not ch or int(ch['user_id'] or 0) != int(user['id']):
            return self._send_json({'ok': False, 'error': 'Registration challenge expired or invalid.'}, 400)
        server = self._webauthn_server()
        if not server:
            return self._send_json({'ok': False, 'error': 'Unable to initialize WebAuthn server.'}, 500)
        try:
            state = _webauthn_state_unpack(ch['state_json'])
            if state is None:
                log.warning('WEBAUTHN register finish invalid challenge state challenge_id=%s', challenge_id)
                return self._send_json({'ok': False, 'error': 'Registration challenge expired or invalid.'}, 400)
            resp = cred.get('response', {}) if isinstance(cred.get('response'), dict) else {}
            client_data = CollectedClientData(_b64url_decode(str(resp.get('clientDataJSON', ''))))
            att_obj = AttestationObject(_b64url_decode(str(resp.get('attestationObject', ''))))
            auth_data = server.register_complete(state, client_data, att_obj)
            cd = auth_data.credential_data
            cred_id_b64 = _b64url_encode(cd.credential_id)
            added = REGISTRATION_DB.add_webauthn_credential(
                user['id'],
                cred_id_b64,
                bytes(cd),
                int(auth_data.counter),
                aaguid=str(getattr(cd, 'aaguid', '') or ''),
                transports_json=json.dumps(cred.get('transports', [])),
                authenticator_attachment=str(cred.get('authenticatorAttachment', '') or ''),
                is_resident_key=False,
                user_verification=True,
                nickname=nickname or 'Passkey',
            )
            if not added:
                return self._send_json({'ok': False, 'error': 'Credential already registered.'}, 409)
            REGISTRATION_DB.consume_webauthn_challenge(challenge_id)
            REGISTRATION_DB.set_user_webauthn_preferences(
                user['id'],
                enabled=True,
                required=bool(user['webauthn_required']) if 'webauthn_required' in user.keys() else False,
            )
            tok = self._current_valid_session_token()
            if tok and REGISTRATION_DB.session_requires_passkey_enroll(tok):
                REGISTRATION_DB.set_session_passkey_enroll(tok, False)
            REGISTRATION_DB._log(user['username'], 'webauthn_register_finish', user['username'],
                                 f'challenge_id={challenge_id} cred={cred_id_b64[:14]}...')
            policy = _auth_factor_policy_for_user(REGISTRATION_DB.get_user_by_id(user['id']) or user)
            redirect = '/manage/tfa/setup' if policy.get('must_enroll_tfa') else (
                '/manage/passkey-enroll' if policy.get('must_enroll_passkey') else
                ('/manage/account/delete/confirm' if REGISTRATION_DB.get_active_account_delete_challenge(user['id']) else '/manage/dashboard')
            )
            return self._send_json({'ok': True, 'message': 'Passkey registered.', 'redirect': redirect})
        except Exception as e:
            log.warning('WEBAUTHN register finish failed user=%s challenge_id=%s err=%s',
                        user['username'], challenge_id, e)
            return self._send_json({'ok': False, 'error': 'Passkey registration failed.'}, 400)

    def _post_webauthn_preferences(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        body = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        policy = _auth_factor_policy_for_user(user)
        admin_required = _flag_true(user['webauthn_required_admin']) if ('webauthn_required_admin' in user.keys()) else False
        server_policy_required = bool(policy.get('passkey_sitewide') or policy.get('passkey_admin_scope'))
        enforced_policy_required = bool(server_policy_required or admin_required)
        enabled_current = _flag_true(user['webauthn_enabled']) if ('webauthn_enabled' in user.keys()) else False
        user_account_required = _flag_true(user['webauthn_required']) if ('webauthn_required' in user.keys()) else False
        # Unchecked checkboxes are omitted from multipart payloads.
        # Preserve current enabled state only when that control is effectively locked.
        enabled_locked = bool(enforced_policy_required)
        enabled = (fields.get('webauthn_enabled') == '1') if ('webauthn_enabled' in fields) else (enabled_current if enabled_locked else False)
        required = fields.get('webauthn_required') == '1'
        if required and not _webauthn_login_enabled():
            return self._redirect('/manage/profile?msg=Operator+must+enable+WebAuthn+login+before+requiring+passkeys.&msg_type=error')
        if enforced_policy_required and not _webauthn_login_enabled():
            return self._redirect('/manage/profile?msg=Passkey+policy+requires+WebAuthn+login+to+remain+enabled.&msg_type=error')
        if enforced_policy_required:
            enabled = True
        if admin_required:
            required = True
        if required and not enabled:
            return self._redirect('/manage/profile?msg=Enable+passkey+sign-in+before+requiring+passkey+login.&msg_type=error')
        REGISTRATION_DB.set_user_webauthn_preferences(user['id'], enabled, required)
        REGISTRATION_DB._log(
            user['username'],
            'webauthn_preferences',
            user['username'],
            f'enabled={int(enabled)} required={int(required)} admin_required={1 if admin_required else 0} server_policy_required={1 if server_policy_required else 0} user_account_required={1 if user_account_required else 0}'
        )
        if admin_required:
            self._redirect('/manage/profile?msg=Passkey+preferences+saved.+Admin+policy+keeps+passkey+requirement+enabled.&msg_type=success')
            return
        if server_policy_required:
            self._redirect('/manage/profile?msg=Passkey+preferences+saved.+Server+policy+keeps+passkey+sign-in+enabled.&msg_type=success')
            return
        self._redirect('/manage/profile?msg=Passkey+preferences+saved&msg_type=success')

    def _post_webauthn_credential_delete(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        body = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        try:
            cred_id = int(fields.get('cred_id', '0'))
        except Exception:
            cred_id = 0
        policy = _auth_factor_policy_for_user(user)
        if policy.get('passkey_required'):
            active_count = REGISTRATION_DB.count_webauthn_credentials(user['id'])
            if active_count <= 1:
                return self._redirect('/manage/profile?msg=Cannot+remove+your+last+passkey+while+passkey+enforcement+is+active.&msg_type=error')
        if cred_id and REGISTRATION_DB.delete_webauthn_credential(user['id'], cred_id):
            REGISTRATION_DB._log(user['username'], 'webauthn_credential_delete', user['username'], f'cred_id={cred_id}')
            self._redirect('/manage/profile?msg=Passkey+removed&msg_type=success')
            return
        self._redirect('/manage/profile?msg=Unable+to+remove+passkey&msg_type=error')

    def _post_webauthn_credential_rename(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        body = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        try:
            cred_id = int(fields.get('cred_id', '0'))
        except Exception:
            cred_id = 0
        nickname = (fields.get('nickname', '') or '').strip()
        if not cred_id:
            return self._redirect('/manage/profile?msg=Invalid+passkey+selection&msg_type=error')
        if not nickname:
            return self._redirect('/manage/profile?msg=Passkey+name+cannot+be+empty&msg_type=error')
        renamed = REGISTRATION_DB.rename_webauthn_credential(user['id'], cred_id, nickname)
        set_primary = REGISTRATION_DB.set_webauthn_primary_credential(user['id'], cred_id)
        if renamed and set_primary:
            REGISTRATION_DB._log(user['username'], 'webauthn_credential_rename', user['username'],
                                 f'cred_id={cred_id} nickname={nickname[:80]!r} primary=1')
            return self._redirect('/manage/profile?msg=Passkey+updated+and+set+as+primary&msg_type=success')
        self._redirect('/manage/profile?msg=Unable+to+rename+passkey&msg_type=error')

    def _post_upload(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        max_content_mb, max_files, max_file_mb = self._get_upload_limits()
        max_file_bytes = max_file_mb * 1024 * 1024
        body = self._read_body()
        log.debug('UPLOAD body_len=%d content_type=%r',
                  len(body), self.headers.get('Content-Type', '')[:60])
        fields, files = _parse_multipart(self.headers, body)
        log.debug('UPLOAD fields=%s file_keys=%s', list(fields.keys()), list(files.keys()))
        # files dict may hold a single tuple or list of tuples for multiple uploads
        raw_files = files.get('torrent')
        if not raw_files:
            log.debug('UPLOAD no torrent field found in parsed body')
            torrents = REGISTRATION_DB.list_torrents(user_id=user['id'])
            return self._send_html(_render_dashboard(user, torrents, 'No torrent file received.'))
        # Normalise to list of (filename, data) tuples
        if isinstance(raw_files, tuple):
            file_list = [raw_files]
        else:
            file_list = raw_files
        added = []
        added_with_hash = []
        skipped_duplicate = 0
        skipped_too_large = 0
        skipped_invalid   = 0
        skipped_suppressed = 0
        skipped_over_max_files = 0
        skipped_db_locked = 0
        normalized_names = 0
        cleanup_enabled = REGISTRATION_DB.get_setting('torrent_name_cleanup_enabled', '1') == '1'
        cleanup_on_upload = REGISTRATION_DB.get_setting('torrent_name_cleanup_on_upload', '1') == '1'
        cleanup_tags = _parse_torrent_name_cleanup_tags(
            REGISTRATION_DB.get_setting('torrent_name_cleanup_tags', '')
        )
        cleanup_strip_www = REGISTRATION_DB.get_setting(
            'torrent_name_cleanup_strip_www_prefix', '1'
        ) == '1'
        cleanup_strip_extensions = REGISTRATION_DB.get_setting(
            'torrent_name_cleanup_strip_extensions', '1'
        ) == '1'
        for idx, (fname, file_data) in enumerate(file_list):
            if idx >= max_files:
                skipped_over_max_files += 1
                continue
            if len(file_data) > max_file_bytes:
                skipped_too_large += 1
                continue
            try:
                ih, name, total_size, meta = parse_torrent(file_data)
            except Exception:
                skipped_invalid += 1
                continue
            if REGISTRATION_DB.is_info_hash_suppressed(ih):
                skipped_suppressed += 1
                continue
            if cleanup_enabled and cleanup_on_upload:
                normalized_name = _normalize_torrent_display_name(
                    name, cleanup_tags,
                    strip_www_prefix=cleanup_strip_www,
                    strip_extensions=cleanup_strip_extensions,
                )
            else:
                normalized_name = (name or '').strip()
            if normalized_name and normalized_name != name:
                normalized_names += 1
            try:
                ok = REGISTRATION_DB.register_torrent(
                    ih, normalized_name, total_size, user['id'], user['username'], meta=meta
                )
            except sqlite3.OperationalError as e:
                if 'locked' in str(e).lower():
                    skipped_db_locked += 1
                    log.warning('UPLOAD register skipped due DB lock ih=%s user=%s', ih, user['username'])
                    continue
                raise
            if ok:
                log.info('REGISTRATION torrent registered  ih=%s  name=%s  by=%s',
                         ih, normalized_name, user['username'])
                REGISTRATION_DB.award_upload_points(user['id'], normalized_name, ih)
                REGISTRATION_DB.check_auto_promote(user['id'])
                added.append(normalized_name)
                added_with_hash.append((ih, normalized_name))
            else:
                skipped_duplicate += 1
        auto_peer_queued = 0
        auto_peer_not_queued = 0
        auto_match_approved = 0
        auto_match_pending = 0
        auto_match_skipped = 0
        srrdb_matched = 0
        srrdb_skipped = 0
        peer_cfg = REGISTRATION_DB.get_peer_query_config()
        meta_cfg = REGISTRATION_DB.get_metadata_config() if REGISTRATION_DB else {}
        srrdb_cfg = REGISTRATION_DB.get_srrdb_config() if REGISTRATION_DB else {'enabled': False}
        if added_with_hash and peer_cfg.get('active') and peer_cfg.get('auto_on_upload'):
            configured_cap = max(1, int(peer_cfg.get('auto_upload_cap', 5)))
            # Guardrail for very large uploads: keep auto peer queue pressure bounded.
            hard_cap = 10
            cap = min(configured_cap, hard_cap)
            for ih, tname in added_with_hash[:cap]:
                if _enqueue_peer_update(ih, user['username'], 'upload'):
                    auto_peer_queued += 1
                else:
                    auto_peer_not_queued += 1
                    log.debug('UPLOAD auto peer queue failed ih=%s', ih)
        if (added_with_hash and srrdb_cfg.get('enabled', False)
                and srrdb_cfg.get('on_upload', False)):
            scap = max(1, min(50, int(srrdb_cfg.get('upload_cap', 5))))
            for ih, _tname in added_with_hash[:scap]:
                try:
                    s_ok, _s_msg = REGISTRATION_DB.refresh_torrent_srrdb_cache(
                        ih, actor_username=user['username'], force=True
                    )
                    if s_ok and REGISTRATION_DB.get_torrent_srrdb_cache(ih):
                        row = REGISTRATION_DB.get_torrent_srrdb_cache(ih)
                        if row and int(row['matched'] or 0) == 1:
                            srrdb_matched += 1
                        else:
                            srrdb_skipped += 1
                    else:
                        srrdb_skipped += 1
                except sqlite3.OperationalError as e:
                    if 'locked' in str(e).lower():
                        srrdb_skipped += 1
                        log.warning('UPLOAD srrdb refresh skipped due DB lock ih=%s user=%s', ih, user['username'])
                    else:
                        raise
            if len(added_with_hash) > scap:
                srrdb_skipped += (len(added_with_hash) - scap)
        if (added_with_hash and meta_cfg.get('enabled', True)
                and meta_cfg.get('auto_match_enabled', False)
                and meta_cfg.get('auto_match_on_upload', False)):
            mcap = max(1, min(100, int(meta_cfg.get('auto_match_upload_cap', 5))))
            for ih, _tname in added_with_hash[:mcap]:
                try:
                    m_ok, _m_msg, m_level, _m_score = REGISTRATION_DB.auto_match_torrent_metadata(
                        ih, int(user['id']), user['username'], source='upload'
                    )
                    if m_ok and m_level == 'high':
                        auto_match_approved += 1
                    elif m_ok and m_level == 'medium':
                        auto_match_pending += 1
                    else:
                        auto_match_skipped += 1
                except sqlite3.OperationalError as e:
                    if 'locked' in str(e).lower():
                        auto_match_skipped += 1
                        log.warning('UPLOAD auto match skipped due DB lock ih=%s user=%s', ih, user['username'])
                    else:
                        raise
            if len(added_with_hash) > mcap:
                auto_match_skipped += (len(added_with_hash) - mcap)
        follower_notifs = 0
        for ih, tname in added_with_hash:
            follower_notifs += REGISTRATION_DB.notify_followers_torrent_upload(
                user['id'], user['username'], ih, tname
            )
        parts = []
        if added:
            parts.append(f'{len(added)} registered')
        if skipped_duplicate:
            parts.append(f'{skipped_duplicate} duplicates skipped')
        if skipped_too_large:
            parts.append(f'{skipped_too_large} skipped (file > {max_file_mb} MB)')
        if skipped_invalid:
            parts.append(f'{skipped_invalid} invalid torrent files skipped')
        if skipped_suppressed:
            parts.append(f'{skipped_suppressed} suppressed hashes skipped')
        if skipped_over_max_files:
            parts.append(f'{skipped_over_max_files} skipped (max files per upload is {max_files})')
        if skipped_db_locked:
            parts.append(f'{skipped_db_locked} skipped (temporary database lock)')
        if normalized_names:
            parts.append(f'{normalized_names} names normalized')
        if auto_peer_queued:
            parts.append(f'{auto_peer_queued} peer snapshots queued')
        over_cap = max(0, len(added_with_hash) - cap) if (added_with_hash and peer_cfg.get('active') and peer_cfg.get('auto_on_upload')) else 0
        if over_cap:
            parts.append(f'{over_cap} peer snapshots deferred (cap {cap})')
        if auto_peer_not_queued:
            parts.append(f'{auto_peer_not_queued} peer snapshots queue failed')
        if auto_match_approved:
            parts.append(f'{auto_match_approved} metadata auto-approved')
        if auto_match_pending:
            parts.append(f'{auto_match_pending} metadata queued for review')
        if auto_match_skipped and meta_cfg.get('auto_match_on_upload', False):
            parts.append(f'{auto_match_skipped} metadata auto-match skipped')
        if srrdb_matched:
            parts.append(f'{srrdb_matched} SRRDB matches cached')
        if srrdb_skipped and srrdb_cfg.get('on_upload', False):
            parts.append(f'{srrdb_skipped} SRRDB checks skipped')
        msg = ' | '.join(parts) if parts else 'No files processed.'
        msg_type = 'success' if added else 'error'
        log.debug('UPLOAD result msg=%r msg_type=%r added=%d skipped=%d errors=%d',
                  msg[:80], msg_type, len(added),
                  skipped_duplicate + skipped_too_large + skipped_invalid + skipped_over_max_files,
                  skipped_invalid)
        if follower_notifs:
            log.debug('UPLOAD follower notifications sent=%d uploader=%s', follower_notifs, user['username'])
        # PRG pattern: prevent browser back button from replaying POST /manage/upload.
        msg_q = urllib.parse.quote_plus(msg[:500])
        return self._redirect(f'/manage/dashboard?msg={msg_q}&msg_type={msg_type}')

    def _post_magnet_submit(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        cfg = REGISTRATION_DB.get_magnet_submission_config() if REGISTRATION_DB else {'enabled': False}
        if not cfg.get('enabled', False):
            q = urllib.parse.quote_plus('Magnet submission engine is disabled.')
            return self._redirect(f'/manage/dashboard?msg={q}&msg_type=error')
        _start_magnet_workers()
        body = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        magnet_uri = (fields.get('magnet_uri', '') or '').strip()
        ok, msg, _job_id, _ih = REGISTRATION_DB.submit_magnet_job(
            int(user['id']), user['username'], magnet_uri
        )
        q = urllib.parse.quote_plus(msg[:500])
        return self._redirect(f'/manage/dashboard?msg={q}&msg_type={"success" if ok else "error"}')

    def _post_magnet_resubmit(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        cfg = REGISTRATION_DB.get_magnet_submission_config() if REGISTRATION_DB else {'enabled': False}
        if not cfg.get('enabled', False):
            q = urllib.parse.quote_plus('Magnet submission engine is disabled.')
            return self._redirect(f'/manage/notifications?msg={q}&msg_type=error')
        _start_magnet_workers()
        body = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        info_hash = (fields.get('info_hash', '') or '').strip().upper()
        if not re.fullmatch(r'[A-F0-9]{40}', info_hash):
            q = urllib.parse.quote_plus('Invalid info hash for resubmit.')
            return self._redirect(f'/manage/notifications?msg={q}&msg_type=error')
        ok, msg, _job_id, _ih = REGISTRATION_DB.submit_magnet_job(
            int(user['id']), user['username'], info_hash
        )
        notif_id_raw = (fields.get('notif_id', '0') or '0').strip()
        if notif_id_raw.isdigit() and int(notif_id_raw) > 0:
            try:
                REGISTRATION_DB.mark_notification_read(int(notif_id_raw), int(user['id']))
            except Exception:
                pass
        q = urllib.parse.quote_plus(msg[:500])
        return self._redirect(f'/manage/notifications?msg={q}&msg_type={"success" if ok else "error"}')

    def _post_torrent_normalize_name(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        body = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        ih = fields.get('info_hash', '').strip().upper()
        if not re.fullmatch(r'[A-F0-9]{40}', ih):
            return self._redirect('/manage/dashboard')
        t = REGISTRATION_DB.get_torrent(ih)
        if not t:
            return self._redirect('/manage/dashboard')
        cleanup_tags = _parse_torrent_name_cleanup_tags(
            REGISTRATION_DB.get_setting('torrent_name_cleanup_tags', '')
        )
        cleanup_strip_www = REGISTRATION_DB.get_setting(
            'torrent_name_cleanup_strip_www_prefix', '1'
        ) == '1'
        cleanup_strip_extensions = REGISTRATION_DB.get_setting(
            'torrent_name_cleanup_strip_extensions', '1'
        ) == '1'
        ok, msg = REGISTRATION_DB.normalize_torrent_name(
            ih, user['username'], cleanup_tags,
            strip_www_prefix=cleanup_strip_www,
            strip_extensions=cleanup_strip_extensions,
        )
        q = urllib.parse.quote(msg)
        return self._redirect(f'/manage/torrent/{ih.lower()}?msg={q}&msg_type={"success" if ok else "error"}')

    def _post_torrent_reclassify(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        role = _user_role(user)
        if role == 'basic':
            return self._redirect('/manage/dashboard')
        body = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        ih = fields.get('info_hash', '').strip().upper()
        if not ih or not re.fullmatch(r'[A-F0-9]{40}', ih):
            return self._redirect('/manage/dashboard')
        t = REGISTRATION_DB.get_torrent(ih)
        if not t:
            q = urllib.parse.quote('Torrent not found.')
            return self._redirect(f'/manage/dashboard?msg={q}&msg_type=error')
        is_owner = int(t['uploaded_by_id'] or 0) == int(user['id'])
        if role not in ('super', 'admin', 'editor') and not is_owner:
            q = urllib.parse.quote('Only owner/editor/admin can reclassify this torrent.')
            return self._redirect(f'/manage/torrent/{ih.lower()}?msg={q}&msg_type=error')
        ok = REGISTRATION_DB.classify_torrent(ih)
        if not ok:
            q = urllib.parse.quote('Reclassify deferred due to a temporary DB lock. Please retry.')
            return self._redirect(f'/manage/torrent/{ih.lower()}?msg={q}&msg_type=error')
        q = urllib.parse.quote('Release classification refreshed.')
        return self._redirect(f'/manage/torrent/{ih.lower()}?msg={q}&msg_type=success')

    def _get_notifications(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        qs = urllib.parse.parse_qs(urllib.parse.urlparse(self.path).query)
        msg = urllib.parse.unquote(qs.get('msg', [''])[0])
        msg_type = qs.get('msg_type', ['error'])[0]
        self._send_html(_render_notifications_page(user, msg=msg, msg_type=msg_type))

    def _get_bounty_board(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        if _user_role(user) == 'basic':
            return self._redirect('/manage/dashboard')
        qs   = urllib.parse.parse_qs(urllib.parse.urlparse(self.path).query)
        sort = qs.get('sort', ['points'])[0]
        raw_status = qs.get('status', [None])[0]
        if raw_status is None:
            filt = 'open'
        elif raw_status in ('', 'all'):
            filt = 'all'
        elif raw_status in ('open', 'pending', 'fulfilled', 'expired'):
            filt = raw_status
        else:
            filt = 'open'
        page = max(1, int(qs.get('page', ['1'])[0]) if qs.get('page', ['1'])[0].isdigit() else 1)
        per_page = 20
        status_filter = None if filt == 'all' else filt
        bounties, total = REGISTRATION_DB.list_bounties(
            status=status_filter, sort=sort, page=page, per_page=per_page)
        total_pages = max(1, (total + per_page - 1) // per_page)
        msg      = urllib.parse.unquote(qs.get('msg', [''])[0])
        msg_type = qs.get('msg_type', ['error'])[0]
        self._send_html(_render_bounty_board(user, bounties, total, page, total_pages,
                                             sort=sort, status=filt,
                                             msg=msg, msg_type=msg_type))

    def _get_leaderboard(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        if _user_role(user) == 'basic':
            return self._redirect('/manage/dashboard')
        top_n = int(REGISTRATION_DB.get_setting('leaderboard_top_n', '10'))
        data  = REGISTRATION_DB.get_leaderboard(top_n)
        self._send_html(_render_leaderboard(user, data, top_n))

    def _get_bounty_detail(self, bounty_id: int):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        role = _user_role(user)
        if role == 'basic':
            return self._redirect('/manage/dashboard')
        bounty = REGISTRATION_DB.get_bounty(bounty_id)
        if not bounty:
            return self._send_html('<h1>Bounty Not Found</h1>', 404)
        if bounty['status'] == 'removed' and role not in ('super', 'admin'):
            return self._redirect('/manage/bounty?msg=Bounty+not+found.&msg_type=error')
        qs = urllib.parse.parse_qs(urllib.parse.urlparse(self.path).query)
        msg      = urllib.parse.unquote(qs.get('msg', [''])[0])
        msg_type = qs.get('msg_type', ['error'])[0]
        contributions = REGISTRATION_DB.get_bounty_contributions(bounty_id)
        votes         = REGISTRATION_DB.get_bounty_votes(bounty_id)
        torrent = None
        if bounty['claimed_infohash']:
            torrent = REGISTRATION_DB.get_torrent(bounty['claimed_infohash'])
        threshold = int(REGISTRATION_DB.get_setting('bounty_confirm_votes', '3'))
        self._send_html(_render_bounty_detail(user, bounty, contributions, votes,
                                              torrent, threshold,
                                              msg=msg, msg_type=msg_type))


    @staticmethod
    def _comment_route_meta(thread_key: str) -> tuple[str, str]:
        """Return (base_url, anchor_prefix) for comment threads."""
        key = (thread_key or '').strip().upper()
        if key.startswith('BOUNTY:'):
            bid = key.split(':', 1)[1].strip()
            if bid.isdigit():
                return f'/manage/bounty/{bid}', 'bcmt'
            return '/manage/bounty', 'bcmt'
        return f'/manage/torrent/{key.lower()}', 'comment'

    def _post_comment(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        body   = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        ih     = fields.get('info_hash', '').strip().upper()
        text   = fields.get('body', '').strip()[:2000]
        parent = fields.get('parent_id', '').strip()
        parent_id = int(parent) if parent.isdigit() else None
        base_url, anchor_prefix = self._comment_route_meta(ih)
        if not ih or not text:
            return self._redirect(base_url)
        is_bounty_thread = ih.startswith('BOUNTY:')
        bounty = None
        t = None
        if is_bounty_thread:
            if _user_role(user) == 'basic':
                return self._redirect('/manage/dashboard')
            bid_raw = ih.split(':', 1)[1].strip()
            if not bid_raw.isdigit():
                return self._redirect('/manage/bounty')
            bounty = REGISTRATION_DB.get_bounty(int(bid_raw))
            if not bounty:
                return self._redirect('/manage/bounty?msg=Bounty+not+found.&msg_type=error')
            if bounty['status'] in ('expired', 'removed'):
                return self._redirect(f'/manage/bounty/{int(bid_raw)}?msg=Bounty+is+closed+for+comments.&msg_type=error')
        else:
            t = REGISTRATION_DB.get_torrent(ih)
            if not t:
                return self._redirect('/manage/dashboard')
        # Block if comments system is disabled globally
        if REGISTRATION_DB.get_setting('comments_enabled', '1') != '1':
            return self._redirect(base_url)
        # Block posting if comments are locked on this torrent
        if (not is_bounty_thread) and t['comments_locked']:
            return self._redirect(f'{base_url}?msg=locked')
        uname = user['username']
        tname = bounty['description'] if is_bounty_thread else t['name']
        # Validate @mentions — warn on unknowns but still post
        mentioned = set(_MENTION_RE.findall(text))
        unknown = [m for m in mentioned
                   if m != uname and not REGISTRATION_DB.get_user(m)]
        if unknown:
            unknown_list = ', '.join(f'@{u}' for u in sorted(unknown))
            warn_param = urllib.parse.quote(unknown_list)
            # Still save the comment; just notify the poster
            cid = REGISTRATION_DB.add_comment(ih, user['id'], uname, text, parent_id)
            REGISTRATION_DB.award_comment_points(user['id'], cid)
            _deliver_notifications(cid, ih, tname, uname, text, parent_id)
            return self._redirect(
                f'{base_url}?warn={warn_param}#{anchor_prefix}-{cid}')
        cid = REGISTRATION_DB.add_comment(ih, user['id'], uname, text, parent_id)
        REGISTRATION_DB.award_comment_points(user['id'], cid)
        _deliver_notifications(cid, ih, tname, uname, text, parent_id)
        self._redirect(f'{base_url}#{anchor_prefix}-{cid}')

    def _post_comment_edit(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        body   = self._read_body()
        fields, _ = _parse_multipart(self.headers, body)
        cid    = fields.get('comment_id', '').strip()
        ih     = fields.get('info_hash', '').strip().upper()
        text   = fields.get('body', '').strip()[:2000]
        base_url, anchor_prefix = self._comment_route_meta(ih)
        if not cid.isdigit() or not text:
            return self._redirect(base_url)
        role = _user_role(user)
        REGISTRATION_DB.edit_comment(int(cid), user['id'], text, role in ('super','admin'))
        # Validate @mentions — warn on unknowns the same as post
        uname = user['username']
        mentioned = set(_MENTION_RE.findall(text))
        unknown = [m for m in mentioned
                   if m != uname and not REGISTRATION_DB.get_user(m)]
        if unknown:
            unknown_list = ', '.join(f'@{u}' for u in sorted(unknown))
            warn_param = urllib.parse.quote(unknown_list)
            return self._redirect(
                f'{base_url}?warn={warn_param}#{anchor_prefix}-{cid}')
        self._redirect(f'{base_url}#{anchor_prefix}-{cid}')

