    def _post_tracker_move(self):
        user = self._get_session_user()
        if not user:
            return self._redirect('/manage')
        if not (user['is_admin'] or user['username'] == SUPER_USER):
            return self._redirect('/manage/dashboard')
        body = self._read_body()
