        _tfa_method = (viewer['tfa_method'] or '').strip().upper() if ('tfa_method' in viewer.keys()) else ''
        _sitewide_enforced = (REGISTRATION_DB.get_setting('webauthn_enforce_sitewide', '0') == '1') if REGISTRATION_DB else False
